import { locales } from "@/lib/i18n"
import { generateMetadata as generateAboutMetadata } from "../about-me/page"

export const revalidate = 3600

export { default } from "../about-me/page"

export async function generateMetadata(props: any) {
    return generateAboutMetadata(props)
}

export function generateStaticParams() {
    return locales.map(locale => ({ locale }))
}

/**
 * Account Completion Form Container
 *
 * Manages the multi-step form flow for account completion.
 * Handles step navigation, form submission, and error handling.
 *
 * Validates: Requirements 4.1, 4.2, 4.3, 4.4, 4.5
 */

"use client"

import { useTranslations } from "next-intl"
import { useCallback, useEffect, useState } from "react"
import ProgressIndicator from "./components/progress-indicator"
import { useAccountCompletion } from "./hooks/useAccountCompletion"
import Step1Prefilled from "./steps/step-1-prefilled"
import Step2NewFields from "./steps/step-2-new-fields"
import Step3Verification from "./steps/step-3-verification"

interface CompleteAccountFormProps {
    locale: string
}

export default function CompleteAccountForm({
    locale,
}: CompleteAccountFormProps) {
    const t = useTranslations("auth")
    const [isLoading, setIsLoading] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const [successMessage, setSuccessMessage] = useState<string | null>(null)

    const {
        currentStep,
        tempToken,
        prefilledData,
        editedData,
        newFields,
        errors,
        setCurrentStep,
        updatePrefilledField,
        updateNewField,
        validateStep,
        submitForm,
        resetForm,
        loadRegistrationData,
    } = useAccountCompletion()

    // Load registration data from temp token on mount
    useEffect(() => {
        if (tempToken) {
            loadRegistrationData(tempToken)
        }
    }, [tempToken, loadRegistrationData])

    const handleContinue = useCallback(async () => {
        setError(null)

        // Validate current step
        const isValid = validateStep(currentStep)
        if (!isValid) {
            setError(t("completeAccount.errors.validationFailed"))
            return
        }

        // Move to next step
        if (currentStep < 3) {
            setCurrentStep((currentStep + 1) as 1 | 2 | 3)
        }
    }, [currentStep, validateStep, setCurrentStep, t])

    const handleBack = useCallback(() => {
        if (currentStep > 1) {
            setCurrentStep((currentStep - 1) as 1 | 2 | 3)
        }
    }, [currentStep, setCurrentStep])

    const handleEditSection = useCallback(
        (section: "prefilled" | "newFields") => {
            if (section === "prefilled") {
                setCurrentStep(1)
            } else {
                setCurrentStep(2)
            }
        },
        [setCurrentStep]
    )

    const handleSubmit = useCallback(async () => {
        setError(null)
        setIsLoading(true)

        try {
            // Validate all data before submission
            const isValid = validateStep(3)
            if (!isValid) {
                setError(t("completeAccount.errors.validationFailed"))
                setIsLoading(false)
                return
            }

            // Submit form
            const result = await submitForm()

            if (result.success) {
                setSuccessMessage(t("completeAccount.step3.success"))
                // Redirect to dashboard after a short delay
                setTimeout(() => {
                    window.location.href = result.redirectUrl || "/dashboard"
                }, 1500)
            } else {
                setError(
                    result.error || t("completeAccount.errors.serverError")
                )
            }
        } catch (err) {
            console.error("Form submission error:", err)
            setError(t("completeAccount.errors.serverError"))
        } finally {
            setIsLoading(false)
        }
    }, [validateStep, submitForm, t])

    const handleReset = useCallback(() => {
        resetForm()
        setError(null)
        setSuccessMessage(null)
    }, [resetForm])

    return (
        <div className="space-y-8">
            {/* Progress Indicator */}
            <ProgressIndicator currentStep={currentStep} totalSteps={3} />

            {/* Error Message */}
            {error && (
                <div className="p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg">
                    <p className="text-red-800 dark:text-red-200 text-sm">
                        {error}
                    </p>
                </div>
            )}

            {/* Success Message */}
            {successMessage && (
                <div className="p-4 bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 rounded-lg">
                    <p className="text-green-800 dark:text-green-200 text-sm">
                        {successMessage}
                    </p>
                </div>
            )}

            {/* Step Content */}
            <div className="min-h-96">
                {currentStep === 1 && (
                    <Step1Prefilled
                        prefilledData={prefilledData}
                        editedData={editedData}
                        errors={errors}
                        onUpdateField={updatePrefilledField}
                        onContinue={handleContinue}
                        isLoading={isLoading}
                    />
                )}

                {currentStep === 2 && (
                    <Step2NewFields
                        newFields={newFields}
                        errors={errors}
                        onUpdateField={updateNewField}
                        onContinue={handleContinue}
                        onBack={handleBack}
                        isLoading={isLoading}
                    />
                )}

                {currentStep === 3 && (
                    <Step3Verification
                        prefilledData={prefilledData}
                        editedData={editedData}
                        newFields={newFields}
                        errors={errors}
                        onEditSection={handleEditSection}
                        onSubmit={handleSubmit}
                        onBack={handleBack}
                        isLoading={isLoading}
                    />
                )}
            </div>

            {/* Back to Login Link */}
            {currentStep === 1 && (
                <div className="text-center">
                    <a
                        href={`/${locale}/login`}
                        className="text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 text-sm font-medium"
                    >
                        {t("completeAccount.backToLogin")}
                    </a>
                </div>
            )}
        </div>
    )
}

"use client"

import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import {
    CreditCostsTable,
    CreditWidget,
} from "@/components/credits/CreditWidget"
import { Input } from "@/components/ui/input"
import { useLocale, useTranslations } from "next-intl"
import {
    ArrowLeft,
    Coins,
    Copy,
    Gift,
    Loader2,
    Terminal,
    TrendingDown,
    TrendingUp,
} from "lucide-react"
import Link from "next/link"
import { useEffect, useState } from "react"

interface TransactionData {
    id: string
    amount: number
    type: "debit" | "credit"
    reason: string
    balanceBefore: number
    balanceAfter: number
    createdAt: string
}

const API_ROUTES = [
    {
        method: "GET",
        path: "/api/credits/balance",
        auth: true,
        desc: "Current balance",
    },
    {
        method: "GET",
        path: "/api/credits/transactions?limit=5",
        auth: true,
        desc: "Recent transactions",
    },
    {
        method: "GET",
        path: "/api/credits/costs",
        auth: false,
        desc: "Credit cost table",
    },
    {
        method: "GET",
        path: "/api/credits/whoami",
        auth: true,
        desc: "User info + admin status",
    },
    {
        method: "POST",
        path: "/api/credits/grant",
        auth: true,
        desc: "Admin: grant credits",
    },
] as const

export default function CreditsPage() {
    const t = useTranslations("dashboard.credits")
    const locale = useLocale()
    const [balance, setBalance] = useState<number | null>(null)
    const [transactions, setTransactions] = useState<TransactionData[]>([])
    const [loading, setLoading] = useState(true)
    const [isAdmin, setIsAdmin] = useState(false)
    const [userId, setUserId] = useState<string | null>(null)
    const [grantAmount, setGrantAmount] = useState("")
    const [granting, setGranting] = useState(false)
    const [grantMsg, setGrantMsg] = useState<string | null>(null)

    async function loadData() {
        try {
            const [balRes, txRes] = await Promise.all([
                fetch("/api/credits/balance"),
                fetch("/api/credits/transactions?limit=50"),
            ])
            const balData = await balRes.json()
            const txData = await txRes.json()

            if (balData.success) {
                setBalance(balData.data.balance)
                setUserId(balData.data.userId ?? null)
                setIsAdmin(balData.data.isAdmin ?? false)
            }
            if (txData.success) setTransactions(txData.data.transactions)
        } catch {
            /* ignore */
        } finally {
            setLoading(false)
        }
    }

    useEffect(() => {
        loadData()
    }, [])

    async function handleGrant() {
        const amount = parseInt(grantAmount, 10)
        if (!amount || amount <= 0) return

        setGranting(true)
        setGrantMsg(null)
        try {
            const res = await fetch("/api/credits/grant", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ amount, reason: "Admin grant (test)" }),
            })
            const data = await res.json()
            if (data.success) {
                setGrantMsg(t("creditsGranted", { amount }))
                setGrantAmount("")
                loadData()
            } else {
                setGrantMsg(t("error", { message: data.error }))
            }
        } catch {
            setGrantMsg(t("requestFailed"))
        } finally {
            setGranting(false)
        }
    }

    async function copyUserId() {
        if (!userId) return
        await navigator.clipboard.writeText(userId)
    }

    return (
        <div className="space-y-6">
            <div className="flex items-center gap-4">
                <Link
                    href={`/${locale}/dashboard`}
                    className="text-muted-foreground hover:text-foreground"
                >
                    <ArrowLeft className="h-5 w-5" />
                </Link>
                <div>
                    <h1 className="text-2xl font-bold flex items-center gap-2">
                        <Coins className="h-6 w-6" />
                        {t("title")}
                    </h1>
                    <p className="text-sm text-muted-foreground">
                        {t("description")}
                    </p>
                </div>
            </div>

            {userId ? (
                <Card className="border-dashed border-yellow-400 bg-yellow-50/50 dark:bg-yellow-950/20">
                    <CardContent className="py-3">
                        <div className="flex items-center gap-2">
                            <span className="text-xs font-mono text-muted-foreground shrink-0">
                                {t("yourUserId")}
                            </span>
                            <code className="text-xs font-mono bg-background px-2 py-0.5 rounded border truncate min-w-0">
                                {userId}
                            </code>
                            <Button
                                variant="ghost"
                                size="sm"
                                className="h-6 px-2 shrink-0"
                                onClick={copyUserId}
                            >
                                <Copy className="h-3 w-3" />
                            </Button>
                        </div>
                        <p className="text-[10px] text-muted-foreground mt-1">
                            {t("addThisIdTo")}{" "}
                            <code className="text-[10px] font-mono bg-background px-1 rounded">
                                CREDIT_ADMIN_IDS
                            </code>{" "}
                            {t("inYourEnvLocal")}
                        </p>
                    </CardContent>
                </Card>
            ) : null}

            {loading ? (
                <div className="flex items-center justify-center py-12">
                    <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                </div>
            ) : (
                <div className="grid gap-6 md:grid-cols-2">
                    <div className="space-y-6">
                        <CreditWidget />

                        <Card>
                            <CardHeader>
                                <CardTitle className="text-lg flex items-center gap-2">
                                    <Gift className="h-5 w-5" />
                                    {t("adminGrant")}
                                </CardTitle>
                            </CardHeader>
                            <CardContent className="space-y-3">
                                <p className="text-xs text-muted-foreground">
                                    {t("grantDescription")}
                                </p>
                                <div className="flex gap-2">
                                    <Input
                                        type="number"
                                        placeholder={t("amount")}
                                        value={grantAmount}
                                        onChange={e =>
                                            setGrantAmount(e.target.value)
                                        }
                                        min={1}
                                        className="w-32"
                                    />
                                    <Button
                                        onClick={handleGrant}
                                        disabled={
                                            granting ||
                                            !grantAmount ||
                                            parseInt(grantAmount) <= 0
                                        }
                                        size="sm"
                                    >
                                        {granting ? (
                                            <Loader2 className="h-4 w-4 animate-spin mr-1" />
                                        ) : null}
                                        {t("grant")}
                                    </Button>
                                </div>
                                {grantMsg && (
                                    <p
                                        className={`text-xs ${
                                            grantMsg.startsWith("+")
                                                ? "text-green-600"
                                                : "text-red-600"
                                        }`}
                                    >
                                        {grantMsg}
                                    </p>
                                )}
                            </CardContent>
                        </Card>
                    </div>

                    <div className="space-y-6">
                        <CreditCostsTable />

                        <Card>
                            <CardHeader>
                                <CardTitle className="text-lg">
                                    {t("transactionHistory")}
                                </CardTitle>
                            </CardHeader>
                            <CardContent>
                                {transactions.length === 0 ? (
                                    <p className="text-sm text-muted-foreground">
                                        {t("noTransactions")}
                                    </p>
                                ) : (
                                    <div className="divide-y text-sm max-h-80 overflow-y-auto">
                                        {transactions.map(tx => (
                                            <div
                                                key={tx.id}
                                                className="flex items-center justify-between py-2"
                                            >
                                                <div className="flex items-center gap-2 min-w-0">
                                                    {tx.type === "credit" ? (
                                                        <TrendingUp className="h-4 w-4 shrink-0 text-green-500" />
                                                    ) : (
                                                        <TrendingDown className="h-4 w-4 shrink-0 text-red-500" />
                                                    )}
                                                    <div className="min-w-0">
                                                        <p className="truncate text-xs">
                                                            {tx.reason}
                                                        </p>
                                                        <p className="text-[10px] text-muted-foreground">
                                                            {new Date(
                                                                tx.createdAt
                                                            ).toLocaleString()}
                                                        </p>
                                                    </div>
                                                </div>
                                                <div className="text-right shrink-0 ml-2">
                                                    <p
                                                        className={
                                                            tx.type === "credit"
                                                                ? "text-green-600 text-xs"
                                                                : "text-red-600 text-xs"
                                                        }
                                                    >
                                                        {tx.type === "credit"
                                                            ? "+"
                                                            : "-"}
                                                        {tx.amount}
                                                    </p>
                                                    <p className="text-[10px] text-muted-foreground">
                                                        {t("balance")}{" "}
                                                        {tx.balanceAfter.toLocaleString()}
                                                    </p>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </CardContent>
                        </Card>
                    </div>
                </div>
            )}

            <details className="group">
                <summary className="flex items-center gap-2 cursor-pointer text-sm text-muted-foreground hover:text-foreground py-2">
                    <Terminal className="h-4 w-4" />
                    <span>{t("apiReference")}</span>
                    <span className="text-xs opacity-50 group-open:opacity-100">
                        {t("endpoints", { count: API_ROUTES.length })}
                    </span>
                </summary>
                <Card className="border-dashed">
                    <CardContent className="py-3 space-y-2">
                        {API_ROUTES.map(route => (
                            <div
                                key={route.path}
                                className="flex items-center gap-3 text-xs font-mono"
                            >
                                <span
                                    className={`shrink-0 font-bold px-1.5 py-0.5 rounded text-[10px] ${
                                        route.method === "GET"
                                            ? "bg-green-100 text-green-700 dark:bg-green-950 dark:text-green-400"
                                            : "bg-blue-100 text-blue-700 dark:bg-blue-950 dark:text-blue-400"
                                    }`}
                                >
                                    {route.method}
                                </span>
                                <code className="truncate text-muted-foreground">
                                    {route.path}
                                </code>
                                <span className="text-muted-foreground/60 shrink-0 ml-auto">
                                    {route.auth ? "🔒" : "🔓"}
                                </span>
                            </div>
                        ))}
                        <p className="text-[10px] text-muted-foreground pt-1 border-t">
                            🔒 {t("legendSessionRequired")} &nbsp;|&nbsp; 🔓{" "}
                            {t("legendPublic")}
                        </p>
                    </CardContent>
                </Card>
            </details>
        </div>
    )
}

"use client"

import CalendarView from "@/components/publish/CalendarView"
import PostingInterface from "@/components/publish/PostingInterface"
import { PostList } from "@/components/publish/PostList"
import { Post } from "@/components/publish/PostCard"
import { UniversalPostingButton } from "@/components/publish"
import { useLocale, useTranslations } from "next-intl"
import { format } from "date-fns"
import { Suspense, useCallback, useEffect, useMemo, useState } from "react"

function getLocalTimezone(): string {
    try {
        return Intl.DateTimeFormat().resolvedOptions().timeZone
    } catch {
        return "UTC"
    }
}

function getStoredTimezone(): string {
    if (typeof window === "undefined") return "UTC"
    try {
        return localStorage.getItem("user-timezone") || getLocalTimezone()
    } catch {
        return getLocalTimezone()
    }
}

export default function PublishPage() {
    const t = useTranslations("dashboard.publish")
    const locale = useLocale()
    const [posts, setPosts] = useState<Post[]>([])
    const [isLoading, setIsLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)
    const [selectedDate, setSelectedDate] = useState<Date | null>(null)
    const [showPostingInterface, setShowPostingInterface] = useState(false)
    const [interfaceDate, setInterfaceDate] = useState<Date | undefined>()

    const fetchPosts = useCallback(async () => {
        try {
            setIsLoading(true)
            setError(null)
            const res = await fetch("/api/posts")
            if (!res.ok) {
                const text = await res.text()
                let msg = t("failedToFetch")
                try {
                    const data = JSON.parse(text)
                    msg = data.error || msg
                } catch {}
                throw new Error(msg)
            }
            const data = await res.json()
            const mapped: Post[] = (data.posts || []).map((p: any) => ({
                id: p.id,
                title: p.content.slice(0, 80),
                content: p.content,
                scheduledAt: new Date(p.scheduledTime),
                publishedAt: p.publishedAt
                    ? new Date(p.publishedAt)
                    : undefined,
                status:
                    p.status === "published"
                        ? "published"
                        : p.status === "failed"
                          ? "failed"
                          : "scheduled",
                channels: (p.networks || []).map((n: any) =>
                    typeof n === "string" ? n : n.platform || ""
                ),
                errorMessage: p.errorMessage,
                createdAt: new Date(p.createdAt),
            }))
            setPosts(mapped)
        } catch (err) {
            setError(err instanceof Error ? err.message : t("failedToFetch"))
        } finally {
            setIsLoading(false)
        }
    }, [t])

    useEffect(() => {
        fetchPosts()
    }, [fetchPosts])

    const handleSelectDate = useCallback((date: Date) => {
        setSelectedDate(date)
        setInterfaceDate(date)
        setShowPostingInterface(true)
    }, [])

    const handleCloseInterface = useCallback(() => {
        setShowPostingInterface(false)
        setInterfaceDate(undefined)
        fetchPosts()
    }, [fetchPosts])

    const handleNewPost = useCallback(() => {
        setInterfaceDate(undefined)
        setShowPostingInterface(true)
    }, [])

    const handleEditPost = useCallback((post: Post) => {
        setInterfaceDate(post.scheduledAt)
        setShowPostingInterface(true)
    }, [])

    const handleDeletePost = useCallback(
        async (post: Post) => {
            if (!confirm(t("deleteConfirm"))) return
            try {
                const res = await fetch(`/api/posts/${post.id}`, {
                    method: "DELETE",
                })
                if (!res.ok) throw new Error("Failed to delete post")
                fetchPosts()
            } catch (err) {
                console.error("Failed to delete post:", err)
            }
        },
        [fetchPosts]
    )

    const filteredPosts = useMemo(() => {
        if (!selectedDate) return posts
        const dateKey = format(selectedDate, "yyyy-MM-dd")
        return posts.filter(p => {
            const postKey = format(p.scheduledAt, "yyyy-MM-dd")
            return postKey === dateKey
        })
    }, [posts, selectedDate])

    const calendarPosts = useMemo(
        () =>
            posts
                .filter(p => p.status === "scheduled")
                .map(p => ({
                    id: p.id,
                    scheduledTime: p.scheduledAt.getTime(),
                })),
        [posts]
    )

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-bold text-gray-900">
                        {t("title")}
                    </h1>
                    <p className="mt-2 text-gray-600">{t("description")}</p>
                </div>
                <UniversalPostingButton
                    linkedNetworksCount={3}
                    onOpen={handleNewPost}
                />
            </div>

            <CalendarView
                posts={calendarPosts}
                selectedDate={selectedDate}
                onSelectDate={handleSelectDate}
            />

            <div className="space-y-2">
                <div className="flex items-center justify-between">
                    <h2 className="text-lg font-semibold text-gray-900">
                        {selectedDate
                            ? t("postsFor", {
                                  date: format(selectedDate, "MMM d, yyyy"),
                              })
                            : t("allScheduledPosts")}
                    </h2>
                    {selectedDate && (
                        <button
                            onClick={() => setSelectedDate(null)}
                            className="text-sm text-blue-600 hover:underline"
                        >
                            {t("clearFilter")}
                        </button>
                    )}
                </div>
                <PostList
                    posts={filteredPosts}
                    isLoading={isLoading}
                    error={error}
                    onEdit={handleEditPost}
                    onDelete={handleDeletePost}
                    onRetry={fetchPosts}
                />
            </div>

            {showPostingInterface && (
                <PostingInterface
                    onClose={handleCloseInterface}
                    defaultDate={interfaceDate}
                />
            )}
        </div>
    )
}

