import Header from "@/components/layout/header"
import StructuredData from "@/components/seo/structured-data"
import { ThemeScript } from "@/components/theme/theme-script"
import { defaultLocale, locales, type Locale } from "@/lib/i18n"
import { NextIntlClientProvider } from "next-intl"
import { getMessages } from "next-intl/server"
import LocaleProvider from "./locale-provider"

interface LocaleLayoutProps {
    children: React.ReactNode
    params: Promise<{ locale: string }>
}

export function generateStaticParams() {
    return locales.map(locale => ({ locale }))
}

export { generateMetadata } from "./layout-metadata"

export default async function LocaleLayout({
    children,
    params,
}: LocaleLayoutProps) {
    const { locale: localeParam } = await params

    // Validate locale parameter
    let locale: Locale = defaultLocale

    // Check if locale is valid
    if (
        localeParam &&
        typeof localeParam === "string" &&
        locales.includes(localeParam as Locale)
    ) {
        locale = localeParam as Locale
    }

    // Get messages with error handling
    let messages
    try {
        messages = await getMessages({ locale })
    } catch (error) {
        // If getMessages fails, try with default locale
        try {
            messages = await getMessages({ locale: defaultLocale })
            locale = defaultLocale
        } catch (fallbackError) {
            // If even default locale fails, use empty messages object
            messages = {}
        }
    }

    return (
        <NextIntlClientProvider locale={locale} messages={messages}>
            <LocaleProvider locale={locale}>
                <ThemeScript />
                <StructuredData locale={locale} type="both" />
                <Header />
                {children}
            </LocaleProvider>
        </NextIntlClientProvider>
    )
}

"use client"

import { GoogleLoginButton } from "@/components/auth/google-login-button"
import { useTranslations } from "next-intl"
import Link from "next/link"
import { useRouter } from "next/navigation"
import { useState } from "react"

interface LoginFormProps {
    locale: string
}

export default function LoginForm({ locale }: LoginFormProps) {
    const t = useTranslations("auth")
    const router = useRouter()
    const [formData, setFormData] = useState({
        email: "",
        password: "",
    })
    const [error, setError] = useState<string | null>(null)
    const [isLoading, setIsLoading] = useState(false)
    const [showEmailForm, setShowEmailForm] = useState(false)

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        setError(null)
        setIsLoading(true)

        try {
            const response = await fetch("/api/auth/login", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    email: formData.email,
                    password: formData.password,
                }),
            })

            const data = await response.json()

            if (!response.ok || !data.success) {
                setError(data.error || "Invalid email or password")
                return
            }

            router.push(`/${locale}/dashboard`)
            router.refresh()
        } catch (err) {
            setError("An unexpected error occurred")
        } finally {
            setIsLoading(false)
        }
    }

    return (
        <>
            <GoogleLoginButton className="w-full mb-3" type="login" />

            <button
                onClick={() => setShowEmailForm(!showEmailForm)}
                disabled={isLoading}
                className="w-full px-4 py-3 bg-gray-200 hover:bg-gray-300 dark:bg-gray-700 dark:hover:bg-gray-600 text-gray-900 dark:text-white rounded-lg font-medium transition-colors mb-6 disabled:opacity-50 disabled:cursor-not-allowed"
            >
                {t("login.emailButton")}
            </button>

            {showEmailForm && (
                <form onSubmit={handleSubmit} className="space-y-4 mb-6">
                    {error && (
                        <div className="p-3 bg-red-100 dark:bg-red-900/20 border border-red-400 dark:border-red-800 text-red-700 dark:text-red-400 rounded-lg text-sm">
                            {error}
                        </div>
                    )}

                    <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                            {t("login.email")}
                        </label>
                        <input
                            type="email"
                            value={formData.email}
                            onChange={e =>
                                setFormData({
                                    ...formData,
                                    email: e.target.value,
                                })
                            }
                            className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-600 dark:focus:ring-blue-500"
                            placeholder={t("login.emailPlaceholder")}
                            required
                            disabled={isLoading}
                        />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                            {t("login.password")}
                        </label>
                        <input
                            type="password"
                            value={formData.password}
                            onChange={e =>
                                setFormData({
                                    ...formData,
                                    password: e.target.value,
                                })
                            }
                            className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-600 dark:focus:ring-blue-500"
                            placeholder="••••••••"
                            required
                            disabled={isLoading}
                        />
                    </div>

                    <div className="flex items-center justify-between">
                        <label className="flex items-center">
                            <input
                                type="checkbox"
                                className="rounded border-gray-300 dark:border-gray-600 text-blue-600 focus:ring-blue-500"
                                disabled={isLoading}
                            />
                            <span className="ml-2 text-sm text-gray-600 dark:text-gray-400">
                                {t("login.rememberMe")}
                            </span>
                        </label>
                        <Link
                            href={`/${locale}/forgot-password`}
                            className="text-sm text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300"
                        >
                            {t("login.forgotPassword")}
                        </Link>
                    </div>

                    <button
                        type="submit"
                        disabled={isLoading}
                        className="w-full px-4 py-3 bg-blue-600 hover:bg-blue-700 dark:bg-blue-500 dark:hover:bg-blue-600 text-white rounded-lg font-medium transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        {isLoading ? t("login.loading") : t("login.button")}
                    </button>
                </form>
            )}

            <div className="relative mb-6">
                <div className="absolute inset-0 flex items-center">
                    <div className="w-full border-t border-gray-300 dark:border-gray-600"></div>
                </div>
                <div className="relative flex justify-center text-sm">
                    <span className="px-2 bg-white dark:bg-gray-800 text-gray-500 dark:text-gray-400">
                        {t("login.noAccount")}
                    </span>
                </div>
            </div>

            <Link
                href={`/${locale}/register`}
                className="w-full px-4 py-3 bg-blue-600 hover:bg-blue-700 dark:bg-blue-500 dark:hover:bg-blue-600 text-white rounded-lg font-medium transition-colors text-center block mb-6"
            >
                {t("login.registerLink")}
            </Link>

            <div className="relative mb-6">
                <div className="absolute inset-0 flex items-center">
                    <div className="w-full border-t border-gray-300 dark:border-gray-600"></div>
                </div>
            </div>

            <p className="text-center text-xs text-gray-600 dark:text-gray-400">
                {t("login.privacyPolicy")}
            </p>
        </>
    )
}

