/**
 * GET/POST /api/auth/oauth/callback
 * OAuth callback endpoint for Google, Facebook, and TikTok
 *
 * Validates: Requirements 2.1, 2.2, 11.1
 */

import { logAuditEvent } from "@/lib/auth/audit-logging"
import {
    OAuthValidationError,
    validateOAuthToken,
} from "@/lib/auth/oauth-validator"
import { createSession } from "@/lib/auth/session"
import { generateTempToken } from "@/lib/auth/temp-token"
import { getUserByOAuthId } from "@/lib/auth/user"
import { logger } from "@/lib/logger"
import {
    getClientIp,
    getSecurityHeaders,
} from "@/lib/middleware/security-headers"
import { NextRequest, NextResponse } from "next/server"

interface OAuthCallbackResponse {
    success: boolean
    requiresPassword?: boolean
    requiresEmail?: boolean
    tempToken?: string
    userId?: string
    email?: string
    redirectUrl?: string
    error?: string
    errorCode?: string
}

/**
 * Exchange authorization code for OAuth token
 * This is a placeholder - actual implementation depends on provider
 */
async function exchangeCodeForToken(
    code: string,
    provider: "google" | "facebook" | "tiktok",
    redirectUri: string
): Promise<string> {
    try {
        // Get provider credentials from environment
        const clientId = process.env[`${provider.toUpperCase()}_CLIENT_ID`]
        const clientSecret =
            process.env[`${provider.toUpperCase()}_CLIENT_SECRET`]

        if (!clientId || !clientSecret) {
            throw new Error(
                `${provider} OAuth credentials not configured. Please set ${provider.toUpperCase()}_CLIENT_ID and ${provider.toUpperCase()}_CLIENT_SECRET environment variables.`
            )
        }

        // Provider-specific token endpoints
        const tokenEndpoints: Record<string, string> = {
            google: "https://oauth2.googleapis.com/token",
            facebook: "https://graph.facebook.com/v12.0/oauth/access_token",
            tiktok: "https://open-api.tiktok.com/oauth/access_token/",
        }

        const tokenEndpoint = tokenEndpoints[provider]

        // Exchange code for token
        const response = await fetch(tokenEndpoint, {
            method: "POST",
            headers: {
                "Content-Type": "application/x-www-form-urlencoded",
            },
            body: new URLSearchParams({
                code,
                client_id: clientId,
                client_secret: clientSecret,
                redirect_uri: redirectUri,
                grant_type: "authorization_code",
            }),
        })

        if (!response.ok) {
            const errorText = await response.text()
            throw new Error(
                `Token exchange failed: ${response.status} ${errorText}`
            )
        }

        const data = (await response.json()) as {
            id_token?: string
            access_token?: string
        }

        // Google returns id_token, Facebook/TikTok return access_token
        const token = data.id_token || data.access_token

        if (!token) {
            throw new Error("No token received from OAuth provider")
        }

        return token
    } catch (error) {
        if (error instanceof Error) {
            throw new Error(
                `Failed to exchange authorization code: ${error.message}`
            )
        }
        throw new Error("Failed to exchange authorization code: Unknown error")
    }
}

/**
 * Process OAuth callback
 * Handles OAuth provider callbacks and determines next steps
 */
async function handleOAuthCallback(
    code: string,
    provider: "google" | "facebook" | "tiktok",
    clientIp: string
): Promise<NextResponse<OAuthCallbackResponse>> {
    try {
        // Get redirect URI from environment
        const redirectUri =
            process.env[`NEXT_PUBLIC_${provider.toUpperCase()}_REDIRECT_URI`]
        if (!redirectUri) {
            logger.error(`${provider} redirect URI not configured`, {
                context: "Auth",
            })

            return NextResponse.json(
                {
                    success: false,
                    error: "Server configuration error",
                    errorCode: "CONFIG_ERROR",
                },
                { status: 500, headers: getSecurityHeaders() }
            )
        }

        // Exchange authorization code for OAuth token
        let token: string
        try {
            token = await exchangeCodeForToken(code, provider, redirectUri)
        } catch (error) {
            logger.warn("Failed to exchange authorization code", {
                context: "Auth",
                error: error as Error,
                data: { ip: clientIp, provider },
            })

            // Log failed login attempt
            await logAuditEvent("LOGIN_FAILED", undefined, clientIp, {
                reason: "Failed to exchange authorization code",
                provider,
            })

            return NextResponse.json(
                {
                    success: false,
                    error: `Failed to authenticate with ${provider}`,
                    errorCode: "TOKEN_EXCHANGE_FAILED",
                },
                { status: 401, headers: getSecurityHeaders() }
            )
        }

        // Validate OAuth token
        let tokenPayload
        try {
            tokenPayload = await validateOAuthToken(token, provider)
        } catch (error) {
            logger.warn("OAuth token validation failed", {
                context: "Auth",
                error: error as Error,
                data: { ip: clientIp, provider },
            })

            // Log failed login attempt
            const errorCode =
                error instanceof OAuthValidationError ||
                (error as any).code !== undefined
                    ? (error as OAuthValidationError).code
                    : "VALIDATION_FAILED"
            await logAuditEvent("LOGIN_FAILED", undefined, clientIp, {
                reason: "Invalid or expired OAuth token",
                provider,
                errorCode,
            })

            return NextResponse.json(
                {
                    success: false,
                    error: "Invalid or expired OAuth token",
                    errorCode,
                },
                { status: 401, headers: getSecurityHeaders() }
            )
        }

        // Extract user information from token
        const oauthId = tokenPayload.sub
        const email = tokenPayload.email
        const name = tokenPayload.name || ""
        const picture = tokenPayload.picture

        // Check if user exists by OAuth ID
        let user
        try {
            user = await getUserByOAuthId(provider, oauthId)
        } catch (error) {
            logger.error("Failed to query user by OAuth ID", {
                context: "Auth",
                error: error as Error,
                data: { provider, oauthId },
            })

            return NextResponse.json(
                {
                    success: false,
                    error: "Database error",
                    errorCode: "DB_ERROR",
                },
                { status: 500, headers: getSecurityHeaders() }
            )
        }

        // NEW USER: Generate temporary token and return requiresPassword
        if (!user) {
            logger.debug("New OAuth user, requires password creation", {
                context: "Auth",
                data: { provider, email },
            })

            // Generate temporary token with OAuth user data
            const tempToken = generateTempToken({
                email: email || "",
                oauth_provider: provider,
                oauth_id: oauthId,
                name,
                picture,
            })

            // Log authentication attempt
            await logAuditEvent("LOGIN_FAILED", email, clientIp, {
                reason: "New user requires password",
                provider,
            })

            return NextResponse.json(
                {
                    success: true,
                    requiresPassword: true,
                    tempToken,
                    email,
                },
                { status: 200, headers: getSecurityHeaders() }
            )
        }

        // EXISTING USER WITH PASSWORD: Create session and return redirect URL
        if (user.password_hash) {
            logger.debug(
                "Existing OAuth user with password, creating session",
                {
                    context: "Auth",
                    data: { userId: user.id, provider },
                }
            )

            // Create session
            let session
            try {
                session = await createSession(user.id)
            } catch (error) {
                logger.error("Failed to create session", {
                    context: "Auth",
                    error: error as Error,
                    data: { userId: user.id },
                })

                await logAuditEvent(
                    "LOGIN_FAILED",
                    user.email,
                    clientIp,
                    { reason: "Failed to create session", provider },
                    user.id
                )

                return NextResponse.json(
                    {
                        success: false,
                        error: "Failed to create session",
                        errorCode: "SESSION_ERROR",
                    },
                    { status: 500, headers: getSecurityHeaders() }
                )
            }

            // Log successful login
            await logAuditEvent(
                "LOGIN_SUCCESS",
                user.email,
                clientIp,
                { action: `User logged in via ${provider} OAuth`, provider },
                user.id
            )

            logger.info(`User logged in successfully via ${provider} OAuth`, {
                context: "Auth",
                data: { userId: user.id, email: user.email },
            })

            // Create response with session cookie
            const response = NextResponse.json(
                {
                    success: true,
                    redirectUrl: "/dashboard",
                },
                { status: 200, headers: getSecurityHeaders() }
            )

            // Set HTTP-Only session cookie
            response.cookies.set("session", session.session_id, {
                httpOnly: true,
                secure: process.env.NODE_ENV === "production",
                sameSite: "strict",
                maxAge: 30 * 24 * 60 * 60, // 30 days in seconds
                path: "/",
            })

            return response
        }

        // EXISTING USER WITHOUT PASSWORD (MIGRATION): Return requiresPassword with userId
        logger.debug(
            "Existing OAuth user without password, requires migration",
            {
                context: "Auth",
                data: { userId: user.id, provider },
            }
        )

        await logAuditEvent("LOGIN_FAILED", user.email, clientIp, {
            reason: "Existing user requires password (migration)",
            provider,
        })

        return NextResponse.json(
            {
                success: true,
                requiresPassword: true,
                userId: user.id,
                email: user.email,
            },
            { status: 200, headers: getSecurityHeaders() }
        )
    } catch (err) {
        logger.error("OAuth callback processing error", {
            context: "Auth",
            error: err as Error,
            data: { ip: clientIp, provider },
        })

        return NextResponse.json(
            {
                success: false,
                error: "An error occurred. Please try again later",
                errorerrorCode: "INTERNAL_ERROR",
            },
            { status: 500, headers: getSecurityHeaders() }
        )
    }
}

/**
 * GET handler for OAuth callback
 * OAuth providers redirect here with authorization code in query parameters
 */
export async function GET(
    request: NextRequest
): Promise<NextResponse<OAuthCallbackResponse>> {
    const clientIp = getClientIp(request)

    try {
        // Get authorization code and provider from query parameters
        const code = request.nextUrl.searchParams.get("code")
        const provider = request.nextUrl.searchParams.get("provider") as
            | "google"
            | "facebook"
            | "tiktok"
            | null

        // Validate authorization code
        if (!code) {
            logger.warn("OAuth callback without authorization code", {
                context: "Auth",
                data: { ip: clientIp },
            })

            return NextResponse.json(
                {
                    success: false,
                    error: "Authorization code is required",
                    errorCode: "MISSING_CODE",
                },
                { status: 400, headers: getSecurityHeaders() }
            )
        }

        // Validate provider
        if (!provider || !["google", "facebook", "tiktok"].includes(provider)) {
            logger.warn("OAuth callback with invalid provider", {
                context: "Auth",
                data: { ip: clientIp, provider },
            })

            return NextResponse.json(
                {
                    success: false,
                    error: "Invalid OAuth provider",
                    errorCode: "INVALID_PROVIDER",
                },
                { status: 400, headers: getSecurityHeaders() }
            )
        }

        return handleOAuthCallback(code, provider, clientIp)
    } catch (err) {
        logger.error("OAuth callback GET error", {
            context: "Auth",
            error: err as Error,
            data: { ip: clientIp },
        })

        return NextResponse.json(
            {
                success: false,
                error: "An error occurred. Please try again later",
                errorCode: "INTERNAL_ERROR",
            },
            { status: 500, headers: getSecurityHeaders() }
        )
    }
}

/**
 * POST handler for OAuth callback
 * Frontend can also POST the authorization code
 */
export async function POST(
    request: NextRequest
): Promise<NextResponse<OAuthCallbackResponse>> {
    const clientIp = getClientIp(request)

    try {
        // Parse request body
        const body = (await request.json().catch(() => ({}))) as {
            code?: string
            provider?: string
        }

        // Validate authorization code
        if (!body.code) {
            logger.warn("OAuth callback POST without authorization code", {
                context: "Auth",
                data: { ip: clientIp },
            })

            return NextResponse.json(
                {
                    success: false,
                    error: "Authorization code is required",
                    errorCode: "MISSING_CODE",
                },
                { status: 400, headers: getSecurityHeaders() }
            )
        }

        // Validate provider
        if (
            !body.provider ||
            !["google", "facebook", "tiktok"].includes(body.provider)
        ) {
            logger.warn("OAuth callback POST with invalid provider", {
                context: "Auth",
                data: { ip: clientIp, provider: body.provider },
            })

            return NextResponse.json(
                {
                    success: false,
                    error: "Invalid OAuth provider",
                    errorCode: "INVALID_PROVIDER",
                },
                { status: 400, headers: getSecurityHeaders() }
            )
        }

        return handleOAuthCallback(
            body.code,
            body.provider as "google" | "facebook" | "tiktok",
            clientIp
        )
    } catch (err) {
        logger.error("OAuth callback POST error", {
            context: "Auth",
            error: err as Error,
            data: { ip: clientIp },
        })

        return NextResponse.json(
            {
                success: false,
                error: "An error occurred. Please try again later",
                errorCode: "INTERNAL_ERROR",
            },
            { status: 500, headers: getSecurityHeaders() }
        )
    }
}

import {
    getAuditEnvironment,
    notifyUserAuditDiscord,
} from "@/lib/audit/discord-user-audit"
import { logRegistration } from "@/lib/auth/audit-logging"
import { AuthErrorType, createErrorResponse } from "@/lib/auth/error-handling"
import { AuthenticationService } from "@/lib/auth/password-security"
import { generateTempToken } from "@/lib/auth/temp-token"
import {
    validateBirthDateFormat,
    validateEmail,
    validateMinimumAge,
    validateName,
    validatePassword,
    validatePhoneNumber,
} from "@/lib/validation"
import { getAdminClient } from "@/lib/supabase/server"
import { NextRequest, NextResponse } from "next/server"

const supabase = getAdminClient()

// Initialize authentication service for password security
const authService = new AuthenticationService()

export async function POST(request: NextRequest) {
    try {
        // ============================================================================
        // REQUEST BODY PARSING
        // ============================================================================

        // Parse request body with error handling
        let body: unknown
        try {
            body = await request.json()
        } catch {
            return createErrorResponse(AuthErrorType.INVALID_INPUT)
        }

        // Validate body is an object (prevent script modifications)
        if (typeof body !== "object" || body === null || Array.isArray(body)) {
            return createErrorResponse(AuthErrorType.INVALID_INPUT)
        }

        const bodyObj = body as Record<string, unknown>
        const {
            email,
            password,
            name,
            phone,
            full_name,
            birth_date,
            auth_method,
            captchaToken,
        } = bodyObj

        // ============================================================================
        // TYPE VALIDATION (Prevent script modifications)
        // ============================================================================

        // Validate required field types
        if (
            typeof email !== "string" ||
            typeof password !== "string" ||
            typeof name !== "string" ||
            typeof phone !== "string"
        ) {
            return createErrorResponse(AuthErrorType.INVALID_INPUT)
        }

        // Validate optional field types
        if (full_name !== undefined && typeof full_name !== "string") {
            return createErrorResponse(AuthErrorType.INVALID_INPUT)
        }

        if (birth_date !== undefined && typeof birth_date !== "string") {
            return createErrorResponse(AuthErrorType.INVALID_INPUT)
        }

        if (auth_method !== undefined && typeof auth_method !== "string") {
            return createErrorResponse(AuthErrorType.INVALID_INPUT)
        }

        if (captchaToken !== undefined && typeof captchaToken !== "string") {
            return createErrorResponse(AuthErrorType.INVALID_INPUT)
        }

        // ============================================================================
        // FIELD VALIDATION (Prevent injection attacks)
        // ============================================================================

        // Validate no extra fields (prevent injection)
        const allowedFields = new Set([
            "email",
            "password",
            "name",
            "phone",
            "full_name",
            "birth_date",
            "auth_method",
            "csrfToken",
            "captchaToken",
        ])
        const providedFields = Object.keys(bodyObj)
        const hasExtraFields = providedFields.some(
            field => !allowedFields.has(field)
        )
        if (hasExtraFields) {
            return createErrorResponse(AuthErrorType.INVALID_INPUT)
        }

        // ============================================================================
        // LENGTH VALIDATION (Prevent buffer overflow)
        // ============================================================================

        // Validate field lengths
        if (email.length === 0 || email.length > 255) {
            return createErrorResponse(AuthErrorType.INVALID_INPUT)
        }

        if (password.length === 0 || password.length > 1024) {
            return createErrorResponse(AuthErrorType.INVALID_INPUT)
        }

        if (name.length === 0 || name.length > 255) {
            return createErrorResponse(AuthErrorType.INVALID_INPUT)
        }

        if (phone.length === 0 || phone.length > 20) {
            return createErrorResponse(AuthErrorType.INVALID_INPUT)
        }

        if (birth_date && birth_date.length > 10) {
            return createErrorResponse(AuthErrorType.INVALID_INPUT)
        }

        // Validate all parameters
        if (!email || !password || !name || !phone) {
            return createErrorResponse(AuthErrorType.REQUIRED_FIELD_EMPTY)
        }

        // Validate email format
        const emailValidation = validateEmail(email)
        if (!emailValidation.isValid) {
            return createErrorResponse(
                AuthErrorType.INVALID_EMAIL,
                "email",
                emailValidation.error
            )
        }

        // Validate password
        const passwordValidation = validatePassword(password)
        if (!passwordValidation.isValid) {
            return createErrorResponse(
                AuthErrorType.INVALID_PASSWORD,
                "password",
                passwordValidation.error
            )
        }

        // Validate name
        const nameValidation = validateName(name)
        if (!nameValidation.isValid) {
            return createErrorResponse(
                AuthErrorType.INVALID_NAME,
                "name",
                nameValidation.error
            )
        }
        // Validate phone
        const phoneValidation = validatePhoneNumber(phone)
        if (!phoneValidation.isValid) {
            return createErrorResponse(
                AuthErrorType.INVALID_INPUT,
                "phone",
                phoneValidation.error
            )
        }

        // Validate birth_date if provided
        if (birth_date) {
            const birthDateFormatValidation =
                validateBirthDateFormat(birth_date)
            if (!birthDateFormatValidation.isValid) {
                return createErrorResponse(
                    AuthErrorType.INVALID_INPUT,
                    "birth_date",
                    birthDateFormatValidation.error
                )
            }

            const ageValidation = validateMinimumAge(birth_date)
            if (!ageValidation.isValid) {
                return createErrorResponse(
                    AuthErrorType.INVALID_INPUT,
                    "birth_date",
                    ageValidation.error
                )
            }
        }

        // ============================================================================
        // USE AUTHENTICATION SERVICE FOR REGISTRATION
        // ============================================================================
        // The AuthenticationService handles:
        // - CAPTCHA validation (Requirement 20.1, 20.2, 20.3, 20.4)
        // - Input validation (Requirement 8.1, 8.2, 8.3, 8.6)
        // - Email existence check (Requirement 8.6)
        // - Argon2id password hashing (Requirement 1.1, 1.2, 1.3)
        // - User record creation (Requirement 1.1, 5.5)
        // - Audit logging (Requirement 14.1, 14.3)
        // - Generic error messages (Requirement 7.4)

        const authResult = await authService.register({
            email: email.toLowerCase(),
            password,
            captchaToken: captchaToken as string | undefined,
        })

        // Handle authentication service errors
        if (!authResult.success) {
            return NextResponse.json(
                {
                    success: false,
                    error: authResult.error || "Registration failed",
                    errorCode: authResult.errorCode,
                },
                { status: authResult.statusCode }
            )
        }

        // ============================================================================
        // REGISTRATION SUCCESSFUL - CREATE SESSION
        // ============================================================================

        // Generate temporary token for session creation
        const tempToken = generateTempToken({
            email: email.toLowerCase(),
            oauth_provider: "email",
            oauth_id: email.toLowerCase(),
            name,
            picture: undefined,
        })

        // Get client IP for logging
        const clientIp =
            request.headers.get("x-forwarded-for")?.split(",")[0] ||
            request.headers.get("x-real-ip") ||
            "unknown"

        // Log registration completion
        await logRegistration(email, clientIp, authResult.userId!)

        void notifyUserAuditDiscord("user_registered", {
            email: email.toLowerCase(),
            userId: authResult.userId,
            provider: "email",
            ip: clientIp,
            environment: getAuditEnvironment(),
        })

        return NextResponse.json(
            {
                success: true,
                message:
                    "Account created successfully. Proceeding to dashboard.",
                data: {
                    userId: authResult.userId,
                    email: email.toLowerCase(),
                    tempToken,
                    redirectUrl: `/auth/complete-account?token=${encodeURIComponent(tempToken)}`,
                },
            },
            { status: 201 }
        )
    } catch (error) {
        console.error("Registration error:", error)
        return createErrorResponse(AuthErrorType.INTERNAL_ERROR)
    }
}

/**
 * Registration Session Management API Endpoint
 * Handles creation, validation, and management of registration sessions
 *
 * Validates: Requirements 16.1, 16.2, 16.3, 16.4, 16.6
 */

import {
    AuthErrorType,
    createErrorResponse,
    createSuccessResponse,
} from "@/lib/auth/error-handling"
import {
    createRegistrationSession,
    removeRegistrationSession,
    updateRegistrationSession,
    validateRegistrationSession,
} from "@/lib/auth/registration-session"
import { validateEmail } from "@/lib/validation"
import { cookies } from "next/headers"
import { NextRequest, NextResponse } from "next/server"

const SESSION_COOKIE_NAME = "registration_session_id"
const SESSION_COOKIE_MAX_AGE = 30 * 60 // 30 minutes in seconds

/**
 * POST /api/auth/registration-session
 * Create a new registration session
 *
 * Request body:
 * {
 *   email?: string (optional)
 * }
 *
 * Response:
 * {
 *   success: true,
 *   data: {
 *     sessionId: string,
 *     expiresAt: ISO8601 timestamp
 *   }
 * }
 */
export async function POST(request: NextRequest) {
    try {
        const body = await request.json()
        const { email } = body

        // Email is optional for initial session creation
        // If provided, validate it
        if (email) {
            const emailValidation = validateEmail(email)
            if (!emailValidation.isValid) {
                return NextResponse.json(
                    createErrorResponse(
                        AuthErrorType.INVALID_EMAIL,
                        "Invalid email format"
                    ),
                    { status: 400 }
                )
            }
        }

        // Create registration session (email can be empty initially)
        const session = await createRegistrationSession(email || "")

        // Set HTTP-only cookie with session ID
        const cookieStore = await cookies()
        cookieStore.set(SESSION_COOKIE_NAME, session.session_id, {
            httpOnly: true,
            secure: process.env.NODE_ENV === "production",
            sameSite: "lax",
            maxAge: SESSION_COOKIE_MAX_AGE,
            path: "/",
        })

        return NextResponse.json(
            createSuccessResponse({
                sessionId: session.session_id,
                expiresAt: session.expires_at.toISOString(),
            }),
            { status: 201 }
        )
    } catch (error) {
        console.error("Registration session creation error:", error)
        return NextResponse.json(
            createErrorResponse(
                AuthErrorType.INTERNAL_ERROR,
                "Failed to create registration session"
            ),
            { status: 500 }
        )
    }
}

/**
 * GET /api/auth/registration-session
 * Validate and retrieve current registration session
 *
 * Response:
 * {
 *   success: true,
 *   data: {
 *     sessionId: string,
 *     email: string,
 *     currentStep: number,
 *     expiresAt: ISO8601 timestamp
 *   }
 * }
 *
 * or
 *
 * {
 *   success: false,
 *   error: "SESSION_EXPIRED" | "SESSION_NOT_FOUND"
 * }
 */
export async function GET(request: NextRequest) {
    try {
        // Get session ID from HTTP-only cookie
        const cookieStore = await cookies()
        const sessionId = cookieStore.get(SESSION_COOKIE_NAME)?.value

        if (!sessionId) {
            return NextResponse.json(
                createErrorResponse(
                    AuthErrorType.SESSION_NOT_FOUND,
                    "No active registration session"
                ),
                { status: 404 }
            )
        }

        // Validate session
        const session = await validateRegistrationSession(sessionId)

        if (!session) {
            // Clear expired session cookie
            const cookieStore = await cookies()
            cookieStore.delete(SESSION_COOKIE_NAME)

            return NextResponse.json(
                createErrorResponse(
                    AuthErrorType.SESSION_EXPIRED,
                    "Registration session has expired"
                ),
                { status: 401 }
            )
        }

        return NextResponse.json(
            createSuccessResponse({
                sessionId: session.session_id,
                email: session.email,
                name: session.name,
                phone: session.phone,
                currentStep: session.current_step,
                expiresAt: session.expires_at.toISOString(),
            }),
            { status: 200 }
        )
    } catch (error) {
        console.error("Registration session validation error:", error)
        return NextResponse.json(
            createErrorResponse(
                AuthErrorType.INTERNAL_ERROR,
                "Failed to validate registration session"
            ),
            { status: 500 }
        )
    }
}

/**
 * PUT /api/auth/registration-session
 * Update registration session with form data
 *
 * Request body:
 * {
 *   email?: string,
 *   name?: string,
 *   phone?: string,
 *   currentStep?: number
 * }
 *
 * Response:
 * {
 *   success: true,
 *   data: {
 *     sessionId: string,
 *     expiresAt: ISO8601 timestamp
 *   }
 * }
 */
export async function PUT(request: NextRequest) {
    try {
        // Get session ID from HTTP-only cookie
        const cookieStore = await cookies()
        const sessionId = cookieStore.get(SESSION_COOKIE_NAME)?.value

        if (!sessionId) {
            return NextResponse.json(
                createErrorResponse(
                    AuthErrorType.SESSION_NOT_FOUND,
                    "No active registration session"
                ),
                { status: 404 }
            )
        }

        // Validate session exists
        const session = await validateRegistrationSession(sessionId)
        if (!session) {
            const cookieStore = await cookies()
            cookieStore.delete(SESSION_COOKIE_NAME)

            return NextResponse.json(
                createErrorResponse(
                    AuthErrorType.SESSION_EXPIRED,
                    "Registration session has expired"
                ),
                { status: 401 }
            )
        }

        // Get update data
        const body = await request.json()
        const { email, name, phone, currentStep } = body

        // Update session
        const updatedSession = await updateRegistrationSession(sessionId, {
            email,
            name,
            phone,
            current_step: currentStep as 1 | 2 | 3 | 4 | undefined,
        })

        // Extend cookie expiration
        const cookieStore2 = await cookies()
        cookieStore2.set(SESSION_COOKIE_NAME, sessionId, {
            httpOnly: true,
            secure: process.env.NODE_ENV === "production",
            sameSite: "lax",
            maxAge: SESSION_COOKIE_MAX_AGE,
            path: "/",
        })

        return NextResponse.json(
            createSuccessResponse({
                sessionId: updatedSession.session_id,
                expiresAt: updatedSession.expires_at.toISOString(),
            }),
            { status: 200 }
        )
    } catch (error) {
        console.error("Registration session update error:", error)
        return NextResponse.json(
            createErrorResponse(
                AuthErrorType.INTERNAL_ERROR,
                "Failed to update registration session"
            ),
            { status: 500 }
        )
    }
}

/**
