import { createLogger } from "@/lib/logger"
import { getOAuthManager } from "@/lib/oauth"
import { rateLimitByKey } from "@/lib/rate-limit"
import { NextRequest, NextResponse } from "next/server"

const logger = createLogger("OAuthAuthorizeEndpoint")

/**
 * POST /api/oauth/authorize/:platform
 * Initiates OAuth authorization flow
 */
export async function POST(
    request: NextRequest,
    context: { params: Promise<{ platform: string }> }
): Promise<NextResponse> {
    const { platform } = await context.params

    try {
        // Rate limiting
        const clientIp =
            request.headers.get("x-forwarded-for") ||
            request.headers.get("x-real-ip") ||
            "unknown"

        const rateLimitResult = await rateLimitByKey(
            `oauth:authorize:${clientIp}`
        )

        if (!rateLimitResult.success) {
            logger.warn("Rate limit exceeded for OAuth authorization", {
                platform: platform,
                clientIp,
            })
            return NextResponse.json(
                { error: "Too many requests. Please try again later." },
                { status: 429 }
            )
        }

        // Get user ID from session
        const userId = request.headers.get("x-user-id")
        if (!userId) {
            logger.warn("Unauthorized OAuth authorization attempt", {
                platform: platform,
            })
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
        }

        // Validate platform
        const oauthManager = getOAuthManager()

        if (!oauthManager.isPlatformConfigured(platform as any)) {
            logger.warn("Unsupported platform for OAuth", {
                platform,
                userId,
            })
            return NextResponse.json(
                { error: `Platform ${platform} is not supported` },
                { status: 400 }
            )
        }

        // Generate authorization URL
        const authResponse = await oauthManager.generateAuthorizationUrl(
            platform as any,
            userId
        )

        logger.info("OAuth authorization URL generated", {
            platform,
            userId,
        })

        return NextResponse.json(authResponse, { status: 200 })
    } catch (error) {
        logger.error("OAuth authorization failed", {
            platform: platform,
            error: error instanceof Error ? error.message : String(error),
        })

        return NextResponse.json(
            {
                error: "Failed to initiate OAuth authorization",
                details: error instanceof Error ? error.message : String(error),
            },
            { status: 500 }
        )
    }
}

/**
 * OAuth Callback Endpoint
 * GET /api/oauth/callback/:platform
 * Handles OAuth callback and token exchange
 * Requirements: 10.1, 10.2, 10.3, 10.5, 10.6, 10.7
 */

import {
    getAuditEnvironment,
    notifyUserAuditDiscord,
} from "@/lib/audit/discord-user-audit"
import { getUserById } from "@/lib/auth/user"
import { createLogger } from "@/lib/logger"
import { getOAuthManager } from "@/lib/oauth"
import { getTokenStore } from "@/lib/token-store"
import { NextRequest, NextResponse } from "next/server"

const logger = createLogger("OAuthCallbackEndpoint")

/**
 * GET /api/oauth/callback/:platform
 * Handles OAuth callback and exchanges code for token
 */
export async function GET(
    request: NextRequest,
    context: { params: Promise<{ platform: string }> }
): Promise<NextResponse> {
    const { platform } = await context.params
    const normalizedPlatform = platform.toLowerCase()

    try {
        const searchParams = request.nextUrl.searchParams
        const code = searchParams.get("code")
        const state = searchParams.get("state")
        const error = searchParams.get("error")
        const errorDescription = searchParams.get("error_description")

        // Handle OAuth errors
        if (error) {
            logger.warn("OAuth error from provider", {
                platform: normalizedPlatform,
                error,
                errorDescription,
            })

            const redirectUrl = new URL("/dashboard", request.nextUrl.origin)
            redirectUrl.searchParams.set("oauth_error", error)
            redirectUrl.searchParams.set(
                "oauth_error_description",
                errorDescription || "Unknown error"
            )
            return NextResponse.redirect(redirectUrl)
        }

        // Validate required parameters
        if (!code || !state) {
            logger.warn("Missing OAuth parameters", {
                platform: normalizedPlatform,
                hasCode: !!code,
                hasState: !!state,
            })

            const redirectUrl = new URL("/dashboard", request.nextUrl.origin)
            redirectUrl.searchParams.set("oauth_error", "missing_parameters")
            return NextResponse.redirect(redirectUrl)
        }

        // Get user ID from session
        const userId = request.headers.get("x-user-id")
        if (!userId) {
            logger.warn("Unauthorized OAuth callback", {
                platform: normalizedPlatform,
            })

            const redirectUrl = new URL("/auth/login", request.nextUrl.origin)
            redirectUrl.searchParams.set("oauth_error", "unauthorized")
            return NextResponse.redirect(redirectUrl)
        }

        // Validate state parameter
        const oauthManager = getOAuthManager()
        const isStateValid = await oauthManager.validateState(
            platform as any,
            userId,
            state
        )

        if (!isStateValid) {
            logger.warn("Invalid state parameter", {
                platform: normalizedPlatform,
                userId,
            })

            const redirectUrl = new URL("/dashboard", request.nextUrl.origin)
            redirectUrl.searchParams.set("oauth_error", "invalid_state")
            return NextResponse.redirect(redirectUrl)
        }

        // Exchange code for token
        const tokenResponse = await oauthManager.exchangeCodeForToken(
            platform as any,
            code,
            userId
        )

        // Store token securely
        const tokenStore = getTokenStore()
        await tokenStore.storeToken({
            accessToken: tokenResponse.accessToken,
            refreshToken: tokenResponse.refreshToken,
            expiresAt: tokenResponse.linkedAt + tokenResponse.expiresIn * 1000,
            platform,
            userId,
        })

        logger.info("OAuth token stored successfully", {
            platform,
            userId,
        })

        const user = await getUserById(userId)
        void notifyUserAuditDiscord("platform_linked", {
            email: user?.google_email,
            userId,
            platform: normalizedPlatform,
            environment: getAuditEnvironment(),
        })

        // Redirect to dashboard with success
        const redirectUrl = new URL("/dashboard", request.nextUrl.origin)
        redirectUrl.searchParams.set("oauth_success", normalizedPlatform)
        return NextResponse.redirect(redirectUrl)
    } catch (error) {
        logger.error("OAuth callback failed", {
            platform: normalizedPlatform,
            error: error instanceof Error ? error.message : String(error),
        })

        const redirectUrl = new URL("/dashboard", request.nextUrl.origin)
        redirectUrl.searchParams.set("oauth_error", "callback_failed")
        return NextResponse.redirect(redirectUrl)
    }
}

/**
 * OAuth Disconnect Endpoint
 * POST /api/oauth/disconnect/:platform
 * Disconnects a social media account and revokes access
 * Requirements: 10.1, 10.2, 10.3, 10.5, 10.6, 10.7
 */

import { createLogger } from "@/lib/logger"
import { getOAuthManager } from "@/lib/oauth"
import { rateLimitByKey } from "@/lib/rate-limit"
import { getTokenStore } from "@/lib/token-store"
import { NextRequest, NextResponse } from "next/server"

const logger = createLogger("OAuthDisconnectEndpoint")

/**
 * POST /api/oauth/disconnect/:platform
 * Disconnects a social media account
 */
export async function POST(
    request: NextRequest,
    context: { params: Promise<{ platform: string }> }
): Promise<NextResponse> {
    const { platform } = await context.params

    try {
        // Rate limiting
        const clientIp =
            request.headers.get("x-forwarded-for") ||
            request.headers.get("x-real-ip") ||
            "unknown"

        const rateLimitResult = await rateLimitByKey(
            `oauth:disconnect:${clientIp}`
        )

        if (!rateLimitResult.success) {
            logger.warn("Rate limit exceeded for OAuth disconnect", {
                platform: platform,
                clientIp,
            })
            return NextResponse.json(
                { error: "Too many requests. Please try again later." },
                { status: 429 }
            )
        }

        // Get user ID from session
        const userId = request.headers.get("x-user-id")
        if (!userId) {
            logger.warn("Unauthorized OAuth disconnect attempt", {
                platform: platform,
            })
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
        }

        // Get the token to revoke
        const tokenStore = getTokenStore()
        const token = await tokenStore.getToken(userId, platform)

        if (!token) {
            logger.warn("Token not found for disconnect", {
                platform,
                userId,
            })
            return NextResponse.json(
                { error: "No token found for this platform" },
                { status: 404 }
            )
        }

        // Revoke the token with the OAuth provider
        const oauthManager = getOAuthManager()
        const revoked = await oauthManager.revokeToken(
            platform as any,
            token.accessToken,
            userId
        )

        if (!revoked) {
            logger.warn("Failed to revoke token with provider", {
                platform,
                userId,
            })
            // Continue with local deletion even if revocation fails
        }

        // Delete the token from local storage
        await tokenStore.deleteToken(userId, platform)

        logger.info("OAuth token disconnected successfully", {
            platform,
            userId,
        })

        return NextResponse.json(
            {
                success: true,
                message: `Successfully disconnected from ${platform}`,
            },
            { status: 200 }
        )
    } catch (error) {
        logger.error("OAuth disconnect failed", {
            platform: platform,
            error: error instanceof Error ? error.message : String(error),
        })

        return NextResponse.json(
            {
                error: "Failed to disconnect OAuth account",
                details: error instanceof Error ? error.message : String(error),
            },
            { status: 500 }
        )
    }
}

import { createLogger } from "@/lib/logger"
import { getTokenStore } from "@/lib/token-store"
import { getValidFacebookToken } from "@/lib/facebook/get-valid-token"
import { getFacebookConfig } from "@/lib/facebook/config"
import { getFacebookOAuthService } from "@/lib/facebook/oauth-service"
import {
    getPageInsights,
    COMMON_PAGE_METRICS,
    PageInsightMetric,
} from "@/lib/facebook/analytics"
import { NextRequest, NextResponse } from "next/server"

const logger = createLogger("FacebookAnalyticsEndpoint")

export async function GET(request: NextRequest): Promise<NextResponse> {
    try {
        const userId = request.headers.get("x-user-id")

        if (!userId) {
            logger.warn("Missing user ID in Facebook analytics request")
            return NextResponse.json(
                {
                    success: false,
                    error: "MISSING_USER_ID",
                    message: "User ID is required",
                },
                { status: 400 }
            )
        }

        const { searchParams } = new URL(request.url)
        const pageId = searchParams.get("pageId")

        if (!pageId) {
            return NextResponse.json(
                {
                    success: false,
                    error: "VALIDATION_ERROR",
                    message: "pageId query parameter is required",
                },
                { status: 400 }
            )
        }

        const config = getFacebookConfig()
        const oauthService = getFacebookOAuthService(config)
        await oauthService.initialize()

        const accessToken = await getValidFacebookToken(userId, {
            oauthService,
        })

        if (!accessToken) {
            logger.warn("Facebook not linked for user", { userId })
            return NextResponse.json(
                {
                    success: false,
                    error: "FACEBOOK_NOT_LINKED",
                    message: "Facebook account is not linked",
                },
                { status: 404 }
            )
        }

        const pageAccessToken = await oauthService.getPageAccessToken(
            pageId,
            accessToken
        )

        if (!pageAccessToken) {
            return NextResponse.json(
                {
                    success: false,
                    error: "PAGE_TOKEN_FAILED",
                    message:
                        "Failed to obtain access token for the specified page",
                },
                { status: 500 }
            )
        }

        const metricParam = searchParams.get("metric")
        const metrics: PageInsightMetric[] = metricParam
            ? (metricParam.split(",") as PageInsightMetric[])
            : COMMON_PAGE_METRICS

        const period =
            (searchParams.get("period") as
                | "day"
                | "week"
                | "days_28"
                | "month"
                | "lifetime") || "day"

        const since = searchParams.get("since") || undefined
        const until = searchParams.get("until") || undefined

        const result = await getPageInsights(pageAccessToken, pageId, metrics, {
            period,
            since,
            until,
        })

        return NextResponse.json(
            {
                success: true,
                data: result.data,
                paging: result.paging,
            },
            { status: 200 }
        )
    } catch (error) {
        const err = error instanceof Error ? error : new Error(String(error))
        logger.error("Failed to fetch Facebook analytics", err)

        return NextResponse.json(
            {
                success: false,
                error: "FETCH_FAILED",
                message: err.message,
            },
            { status: 500 }
        )
    }
}

