        return NextResponse.json(
            {
                success: false,
                error: "PUBLISH_FAILED",
                message: err.message,
            },
            { status: 500 }
        )
    }
}

/**
 * Content Validation Endpoint
 * POST /api/posts/validate
 * Validates content against selected networks and detects conflicts
 * Requirements: 8.1, 8.2, 8.3, 8.4, 8.5, 8.6, 8.7, 8.8, 14.1, 14.2, 14.3, 14.4, 14.5, 14.6, 14.7, 14.8
 */

import { createLogger } from "@/lib/logger"
import { getConflictDetector, getContentAdapter } from "@/lib/posting"
import { NextRequest, NextResponse } from "next/server"

const logger = createLogger("ContentValidationEndpoint")

/**
 * Request body for content validation
 */
interface ValidateContentRequest {
    content: string
    platforms: string[]
    scheduledTime?: number
}

/**
 * POST /api/posts/validate
 * Validates content against selected networks
 */
export async function POST(request: NextRequest): Promise<NextResponse> {
    try {
        // Get user ID from session
        const userId = request.headers.get("x-user-id")
        if (!userId) {
            logger.warn("Unauthorized content validation request")
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
        }

        const body: ValidateContentRequest = await request.json()

        if (!body.content || !body.platforms || body.platforms.length === 0) {
            logger.warn("Missing required fields for content validation", {
                userId,
            })
            return NextResponse.json(
                {
                    error: "Missing required fields: content, platforms (non-empty array)",
                },
                { status: 400 }
            )
        }

        const contentAdapter = getContentAdapter()
        const conflictDetector = getConflictDetector()

        // Validate content for each platform
        const platformValidations = contentAdapter.validateForPlatforms(
            body.content,
            body.platforms as any
        )

        // Detect conflicts
        const conflictResult = await conflictDetector.detectConflicts(
            userId,
            body.content,
            body.platforms as any,
            body.scheduledTime
        )

        logger.info("Content validation completed", {
            userId,
            platforms: body.platforms,
            hasConflicts: conflictResult.hasConflicts,
            canPublish: conflictResult.canPublish,
        })

        return NextResponse.json(
            {
                validation: {
                    platforms: platformValidations,
                    characterLimits: contentAdapter.getAllCharacterLimits(),
                },
                conflicts: conflictResult,
                canPublish: conflictResult.canPublish,
            },
            { status: 200 }
        )
    } catch (error) {
        logger.error("Content validation failed", {
            error: error instanceof Error ? error.message : String(error),
        })

        return NextResponse.json(
            {
                error: "Content validation failed",
                details: error instanceof Error ? error.message : String(error),
            },
            { status: 500 }
        )
    }
}

import { auditLog } from "@/lib/audit/audit-logger"
import { getServerSession } from "@/lib/auth/get-server-session"
import { PublicationQueue } from "@/lib/queue/publication-queue"
import { NextRequest, NextResponse } from "next/server"

export const dynamic = "force-dynamic"
export const runtime = "nodejs"

/**
 * Process publication queue endpoint
 * Called by client-side polling or manually
 */
export async function POST(request: NextRequest) {
    try {
        const session = await getServerSession(request)

        if (!session?.user?.id) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
        }

        const queue = new PublicationQueue()

        // Get publications due for this user
        const duePublications = await queue.getDuePublications(session.user.id)

        if (duePublications.length === 0) {
            return NextResponse.json({
                processed: 0,
                message: "No publications due",
            })
        }

        const results = []

        for (const publication of duePublications) {
            try {
                // Mark as processing
                await queue.markAsProcessing(publication.id)

                // Publish to all networks
                const publishResults = await publishToNetworks(
                    publication,
                    session.user.id
                )

                // Update status based on results
                const allSucceeded = publishResults.every(r => r.success)
                const allFailed = publishResults.every(r => !r.success)

                if (allSucceeded) {
                    await queue.markAsPublished(publication.id)
                } else if (allFailed) {
                    await queue.markAsFailed(
                        publication.id,
                        "All networks failed"
                    )
                } else {
                    await queue.markAsPartiallyPublished(
                        publication.id,
                        publishResults
                    )
                }

                results.push({
                    publicationId: publication.id,
                    status: allSucceeded
                        ? "success"
                        : allFailed
                          ? "failed"
                          : "partial",
                    results: publishResults,
                })

                // Audit log
                await auditLog({
                    userId: session.user.id,
                    action: "publication_processed",
                    resource: "publication",
                    resourceId: publication.id,
                    timestamp: new Date(),
                    status: allFailed ? "failure" : "success",
                    changes: {
                        networks: publication.networks,
                        status: allSucceeded
                            ? "success"
                            : allFailed
                              ? "failed"
                              : "partial",
                    },
                })
            } catch (error) {
                console.error(
                    `Failed to process publication ${publication.id}:`,
                    error
                )

                await queue.handleFailure(
                    publication.id,
                    error instanceof Error ? error.message : "Unknown error"
                )

                results.push({
                    publicationId: publication.id,
                    status: "error",
                    error:
                        error instanceof Error
                            ? error.message
                            : "Unknown error",
                })
            }
        }

        return NextResponse.json({
            processed: results.length,
            results,
        })
    } catch (error) {
        console.error("Error processing queue:", error)
        return NextResponse.json(
            {
                error: "Failed to process queue",
                details:
                    error instanceof Error ? error.message : "Unknown error",
            },
            { status: 500 }
        )
    }
}

async function publishToNetworks(
    publication: any,
    userId: string
): Promise<Array<{ network: string; success: boolean; error?: string }>> {
    const results = []

    for (const network of publication.networks) {
        try {
            // Get network adapter
            const adapter = getNetworkAdapter(network)

            // Get OAuth token
            const token = await getNetworkToken(userId, network)

            if (!token) {
                results.push({
                    network,
                    success: false,
                    error: "No valid token found",
                })
                continue
            }

            // Publish to network
            const result = await adapter.publish({
                content: publication.content,
                images: publication.images,
                metadata: publication.metadata?.[network],
                token,
            })

            results.push({
                network,
                success: true,
                externalId: result.id,
                externalUrl: result.url,
            })
        } catch (error) {
            results.push({
                network,
                success: false,
                error: error instanceof Error ? error.message : "Unknown error",
            })
        }
    }

    return results
}

function getNetworkAdapter(network: string) {
    // Import and return appropriate adapter
    // This is a placeholder - implement based on your adapters
    switch (network) {
        case "youtube":
            return require("@/lib/posting/adapters/youtube").default
        case "facebook":
            return require("@/lib/posting/adapters/facebook").default
        case "instagram":
            return require("@/lib/posting/adapters/instagram").default
        case "twitter":
            return require("@/lib/posting/adapters/twitter").default
        case "linkedin":
            return require("@/lib/posting/adapters/linkedin").default
        default:
            throw new Error(`Unsupported network: ${network}`)
    }
}

async function getNetworkToken(userId: string, network: string) {
    // Get token from token store
    // This is a placeholder - implement based on your token store
    const { TokenStore } = await import("@/lib/token-store/token-store")
    const tokenStore = new TokenStore()
    return tokenStore.getToken(userId, network)
}

import { startBackgroundProcessing } from "@/lib/queue/background-processor"
import { NextRequest, NextResponse } from "next/server"

export const dynamic = "force-dynamic"
export const runtime = "nodejs"

/**
 * Start background queue processing
 *
 * This endpoint should be called once when your server starts.
 * It will start a background interval that processes the queue.
 *
 * NOTE: This only works in long-running Node.js processes.
 * It will NOT work in serverless environments (Vercel, AWS Lambda, etc.)
 *
 * For serverless, use client-side polling or external webhooks instead.
 */
export async function POST(request: NextRequest) {
    try {
        // Verify authorization
        const authHeader = request.headers.get("authorization")
        const expectedToken = process.env.QUEUE_TRIGGER_SECRET

        if (!expectedToken) {
            return NextResponse.json(
                { error: "Queue trigger not configured" },
                { status: 500 }
            )
        }

        if (authHeader !== `Bearer ${expectedToken}`) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
        }

        // Start background processing
        const processor = startBackgroundProcessing(60000) // 1 minute interval

        return NextResponse.json({
            success: true,
            message: "Background processing started",
            interval: 60000,
        })
    } catch (error) {
        console.error("Error starting background processing:", error)
        return NextResponse.json(
            {
                error: "Failed to start background processing",
                details:
                    error instanceof Error ? error.message : "Unknown error",
            },
            { status: 500 }
        )
    }
}

import { NextRequest, NextResponse } from "next/server"
import crypto from "crypto"
import { handleWebhookEvent } from "@/lib/facebook/webhook-handler"
import { createLogger } from "@/lib/logger"

const logger = createLogger("FacebookWebhook")

export async function GET(req: NextRequest) {
    const searchParams = req.nextUrl.searchParams
    const mode = searchParams.get("hub.mode")
    const token = searchParams.get("hub.verify_token")
    const challenge = searchParams.get("hub.challenge")

    if (
        mode === "subscribe" &&
        token === process.env.FACEBOOK_WEBHOOK_VERIFY_TOKEN &&
        challenge
    ) {
        logger.info("Facebook webhook verified")
        return new NextResponse(challenge, { status: 200 })
    }

    return new NextResponse("Forbidden", { status: 403 })
}

export async function POST(req: NextRequest) {
    try {
        const rawBody = await req.text()

        const signature = req.headers.get("x-hub-signature-256")
        if (signature) {
            const appSecret = process.env.FACEBOOK_APP_SECRET
            if (!appSecret) {
                logger.error(
                    "Missing FACEBOOK_APP_SECRET for webhook verification"
                )
                return new NextResponse("Internal Server Error", {
                    status: 500,
                })
            }

            const expectedSig =
                "sha256=" +
                crypto
                    .createHmac("sha256", appSecret)
                    .update(rawBody)
                    .digest("hex")

            try {
                const isVerified = crypto.timingSafeEqual(
                    Buffer.from(signature),
                    Buffer.from(expectedSig)
                )
                if (!isVerified) {
                    logger.warn("Invalid Facebook webhook signature")
                    return new NextResponse("Forbidden", { status: 403 })
                }
            } catch {
                logger.warn("Facebook webhook signature comparison failed")
                return new NextResponse("Forbidden", { status: 403 })
            }
        } else {
            logger.warn("Facebook webhook request missing signature header")
        }

        let body: unknown
        try {
            body = JSON.parse(rawBody)
        } catch {
            logger.warn("Invalid JSON in Facebook webhook payload")
            return new NextResponse("Bad Request", { status: 400 })
        }

        if (
            !body ||
            typeof body !== "object" ||
            !("object" in body) ||
            !("entry" in body)
        ) {
            logger.warn("Invalid Facebook webhook event structure")
            return new NextResponse("Bad Request", { status: 400 })
        }

        const event = body as {
            object: string
            entry: Array<Record<string, unknown>>
        }

        if (event.object !== "page") {
            logger.warn("Received non-page Facebook webhook event", {
                object: event.object,
            })
            return new NextResponse("OK", { status: 200 })
        }

        const result = await handleWebhookEvent(event as any)

        logger.info("Facebook webhook processed", {
            handled: result.handled,
            errors: result.errors,
        })

        return NextResponse.json({ status: "ok" }, { status: 200 })
    } catch (error) {
        logger.error(
            "Facebook webhook processing error",
            error instanceof Error ? error : new Error(String(error))
        )
        return NextResponse.json({ status: "error" }, { status: 500 })
    }
}

/**
 * Instagram Webhook Endpoint
 *
 * GET  — Meta verification handshake (hub.mode, hub.verify_token, hub.challenge)
 * POST — Receive Instagram Graph API webhook events
 *
 * Security:
 *   - GET: verify_token match prevents unauthorized subscriptions
 *   - POST: X-Hub-Signature-256 HMAC-SHA256 signed with App Secret
 *
 * Attack matrix:
 *   GET:  1,2,7,8,9,14,15,18
 *   POST: 2,3,4,5,6,7,8,9,10,13,14,15,19,20
 */

import { NextRequest, NextResponse } from "next/server"
import crypto from "crypto"
import { handleWebhookEvent } from "@/lib/instagram/webhook-handler"
import { createLogger } from "@/lib/logger"

const logger = createLogger("InstagramWebhook")

export async function GET(req: NextRequest) {
    const searchParams = req.nextUrl.searchParams
    const mode = searchParams.get("hub.mode")
    const token = searchParams.get("hub.verify_token")
    const challenge = searchParams.get("hub.challenge")

    if (
        mode === "subscribe" &&
        token === process.env.INSTAGRAM_WEBHOOK_VERIFY_TOKEN &&
        challenge
    ) {
        logger.info("Instagram webhook verified")
        return new NextResponse(challenge, { status: 200 })
    }

    return new NextResponse("Forbidden", { status: 403 })
}

export async function POST(req: NextRequest) {
    try {
        const rawBody = await req.text()

        const signature = req.headers.get("x-hub-signature-256")
        if (signature) {
            const appSecret = process.env.INSTAGRAM_APP_SECRET
            if (!appSecret) {
                logger.error(
                    "Missing INSTAGRAM_APP_SECRET for webhook verification"
                )
                return new NextResponse("Internal Server Error", {
                    status: 500,
                })
            }

            const expectedSig =
                "sha256=" +
                crypto
                    .createHmac("sha256", appSecret)
                    .update(rawBody)
                    .digest("hex")

            try {
                const isVerified = crypto.timingSafeEqual(
                    Buffer.from(signature),
                    Buffer.from(expectedSig)
                )
                if (!isVerified) {
                    logger.warn("Invalid webhook signature")
                    return new NextResponse("Forbidden", { status: 403 })
                }
            } catch {
                logger.warn("Signature comparison failed")
                return new NextResponse("Forbidden", { status: 403 })
            }
        } else {
            logger.warn("Missing x-hub-signature-256 header")
        }

        let body: unknown
        try {
            body = JSON.parse(rawBody)
        } catch {
            return new NextResponse("OK", { status: 200 })
        }

        const event = body as { object?: string }
        if (event?.object === "page" || event?.object === "instagram") {
            handleWebhookEvent(event as any)
        }

        return new NextResponse("OK", { status: 200 })
    } catch (error) {
        logger.error(
            "Instagram webhook error",
            error instanceof Error ? error : new Error(String(error))
        )
        return new NextResponse("OK", { status: 200 })
    }
}

