            })

            await renderReadyLoginForm()

            // Fill in credentials
            await user.type(
                screen.getByRole("textbox", { name: /email/i }),
                "john@example.com"
            )
            await user.type(
                screen.getByPlaceholderText(/enter your password/i),
                "WrongPass123!"
            )

            // Submit form
            await user.click(screen.getByRole("button", { name: /sign in/i }))

            await waitFor(() => {
                expect(
                    screen.getByText(/invalid email or password/i)
                ).toBeInTheDocument()
            })
        })

        it("should display rate limiting error", async () => {
            const user = userEvent.setup()

            ;(global.fetch as any).mockImplementation(async (url: string) => {
                if (String(url).includes("/api/auth/csrf")) {
                    return csrfFetchResponse
                }
                return {
                    ok: false,
                    status: 429,
                    json: async () => ({
                        success: false,
                        error: "Too many login attempts. Please try again later.",
                    }),
                }
            })

            await renderReadyLoginForm()

            // Fill in credentials
            await user.type(
                screen.getByRole("textbox", { name: /email/i }),
                "john@example.com"
            )
            await user.type(
                screen.getByPlaceholderText(/enter your password/i),
                "ValidPass123!"
            )

            // Submit form
            await user.click(screen.getByRole("button", { name: /sign in/i }))

            await waitFor(() => {
                expect(
                    screen.getByText(
                        /too many login attempts\. please try again later/i
                    )
                ).toBeInTheDocument()
            })
        })
    })

    describe("Remember Me Checkbox (Requirement 3.9)", () => {
        it("should toggle remember me checkbox", async () => {
            const user = userEvent.setup()
            render(<LoginForm locale="en" />)

            const rememberMeCheckbox = screen.getByRole("checkbox", {
                name: /remember me/i,
            })

            // Initially unchecked
            expect(rememberMeCheckbox).not.toBeChecked()

            // Click to check
            await user.click(rememberMeCheckbox)
            expect(rememberMeCheckbox).toBeChecked()

            // Click to uncheck
            await user.click(rememberMeCheckbox)
            expect(rememberMeCheckbox).not.toBeChecked()
        })

        it("should include rememberMe in form submission", async () => {
            const user = userEvent.setup()

            ;(global.fetch as any).mockImplementation(async (url: string) => {
                if (String(url).includes("/api/auth/csrf")) {
                    return csrfFetchResponse
                }
                return {
                    ok: true,
                    json: async () => ({
                        success: true,
                        data: {
                            userId: "123",
                            email: "john@example.com",
                            name: "John Doe",
                        },
                    }),
                }
            })

            await renderReadyLoginForm()

            // Fill in credentials
            await user.type(
                screen.getByRole("textbox", { name: /email/i }),
                "john@example.com"
            )
            await user.type(
                screen.getByPlaceholderText(/enter your password/i),
                "ValidPass123!"
            )

            // Check remember me
            await user.click(
                screen.getByRole("checkbox", { name: /remember me/i })
            )

            // Submit form
            await user.click(screen.getByRole("button", { name: /sign in/i }))

            await waitFor(() => {
                expect(global.fetch).toHaveBeenCalledWith(
                    "/api/auth/login",
                    expect.objectContaining({
                        body: expect.stringContaining('"rememberMe":true'),
                    })
                )
            })
        })
    })

    describe("Loading State (Requirement 3.8)", () => {
        it("should disable form during submission", async () => {
            const user = userEvent.setup()

            ;(global.fetch as any).mockImplementation(async (url: string) => {
                if (String(url).includes("/api/auth/csrf")) {
                    return csrfFetchResponse
                }
                await new Promise(resolve => setTimeout(resolve, 100))
                return {
                    ok: true,
                    json: async () => ({
                        success: true,
                        data: {
                            userId: "123",
                            email: "john@example.com",
                            name: "John Doe",
                        },
                    }),
                }
            })

            await renderReadyLoginForm()

            // Fill in credentials
            await user.type(
                screen.getByRole("textbox", { name: /email/i }),
                "john@example.com"
            )
            await user.type(
                screen.getByPlaceholderText(/enter your password/i),
                "ValidPass123!"
            )

            // Submit form
            await user.click(screen.getByRole("button", { name: /sign in/i }))

            // Button should show loading state
            await waitFor(() => {
                expect(
                    screen.getByRole("button", { name: /signing in/i })
                ).toBeDisabled()
            })

            // Inputs should be disabled
            expect(
                screen.getByRole("textbox", { name: /email/i })
            ).toBeDisabled()
            expect(
                screen.getByPlaceholderText(/enter your password/i)
            ).toBeDisabled()
        })
    })

    describe("CSRF Token (Requirement 6.1)", () => {
        it("should include CSRF token in form submission", async () => {
            const user = userEvent.setup()

            ;(global.fetch as any).mockImplementation(async (url: string) => {
                if (String(url).includes("/api/auth/csrf")) {
                    return csrfFetchResponse
                }
                return {
                    ok: true,
                    json: async () => ({
                        success: true,
                        data: {
                            userId: "123",
                            email: "john@example.com",
                            name: "John Doe",
                        },
                    }),
                }
            })

            await renderReadyLoginForm()

            // Fill in credentials
            await user.type(
                screen.getByRole("textbox", { name: /email/i }),
                "john@example.com"
            )
            await user.type(
                screen.getByPlaceholderText(/enter your password/i),
                "ValidPass123!"
            )

            // Submit form
            await user.click(screen.getByRole("button", { name: /sign in/i }))

            await waitFor(() => {
                expect(global.fetch).toHaveBeenCalledWith(
                    "/api/auth/login",
                    expect.objectContaining({
                        headers: expect.objectContaining({
                            "X-CSRF-Token": "test-csrf-token",
                        }),
