"use client"

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { CREDIT_COSTS } from "@/lib/credits/constants"
import { useTranslations } from "next-intl"
import { Coins, TrendingDown, TrendingUp } from "lucide-react"
import { useEffect, useState } from "react"

interface BalanceData {
    balance: number
}

interface TransactionData {
    id: string
    amount: number
    type: "debit" | "credit"
    reason: string
    balanceAfter: number
    createdAt: string
}

export function CreditWidget() {
    const t = useTranslations("dashboard.credits")
    const [balance, setBalance] = useState<number | null>(null)
    const [recent, setRecent] = useState<TransactionData[]>([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)

    useEffect(() => {
        async function load() {
            try {
                const [balRes, txRes] = await Promise.all([
                    fetch("/api/credits/balance"),
                    fetch("/api/credits/transactions?limit=5"),
                ])
                const balData = await balRes.json()
                const txData = await txRes.json()

                if (balData.success) setBalance(balData.data.balance)
                if (txData.success) setRecent(txData.data.transactions)
            } catch {
                setError(t("failedToLoadCredits"))
            } finally {
                setLoading(false)
            }
        }
        load()
    }, [])

    if (loading) {
        return (
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2 text-lg">
                        <Coins className="h-5 w-5" />
                        {t("title")}
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    <p className="text-sm text-muted-foreground">
                        {t("loading")}
                    </p>
                </CardContent>
            </Card>
        )
    }

    if (error) {
        return (
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2 text-lg">
                        <Coins className="h-5 w-5" />
                        {t("title")}
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    <p className="text-sm text-muted-foreground">{error}</p>
                </CardContent>
            </Card>
        )
    }

    return (
        <Card>
            <CardHeader>
                <CardTitle className="flex items-center gap-2 text-lg">
                    <Coins className="h-5 w-5" />
                    {t("title")}
                </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
                <div className="text-3xl font-bold">
                    {balance?.toLocaleString() ?? 0}
                </div>
                <p className="text-xs text-muted-foreground">
                    {t("availableBalance")}
                </p>

                {recent.length > 0 && (
                    <div className="space-y-2 pt-2 border-t">
                        <p className="text-xs font-medium text-muted-foreground">
                            {t("recent")}
                        </p>
                        {recent.slice(0, 3).map(tx => (
                            <div
                                key={tx.id}
                                className="flex items-center justify-between text-xs"
                            >
                                <div className="flex items-center gap-1.5">
                                    {tx.type === "credit" ? (
                                        <TrendingUp className="h-3 w-3 text-green-500" />
                                    ) : (
                                        <TrendingDown className="h-3 w-3 text-red-500" />
                                    )}
                                    <span className="truncate max-w-[140px]">
                                        {tx.reason}
                                    </span>
                                </div>
                                <span
                                    className={
                                        tx.type === "credit"
                                            ? "text-green-600"
                                            : "text-red-600"
                                    }
                                >
                                    {tx.type === "credit" ? "+" : "-"}
                                    {tx.amount}
                                </span>
                            </div>
                        ))}
                    </div>
                )}
            </CardContent>
        </Card>
    )
}

export function CreditCostsTable() {
    const t = useTranslations("dashboard.credits")
    return (
        <Card>
            <CardHeader>
                <CardTitle className="text-lg">{t("creditCosts")}</CardTitle>
            </CardHeader>
            <CardContent>
                <div className="divide-y text-sm">
                    {Object.entries(CREDIT_COSTS).map(([action, cost]) => (
                        <div
                            key={action}
                            className="flex items-center justify-between py-2"
                        >
                            <span className="text-muted-foreground font-mono text-xs">
                                {action}
                            </span>
                            <span className="font-medium">
                                {cost === 0
                                    ? t("free")
                                    : `${cost} ${t("credits")}`}
                            </span>
                        </div>
                    ))}
                </div>
            </CardContent>
        </Card>
    )
}

"use client"

import { cn } from "@/lib/utils"
import { useTranslations } from "next-intl"
import React, { useState } from "react"

const CONNECT_MSG = "Connect Channels"

export interface SocialChannel {
    id: string
    name: string
    icon: React.ReactNode
    isConnected: boolean
}

export interface ChannelConnectorProps {
    channels: SocialChannel[]
    onConnect: (channelId: string) => void
    onDisconnect: (channelId: string) => void
    className?: string
}

/**
 * ChannelConnector Component
 * Social channel connection management UI
 * Features:
 * - Display icons for supported social networks
 * - Show connection status (connected/disconnected)
 * - Allow users to connect/disconnect channels
 * - Visual indicators for connection status
 * - Tailwind CSS styling with Vercel color palette
 * - Accessible with ARIA attributes
 */
export const ChannelConnector: React.FC<ChannelConnectorProps> = ({
    channels,
    onConnect,
    onDisconnect,
    className,
}) => {
    const lt = useTranslations("dashboard.layout")
    const st = useTranslations("dashboard.sidebar")
    const [hoveredChannel, setHoveredChannel] = useState<string | null>(null)

    const handleChannelClick = (channel: SocialChannel) => {
        if (channel.isConnected) {
            onDisconnect(channel.id)
        } else {
            onConnect(channel.id)
        }
    }

    return (
        <div className={cn("space-y-3", className)}>
            <h3 className="text-xs font-semibold uppercase tracking-wide text-gray-500">
                {st("connectChannels")}
            </h3>
            <div className="grid grid-cols-3 gap-2 sm:grid-cols-5">
                {channels.map(channel => (
                    <div
                        key={channel.id}
                        className="relative"
                        onMouseEnter={() => setHoveredChannel(channel.id)}
                        onMouseLeave={() => setHoveredChannel(null)}
                    >
                        <button
                            onClick={() => handleChannelClick(channel)}
                            className={cn(
                                "relative flex h-12 w-12 items-center justify-center rounded-lg border-2 transition-all",
                                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-blue-500 focus-visible:ring-offset-2",
                                channel.isConnected
                                    ? "border-blue-500 bg-blue-50 text-blue-600 hover:bg-blue-100"
                                    : "border-gray-200 bg-white text-gray-600 hover:border-blue-300 hover:bg-blue-50 hover:text-blue-600"
                            )}
                            title={channel.name}
                            aria-label={`${channel.name} - ${channel.isConnected ? lt("connected") : lt("disconnected")}`}
                            aria-pressed={channel.isConnected}
                        >
                            <span className="flex h-6 w-6 items-center justify-center text-lg">
                                {channel.icon}
                            </span>

                            {/* Connection Status Indicator */}
                            {channel.isConnected && (
                                <div className="absolute -right-1 -top-1 flex h-5 w-5 items-center justify-center rounded-full bg-green-500 text-white">
                                    <svg
                                        className="h-3 w-3"
                                        fill="currentColor"
                                        viewBox="0 0 20 20"
                                    >
                                        <path
                                            fillRule="evenodd"
                                            d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"
                                            clipRule="evenodd"
                                        />
                                    </svg>
                                </div>
                            )}
                        </button>

                        {/* Tooltip */}
                        {hoveredChannel === channel.id && (
                            <div className="absolute bottom-full left-1/2 mb-2 -translate-x-1/2 whitespace-nowrap rounded-md bg-gray-900 px-2 py-1 text-xs text-white">
                                {channel.name}
                                <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-gray-900" />
                            </div>
                        )}
                    </div>
                ))}
            </div>

            {/* Connection Status Summary */}
            <div className="text-xs text-gray-500">
                {lt("channelsConnected", {
                    count: channels.filter(c => c.isConnected).length,
                    total: channels.length,
                })}
            </div>
        </div>
    )
}

"use client"

import { logger } from "@/lib/logger"
import { useLocale, useTranslations } from "next-intl"
import { useRouter } from "next/navigation"
import React, { useState } from "react"
import { Sidebar } from "./Sidebar"

export interface DashboardLayoutProps {
    children: React.ReactNode
    activeTab: "publish" | "insights" | "settings"
    onTabChange?: (tab: "publish" | "insights" | "settings") => void
}

/**
 * DashboardLayout Component
 * Main layout wrapper for authenticated dashboard
 * Combines Sidebar navigation with main content area
 * Responsive: Sidebar collapses to hamburger on mobile (<768px)
 */
export const DashboardLayout: React.FC<DashboardLayoutProps> = ({
    children,
    activeTab,
    onTabChange,
}) => {
    const t = useTranslations("dashboard.layout")
    const locale = useLocale()
    const router = useRouter()
    const [sidebarOpen, setSidebarOpen] = useState(false)
    const [isLoggingOut, setIsLoggingOut] = useState(false)
    const [logoutError, setLogoutError] = useState<string | null>(null)

    const handleTabChange = (tab: "publish" | "insights" | "settings") => {
        setSidebarOpen(false)
        onTabChange?.(tab)
    }

    const handleLogout = async () => {
        try {
            setIsLoggingOut(true)
            setLogoutError(null)

            const csrfRes = await fetch("/api/auth/csrf")
            if (!csrfRes.ok) {
                throw new Error("Failed to get CSRF token")
            }
            const csrfData = await csrfRes.json()
            const csrfToken = csrfData.data?.csrfToken
            if (!csrfToken) {
                throw new Error("No CSRF token returned")
            }

            const response = await fetch("/api/auth/logout", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "X-CSRF-Token": csrfToken,
                },
            })

            if (!response.ok) {
                const data = await response.json()
                throw new Error(data.error || "Logout failed")
            }

            logger.info("User logged out successfully", {
                context: "Dashboard",
            })

            router.push(`/${locale}/login`)
        } catch (err) {
            const error = err instanceof Error ? err : new Error(String(err))
            logger.error("Logout error", {
                context: "Dashboard",
                error,
            })
            setLogoutError(error.message)
        } finally {
            setIsLoggingOut(false)
        }
    }

    return (
        <div className="flex h-screen bg-white dark:bg-gray-950">
            {/* Sidebar */}
            <Sidebar
                activeTab={activeTab}
                onTabChange={handleTabChange}
                isOpen={sidebarOpen}
                onClose={() => setSidebarOpen(false)}
                onLogout={handleLogout}
            />

            {/* Mobile overlay */}
            {sidebarOpen && (
                <div
                    className="fixed inset-0 z-30 bg-black/50 md:hidden"
                    onClick={() => setSidebarOpen(false)}
                    aria-hidden="true"
                />
            )}

            {/* Main content area */}
            <main className="flex-1 overflow-auto">
                {/* Mobile header with hamburger */}
                <div className="sticky top-0 z-20 flex items-center justify-between border-b border-gray-200 dark:border-gray-800 bg-white dark:bg-gray-950 px-3 py-3 sm:px-4 md:hidden">
                    <button
                        onClick={() => setSidebarOpen(!sidebarOpen)}
                        className="inline-flex items-center justify-center rounded-md p-2 text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800 focus:outline-none focus:ring-2 focus:ring-blue-500 min-h-10 min-w-10"
                        aria-label={t("toggleSidebar")}
                        aria-expanded={sidebarOpen}
                    >
                        <svg
                            className="h-6 w-6"
                            fill="none"
                            stroke="currentColor"
                            viewBox="0 0 24 24"
                        >
                            <path
                                strokeLinecap="round"
                                strokeLinejoin="round"
                                strokeWidth={2}
                                d="M4 6h16M4 12h16M4 18h16"
                            />
                        </svg>
                    </button>
                    <span className="text-xs sm:text-sm font-medium text-gray-900 dark:text-white">
                        {t("dashboard")}
                    </span>
                </div>

                {/* Logout error message */}
                {logoutError && (
                    <div className="mx-3 mt-3 sm:mx-4 sm:mt-4 md:mx-6 md:mt-6 rounded-md bg-red-50 dark:bg-red-950/30 p-3 text-sm text-red-800 dark:text-red-400">
                        {logoutError}
                    </div>
                )}

                {/* Content */}
                <div className="p-3 sm:p-4 md:p-6">{children}</div>
            </main>
        </div>
    )
}

"use client"

import { cn } from "@/lib/utils"
import { useTranslations } from "next-intl"

export interface CalendarDayProps {
    day: number
    isCurrentMonth: boolean
    isToday: boolean
    postCount: number
    isWeekend?: boolean
    onSelect: () => void
}

export default function CalendarDay({
    day,
    isCurrentMonth,
    isToday,
    postCount,
    isWeekend = false,
    onSelect,
}: CalendarDayProps) {
    const t = useTranslations("dashboard.publish")
    if (!isCurrentMonth) {
        return <div className="h-10 sm:h-14" />
    }

    return (
        <button
            onClick={onSelect}
            className={cn(
                "relative flex h-10 sm:h-14 flex-col items-center justify-center rounded-lg text-sm transition-colors",
                "hover:bg-blue-50 hover:text-blue-700 focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-500 dark:hover:bg-blue-950/50 dark:hover:text-blue-400",
                isWeekend && "text-gray-500 dark:text-gray-500",
                isToday &&
                    "bg-blue-100 font-semibold text-blue-700 ring-2 ring-blue-300 dark:bg-blue-900 dark:text-blue-300 dark:ring-blue-700",
                !isToday && "text-gray-900 dark:text-gray-200"
            )}
            aria-label={`${day}${postCount > 0 ? `, ${postCount} ${postCount !== 1 ? "posts" : "post"}` : ""}`}
        >
            <span>{day}</span>
            {postCount > 0 && (
                <span className="absolute -bottom-0.5 left-1/2 h-1.5 w-1.5 -translate-x-1/2 rounded-full bg-blue-500" />
            )}
        </button>
    )
}

"use client"

import { Button } from "@/components/ui/button"
import {
    addMonths,
    eachDayOfInterval,
    endOfMonth,
    endOfWeek,
    format,
    isSameDay,
    isSameMonth,
    isToday,
    startOfMonth,
    startOfWeek,
    subMonths,
} from "date-fns"
import { ChevronLeft, ChevronRight } from "lucide-react"
import { useLocale, useTranslations } from "next-intl"
import { useCallback, useMemo, useState } from "react"
import CalendarDay from "./CalendarDay"

export interface CalendarPost {
    id: string
    scheduledTime: number
}

export interface CalendarViewProps {
    posts: CalendarPost[]
    selectedDate: Date | null
    onSelectDate: (date: Date) => void
}

export default function CalendarView({
    posts,
    selectedDate,
    onSelectDate,
}: CalendarViewProps) {
    const t = useTranslations("dashboard.publish")
    const locale = useLocale()
    const DAY_HEADERS = useMemo(() => {
        const formatter = new Intl.DateTimeFormat(locale, { weekday: "short" })
        return Array.from({ length: 7 }, (_, i) =>
            formatter.format(new Date(2024, 0, i + 1))
        )
    }, [locale])
    const [currentMonth, setCurrentMonth] = useState(new Date())

    const monthStart = useMemo(() => startOfMonth(currentMonth), [currentMonth])
    const monthEnd = useMemo(() => endOfMonth(currentMonth), [currentMonth])
    const calendarStart = useMemo(
        () => startOfWeek(monthStart, { weekStartsOn: 0 }),
        [monthStart]
    )
    const calendarEnd = useMemo(
        () => endOfWeek(monthEnd, { weekStartsOn: 0 }),
        [monthEnd]
    )

    const days = useMemo(
        () => eachDayOfInterval({ start: calendarStart, end: calendarEnd }),
        [calendarStart, calendarEnd]
    )

    const postDays = useMemo(() => {
        const map = new Map<string, number>()
        for (const post of posts) {
            const dateKey = format(new Date(post.scheduledTime), "yyyy-MM-dd")
            map.set(dateKey, (map.get(dateKey) || 0) + 1)
        }
        return map
    }, [posts])

    const goToPrevMonth = useCallback(
        () => setCurrentMonth(d => subMonths(d, 1)),
        []
    )
    const goToNextMonth = useCallback(
        () => setCurrentMonth(d => addMonths(d, 1)),
        []
    )
    const goToToday = useCallback(() => setCurrentMonth(new Date()), [])

    const weeks = useMemo(() => {
        const result: Date[][] = []
        for (let i = 0; i < days.length; i += 7) {
            result.push(days.slice(i, i + 7))
        }
        return result
    }, [days])

    return (
        <div className="rounded-lg border bg-white p-4 dark:border-gray-700 dark:bg-gray-800">
            <div className="mb-4 flex items-center justify-between">
                <h2 className="text-lg font-semibold text-gray-900 dark:text-white">
                    {format(currentMonth, "MMMM yyyy")}
                </h2>
                <div className="flex items-center gap-1">
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={goToPrevMonth}
                        aria-label={t("previousMonth")}
                        className="h-8 w-8 p-0"
                    >
                        <ChevronLeft className="h-4 w-4" />
                    </Button>
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={goToToday}
                        className="text-xs"
                    >
                        {t("today")}
                    </Button>
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={goToNextMonth}
                        aria-label={t("nextMonth")}
                        className="h-8 w-8 p-0"
                    >
                        <ChevronRight className="h-4 w-4" />
                    </Button>
                </div>
            </div>

            <div className="grid grid-cols-7 gap-px">
                {DAY_HEADERS.map(header => (
                    <div
                        key={header}
                        className="py-2 text-center text-xs font-medium text-gray-600 dark:text-gray-400"
                    >
                        {header}
                    </div>
                ))}

                {weeks.map((week, weekIdx) =>
                    week.map((day, dayIdx) => {
                        const dateKey = format(day, "yyyy-MM-dd")
                        const count = postDays.get(dateKey) || 0
                        const today = isToday(day)
                        const currentMonth = isSameMonth(day, monthStart)

                        return (
                            <CalendarDay
                                key={`${weekIdx}-${dayIdx}`}
                                day={day.getDate()}
                                isCurrentMonth={currentMonth}
                                isToday={today}
                                postCount={count}
                                isWeekend={
                                    day.getDay() === 0 || day.getDay() === 6
                                }
                                onSelect={() => onSelectDate(day)}
                            />
                        )
                    })
                )}
            </div>

            <div className="mt-3 flex items-center gap-4 text-xs text-gray-600 dark:text-gray-400">
                <div className="flex items-center gap-1">
                    <span className="inline-block h-2 w-2 rounded-full bg-blue-500" />
                    <span>{t("hasScheduledPosts")}</span>
                </div>
                {selectedDate && (
                    <div className="flex items-center gap-1 text-blue-700 dark:text-blue-400">
                        <span>
                            {t("selected", {
                                date: format(selectedDate, "MMM d, yyyy"),
                            })}
                        </span>
                    </div>
                )}
            </div>
        </div>
    )
}

"use client"

import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { AlertCircle, Bold, Italic, Link2, Underline, X } from "lucide-react"
import { useTranslations } from "next-intl"
import React, { useCallback, useState } from "react"

interface ContentCreatorProps {
    onContentChange: (content: {
        text: string
        images: File[]
        urls: string[]
        draft?: boolean
    }) => void
    platformLimits?: Record<string, number>
}

const PLATFORM_LIMITS: Record<string, number> = {
    twitter: 280,
    facebook: 63206,
    instagram: 2200,
    linkedin: 3000,
    youtube: 5000,
}

export default function ContentCreator({
    onContentChange,
    platformLimits = PLATFORM_LIMITS,
}: ContentCreatorProps) {
    const t = useTranslations("dashboard.publish")
    const [text, setText] = useState("")
    const [images, setImages] = useState<File[]>([])
    const [urls, setUrls] = useState<string[]>([])
    const [urlInput, setUrlInput] = useState("")
    const [isDraft, setIsDraft] = useState(false)
    const [selectedPlatforms, setSelectedPlatforms] = useState<string[]>([])

    const characterCount = text.length
    const maxLimit =
        selectedPlatforms.length > 0
            ? Math.min(...selectedPlatforms.map(p => platformLimits[p] || 5000))
            : 5000

    const isOverLimit = characterCount > maxLimit

    const handleImageUpload = useCallback(
        (e: React.ChangeEvent<HTMLInputElement>) => {
            const files = Array.from(e.target.files || [])
            setImages(prev => [...prev, ...files])
            onContentChange({
                text,
                images: [...images, ...files],
                urls,
                draft: isDraft,
            })
        },
        [text, images, urls, isDraft, onContentChange]
    )

    const removeImage = (index: number) => {
        const newImages = images.filter((_, i) => i !== index)
        setImages(newImages)
        onContentChange({
            text,
            images: newImages,
            urls,
            draft: isDraft,
        })
    }

    const addUrl = () => {
        if (urlInput.trim() && !urls.includes(urlInput.trim())) {
            const newUrls = [...urls, urlInput.trim()]
            setUrls(newUrls)
            setUrlInput("")
            onContentChange({
                text,
                images,
                urls: newUrls,
                draft: isDraft,
            })
        }
    }

    const removeUrl = (index: number) => {
        const newUrls = urls.filter((_, i) => i !== index)
        setUrls(newUrls)
        onContentChange({
            text,
            images,
            urls: newUrls,
            draft: isDraft,
        })
    }

    const handleTextChange = (newText: string) => {
        setText(newText)
        onContentChange({
            text: newText,
            images,
            urls,
            draft: isDraft,
        })
    }

    const applyFormatting = (before: string, after: string = "") => {
        const textarea = document.getElementById(
            "content-textarea"
        ) as HTMLTextAreaElement
        if (!textarea) return

        const start = textarea.selectionStart
        const end = textarea.selectionEnd
        const selectedText = text.substring(start, end)
        const newText =
            text.substring(0, start) +
            before +
            selectedText +
            after +
            text.substring(end)

        handleTextChange(newText)
    }

    return (
        <div className="space-y-4 rounded-lg border p-4">
            <div className="space-y-2">
                <h3 className="font-semibold">{t("createContent")}</h3>
                <p className="text-sm text-gray-600">
                    {t("contentDescription")}
                </p>
            </div>

            <div className="space-y-2">
                <Label htmlFor="content-textarea">{t("content")}</Label>
                <div className="space-y-2">
                    <div className="flex gap-1 rounded border bg-gray-50 p-2">
                        <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => applyFormatting("**", "**")}
                            title={t("bold")}
                            aria-label={t("bold")}
                        >
                            <Bold className="h-4 w-4" />
                        </Button>
                        <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => applyFormatting("*", "*")}
                            title={t("italic")}
                            aria-label={t("italic")}
                        >
                            <Italic className="h-4 w-4" />
                        </Button>
                        <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => applyFormatting("__", "__")}
                            title={t("underline")}
                            aria-label={t("underline")}
                        >
                            <Underline className="h-4 w-4" />
                        </Button>
                        <div className="border-l" />
                        <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => applyFormatting("[", "](url)")}
                            title={t("link")}
                            aria-label={t("link")}
                        >
                            <Link2 className="h-4 w-4" />
                        </Button>
                    </div>

                    <Textarea
                        id="content-textarea"
                        placeholder={t("whatsOnYourMind")}
                        value={text}
                        onChange={e => handleTextChange(e.target.value)}
                        className="min-h-32 resize-none"
                        aria-label={t("content")}
                    />

                    <div className="flex items-center justify-between">
                        <span
                            className={`text-sm ${
                                isOverLimit
                                    ? "text-red-600 font-semibold"
                                    : "text-gray-600"
                            }`}
                            aria-live="polite"
                        >
                            {t("characters", {
                                count: characterCount,
                                limit: maxLimit,
                            })}
                        </span>
                        {isOverLimit && (
                            <div className="flex items-center gap-1 text-red-600">
                                <AlertCircle className="h-4 w-4" />
                                <span className="text-sm">
                                    {t("exceedsLimit")}
                                </span>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            <div className="space-y-2">
                <Label htmlFor="image-upload">{t("images")}</Label>
                <Input
                    id="image-upload"
                    type="file"
                    multiple
                    accept="image/*"
                    onChange={handleImageUpload}
                    aria-label={t("uploadImages")}
                />
                {images.length > 0 && (
                    <div className="grid grid-cols-3 gap-2">
                        {images.map((img, idx) => (
                            <div key={idx} className="relative">
                                <img
                                    src={URL.createObjectURL(img)}
                                    alt={`Upload ${idx + 1}`}
                                    className="h-20 w-full rounded object-cover"
                                />
                                <button
                                    onClick={() => removeImage(idx)}
                                    className="absolute -top-2 -right-2 rounded-full bg-red-500 p-1 text-white hover:bg-red-600"
                                    aria-label={
                                        t("delete") +
                                        " " +
                                        t("images") +
                                        " " +
                                        (idx + 1)
                                    }
                                >
                                    <X className="h-3 w-3" />
                                </button>
                            </div>
                        ))}
                    </div>
                )}
            </div>

            <div className="space-y-2">
                <Label htmlFor="url-input">{t("addUrls")}</Label>
                <div className="flex gap-2">
                    <Input
                        id="url-input"
                        type="url"
                        placeholder="https://example.com"
                        value={urlInput}
                        onChange={e => setUrlInput(e.target.value)}
                        onKeyPress={e => e.key === "Enter" && addUrl()}
                        aria-label={t("addUrls")}
                    />
                    <Button onClick={addUrl} variant="outline">
                        {t("add")}
                    </Button>
                </div>
                {urls.length > 0 && (
                    <div className="flex flex-wrap gap-2">
                        {urls.map((url, idx) => (
                            <Badge
                                key={idx}
                                variant="secondary"
                                className="gap-2"
                            >
                                <a
                                    href={url}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="truncate hover:underline"
                                >
                                    {url}
                                </a>
                                <button
                                    onClick={() => removeUrl(idx)}
                                    aria-label={
                                        t("delete") +
                                        " " +
                                        t("addUrls") +
                                        " " +
                                        (idx + 1)
                                    }
                                >
                                    <X className="h-3 w-3" />
                                </button>
                            </Badge>
                        ))}
                    </div>
                )}
            </div>

            <div className="flex items-center gap-2">
                <input
                    type="checkbox"
                    id="draft"
                    checked={isDraft}
                    onChange={e => {
                        setIsDraft(e.target.checked)
                        onContentChange({
                            text,
                            images,
                            urls,
                            draft: e.target.checked,
                        })
                    }}
                    aria-label={t("saveAsDraft")}
                />
                <Label htmlFor="draft" className="cursor-pointer">
                    {t("saveAsDraft")}
                </Label>
            </div>
        </div>
    )
}

"use client"

import { Badge } from "@/components/ui/badge"
import { Checkbox } from "@/components/ui/checkbox"
import { Input } from "@/components/ui/input"
import { useTranslations } from "next-intl"
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import {
    SiFacebook,
    SiInstagram,
    SiX,
    SiYoutube,
} from "@icons-pack/react-simple-icons"
import { AlertCircle } from "lucide-react"
import React, { useMemo, useState } from "react"
import { FaLinkedin } from "react-icons/fa6"

export interface Network {
    id: string
    platform: string
    status: "connected" | "disconnected" | "expired"
    metadata?: Record<string, any>
}

export interface NetworkGroup {
    id: string
    name: string
    networkIds: string[]
}

export interface NetworkSelectorProps {
    networks: Network[]
    groups: NetworkGroup[]
    selectedNetworkIds: string[]
    onNetworkToggle: (networkId: string) => void
    onGroupToggle: (groupId: string) => void
    onSelectAll: () => void
    onDeselectAll: () => void
}

const platformIcons: Record<string, React.ReactNode> = {
    youtube: <SiYoutube className="h-4 w-4" />,
    facebook: <SiFacebook className="h-4 w-4" />,
    instagram: <SiInstagram className="h-4 w-4" />,
    twitter: <SiX className="h-4 w-4" />,
    linkedin: <FaLinkedin className="h-4 w-4" />,
}

export default function NetworkSelector({
    networks,
    groups,
    selectedNetworkIds,
    onNetworkToggle,
    onGroupToggle,
    onSelectAll,
    onDeselectAll,
}: NetworkSelectorProps) {
    const [searchTerm, setSearchTerm] = useState("")
    const [sortBy, setSortBy] = useState<"name" | "status">("name")
    const t = useTranslations("dashboard.publish")

    const filteredNetworks = useMemo(() => {
        return networks
            .filter(
                n =>
                    n.platform
                        .toLowerCase()
                        .includes(searchTerm.toLowerCase()) ||
                    n.id.toLowerCase().includes(searchTerm.toLowerCase())
            )
            .sort((a, b) => {
                if (sortBy === "status") {
                    const statusOrder = {
                        connected: 0,
                        disconnected: 1,
                        expired: 2,
                    }
                    return statusOrder[a.status] - statusOrder[b.status]
                }
                return a.platform.localeCompare(b.platform)
            })
    }, [networks, searchTerm, sortBy])

    const filteredGroups = useMemo(() => {
        return groups.filter(g =>
            g.name.toLowerCase().includes(searchTerm.toLowerCase())
        )
    }, [groups, searchTerm])

    const getGroupState = (groupId: string) => {
        const group = groups.find(g => g.id === groupId)
        if (!group) return "unchecked"

        const selectedCount = group.networkIds.filter(id =>
            selectedNetworkIds.includes(id)
        ).length

        if (selectedCount === 0) return "unchecked"
        if (selectedCount === group.networkIds.length) return "checked"
        return "indeterminate"
    }

    const statusColors: Record<string, string> = {
        connected: "bg-green-100 text-green-800",
        disconnected: "bg-gray-100 text-gray-800",
        expired: "bg-red-100 text-red-800",
    }

    const statusLabels: Record<string, string> = {
        connected: "Connected",
        disconnected: "Disconnected",
        expired: "Expired",
    }

    return (
        <div className="space-y-4 rounded-lg border p-4">
            <div className="space-y-2">
                <h3 className="font-semibold">{t("selectNetworks")}</h3>
                <p className="text-sm text-gray-600">
                    {t("xOfYSelected", {
                        selected: selectedNetworkIds.length,
                        total: networks.length,
                    })}
                </p>
            </div>

            <div className="space-y-3">
                <Input
                    placeholder={t("searchNetworks")}
                    value={searchTerm}
                    onChange={e => setSearchTerm(e.target.value)}
                    aria-label={t("searchNetworks")}
                />

                <div className="flex gap-2">
                    <Select
                        value={sortBy}
                        onValueChange={(v: any) => setSortBy(v)}
                    >
                        <SelectTrigger className="w-32">
                            <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="name">
                                {t("sortByName")}
                            </SelectItem>
                            <SelectItem value="status">
                                {t("sortByStatus")}
                            </SelectItem>
                        </SelectContent>
                    </Select>

                    <button
                        onClick={onSelectAll}
                        className="text-sm text-blue-600 hover:underline"
                        aria-label={t("selectAll")}
                    >
                        {t("selectAll")}
                    </button>
                    <button
                        onClick={onDeselectAll}
                        className="text-sm text-blue-600 hover:underline"
                        aria-label={t("deselectAll")}
                    >
                        {t("deselectAll")}
                    </button>
                </div>
            </div>

            {filteredGroups.length > 0 && (
                <div className="space-y-2 border-t pt-3">
                    <h4 className="text-sm font-medium">{t("groups")}</h4>
                    {filteredGroups.map(group => {
                        const state = getGroupState(group.id)
                        return (
                            <div
                                key={group.id}
                                className="flex items-center gap-2"
                            >
                                <Checkbox
                                    id={`group-${group.id}`}
                                    checked={state === "checked"}
                                    ref={el => {
                                        if (
                                            el &&
                                            state === "indeterminate" &&
                                            "indeterminate" in el
                                        ) {
                                            ;(
                                                el as unknown as HTMLInputElement
                                            ).indeterminate = true
                                        }
                                    }}
                                    onCheckedChange={() =>
                                        onGroupToggle(group.id)
                                    }
                                    aria-label={`${group.name} group`}
                                />
                                <label
                                    htmlFor={`group-${group.id}`}
                                    className="cursor-pointer text-sm font-medium"
                                >
                                    {group.name}
                                </label>
                                <span className="text-xs text-gray-500">
                                    ({group.networkIds.length})
                                </span>
                            </div>
                        )
                    })}
                </div>
            )}

            <div className="space-y-2 border-t pt-3">
                <h4 className="text-sm font-medium">{t("networks")}</h4>
                {filteredNetworks.length === 0 ? (
                    <p className="text-sm text-gray-500">
                        {t("noNetworksFound")}
                    </p>
                ) : (
                    <div className="space-y-2 max-h-64 overflow-y-auto">
                        {filteredNetworks.map(network => (
                            <div
                                key={network.id}
                                className="flex items-center gap-3 rounded p-2 hover:bg-gray-50"
                            >
                                <Checkbox
                                    id={`network-${network.id}`}
                                    checked={selectedNetworkIds.includes(
                                        network.id
                                    )}
                                    onCheckedChange={() =>
                                        onNetworkToggle(network.id)
                                    }
                                    aria-label={`${network.platform} network`}
                                />
                                <div className="flex flex-1 items-center gap-2">
                                    {platformIcons[
                                        network.platform.toLowerCase()
                                    ] || <div className="h-4 w-4" />}
                                    <label
                                        htmlFor={`network-${network.id}`}
                                        className="cursor-pointer flex-1 text-sm font-medium capitalize"
                                    >
                                        {network.platform}
                                    </label>
                                </div>
                                <div className="flex items-center gap-2">
                                    <Badge
                                        variant="secondary"
                                        className={statusColors[network.status]}
                                    >
                                        {statusLabels[network.status]}
                                    </Badge>
                                    {network.status === "expired" && (
                                        <AlertCircle className="h-4 w-4 text-red-500" />
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    )
}

