    images: File[]
    urls: string[]
    draft?: boolean
}

interface Schedule {
    type: "immediate" | "scheduled"
    scheduledTime?: Date
    timezone?: string
}

export default function PostingInterface({
    onClose,
    defaultDate,
}: PostingInterfaceProps) {
    const [networks, setNetworks] = useState<Network[]>([])
    const [groups, setGroups] = useState<NetworkGroup[]>([])
    const [selectedNetworkIds, setSelectedNetworkIds] = useState<string[]>([])
    const [content, setContent] = useState<PostContent>({
        text: "",
        images: [],
        urls: [],
    })
    const [schedule, setSchedule] = useState<Schedule>({
        type: defaultDate ? "scheduled" : "immediate",
    })
    const [isSubmitting, setIsSubmitting] = useState(false)
    const [isLoadingNetworks, setIsLoadingNetworks] = useState(true)
    const [error, setError] = useState("")
    const [success, setSuccess] = useState(false)
    const t = useTranslations("dashboard.publish")

    useEffect(() => {
        async function loadNetworks() {
            try {
                const res = await fetch("/api/networks/status")
                if (!res.ok) throw new Error("Failed to load networks")
                const data = await res.json()

                const mapped: Network[] = (data.networks || data || []).map(
                    (n: any, i: number) => ({
                        id: n.id || n.platform || String(i),
                        platform: n.platform || n.name,
                        status:
                            n.status === "connected"
                                ? "connected"
                                : n.status === "expired"
                                  ? "expired"
                                  : "disconnected",
                    })
                )

                if (mapped.length === 0) {
                    setNetworks(exampleNetworks)
                } else {
                    setNetworks(mapped)
                }
            } catch {
                setNetworks(exampleNetworks)
            } finally {
                setIsLoadingNetworks(false)
            }
        }
        loadNetworks()
    }, [])

    const exampleNetworks: Network[] = [
        { id: "1", platform: "youtube", status: "connected" },
        { id: "2", platform: "facebook", status: "connected" },
        { id: "3", platform: "instagram", status: "connected" },
        { id: "4", platform: "twitter", status: "expired" },
        { id: "5", platform: "linkedin", status: "disconnected" },
    ]

    const handleNetworkToggle = useCallback((networkId: string) => {
        setSelectedNetworkIds(prev =>
            prev.includes(networkId)
                ? prev.filter(id => id !== networkId)
                : [...prev, networkId]
        )
    }, [])

    const handleGroupToggle = useCallback((_groupId: string) => {}, [])

    const handleSelectAll = useCallback(() => {
        setSelectedNetworkIds(
            networks.filter(n => n.status === "connected").map(n => n.id)
        )
    }, [networks])

    const handleDeselectAll = useCallback(() => {
        setSelectedNetworkIds([])
    }, [])

    const handlePublish = async () => {
        setError("")
        setSuccess(false)

        if (selectedNetworkIds.length === 0) {
            setError(t("networkRequired"))
            return
        }

        if (!content.text.trim() && content.images.length === 0) {
            setError(t("contentRequired"))
            return
        }

        const expiredNetworks = selectedNetworkIds.filter(id => {
            const network = networks.find(n => n.id === id)
            return network?.status === "expired"
        })

        if (expiredNetworks.length > 0) {
            setError(t("expiredAuth"))
            return
        }

        setIsSubmitting(true)

        try {
            const selectedPlatforms = selectedNetworkIds
                .map(id => networks.find(n => n.id === id)?.platform)
                .filter(Boolean) as string[]

            let scheduledTime: number | undefined
            if (schedule.type === "scheduled" && schedule.scheduledTime) {
                scheduledTime = schedule.scheduledTime.getTime()
            }

            if (schedule.type === "scheduled" && scheduledTime) {
                const res = await fetch("/api/posts", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        content: content.text,
                        scheduledTime,
                        platforms: selectedPlatforms,
                        mediaType: "text",
                    }),
                })

                if (!res.ok) {
                    const data = await res.json()
                    throw new Error(data.error || t("failedToSchedule"))
                }
            } else {
                // Immediate publish - send to each platform's publish endpoint
                await Promise.all(
                    selectedPlatforms.map(async platform => {
                        const res = await fetch(
                            `/api/platform/${platform}/publish`,
                            {
                                method: "POST",
                                headers: {
                                    "Content-Type": "application/json",
                                },
                                body: JSON.stringify({
                                    message: content.text,
                                }),
                            }
                        )
                        if (!res.ok) {
                            const data = await res.json()
                            console.error(
                                `Failed to publish to ${platform}:`,
                                data
                            )
                        }
                    })
                )
            }

            setSuccess(true)
            setTimeout(() => {
                onClose()
            }, 2000)
        } catch (err) {
            setError(err instanceof Error ? err.message : t("failedToPublish"))
        } finally {
            setIsSubmitting(false)
        }
    }

    return (
        <Dialog open={true} onOpenChange={onClose}>
            <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle>
                        {defaultDate
                            ? t("schedulePost") +
                              " " +
                              defaultDate.toLocaleDateString()
                            : t("universalPosting")}
                    </DialogTitle>
                    <DialogDescription>
                        {t("universalPostingDesc")}
                    </DialogDescription>
                    <button
                        onClick={onClose}
                        className="absolute right-4 top-4 rounded-sm opacity-70 hover:opacity-100"
                        aria-label={t("close")}
                    >
                        <X className="h-4 w-4" />
                    </button>
                </DialogHeader>

                <div className="space-y-4">
                    {error && (
                        <div className="flex items-center gap-2 rounded-lg bg-red-50 p-3 text-red-800 dark:bg-red-950/30 dark:text-red-400">
                            <AlertCircle className="h-5 w-5 flex-shrink-0" />
                            <p className="text-sm">{error}</p>
                        </div>
                    )}

                    {success && (
                        <div className="flex items-center gap-2 rounded-lg bg-green-50 p-3 text-green-800 dark:bg-green-950/30 dark:text-green-400">
                            <CheckCircle className="h-5 w-5 flex-shrink-0" />
                            <p className="text-sm">
                                {schedule.type === "immediate"
                                    ? t("postedSuccessfully")
                                    : t("postScheduled")}
                            </p>
                        </div>
                    )}

                    {isLoadingNetworks ? (
                        <div className="flex items-center justify-center py-8">
                            <Loader2 className="h-6 w-6 animate-spin text-gray-400 dark:text-gray-500" />
                        </div>
                    ) : (
                        <NetworkSelector
                            networks={networks}
                            groups={groups}
                            selectedNetworkIds={selectedNetworkIds}
                            onNetworkToggle={handleNetworkToggle}
                            onGroupToggle={handleGroupToggle}
                            onSelectAll={handleSelectAll}
                            onDeselectAll={handleDeselectAll}
                        />
                    )}

                    <ContentCreator onContentChange={setContent} />

                    <PostingScheduler
                        onScheduleChange={setSchedule}
                        defaultDate={defaultDate}
                    />

                    <div className="flex gap-2 border-t pt-4 dark:border-gray-700">
                        <Button
                            onClick={onClose}
                            variant="outline"
                            disabled={isSubmitting}
                            className="flex-1"
                        >
                            {t("cancel")}
                        </Button>
                        <Button
                            onClick={handlePublish}
                            disabled={
                                isSubmitting || selectedNetworkIds.length === 0
                            }
                            className="flex-1"
                        >
                            {isSubmitting && (
                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                            )}
                            {schedule.type === "immediate"
                                ? "Publish Now"
                                : "Schedule Post"}
                        </Button>
                    </div>
                </div>
            </DialogContent>
        </Dialog>
    )
}

"use client"

import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group"
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import { addDays, formatDistanceToNow, isBefore } from "date-fns"
import { format, fromZonedTime, toZonedTime } from "date-fns-tz"
import { AlertCircle, Calendar, Clock } from "lucide-react"
import { useTranslations } from "next-intl"
import { useEffect, useMemo, useState } from "react"

const timezones = [
    "America/New_York",
    "America/Chicago",
    "America/Denver",
    "America/Los_Angeles",
    "Europe/London",
    "Europe/Paris",
    "Europe/Berlin",
    "Europe/Madrid",
    "Europe/Lisbon",
    "Asia/Tokyo",
    "Asia/Shanghai",
    "Asia/Kolkata",
    "Australia/Sydney",
    "Pacific/Auckland",
    "America/Sao_Paulo",
    "America/Argentina/Buenos_Aires",
    "Africa/Cairo",
    "Africa/Lagos",
    "UTC",
]

function getBrowserTimezone(): string {
    try {
        return Intl.DateTimeFormat().resolvedOptions().timeZone || "UTC"
    } catch {
        return "UTC"
    }
}

function getStoredTimezone(): string {
    if (typeof window === "undefined") return "UTC"
    try {
        return localStorage.getItem("user-timezone") || getBrowserTimezone()
    } catch {
        return getBrowserTimezone()
    }
}

function formatDateForInput(date: Date): string {
    const y = date.getFullYear()
    const m = String(date.getMonth() + 1).padStart(2, "0")
    const d = String(date.getDate()).padStart(2, "0")
    return `${y}-${m}-${d}`
}

interface PostingSchedulerProps {
    onScheduleChange: (schedule: {
        type: "immediate" | "scheduled"
        scheduledTime?: Date
        timezone?: string
    }) => void
    defaultDate?: Date
}

export default function PostingScheduler({
    onScheduleChange,
    defaultDate,
}: PostingSchedulerProps) {
    const userTz = getStoredTimezone()
    const t = useTranslations("dashboard.publish")
    const [scheduleType, setScheduleType] = useState<"immediate" | "scheduled">(
        defaultDate ? "scheduled" : "immediate"
    )
    const [selectedTimezone, setSelectedTimezone] = useState(userTz)

    const initialDate = useMemo(() => {
        if (!defaultDate) return formatDateForInput(new Date())
        const zoned = toZonedTime(defaultDate, selectedTimezone)
        return formatDateForInput(zoned)
    }, [defaultDate, selectedTimezone])

    const [selectedDate, setSelectedDate] = useState(initialDate)
    const [selectedTime, setSelectedTime] = useState("00:00")
    const [error, setError] = useState("")

    useEffect(() => {
        if (defaultDate) {
            const zoned = toZonedTime(defaultDate, selectedTimezone)
            setSelectedDate(formatDateForInput(zoned))
            setSelectedTime("00:00")
        }
    }, [defaultDate, selectedTimezone])

    const maxDate = useMemo(() => {
        const max = addDays(new Date(), 365)
        return formatDateForInput(max)
    }, [])

    const minDate = useMemo(() => {
        return formatDateForInput(new Date())
    }, [])

    const previewTime = useMemo(() => {
        if (scheduleType === "immediate") {
            return t("now")
        }

        if (!selectedDate || !selectedTime) {
            return ""
        }

        try {
            const [hours, minutes] = selectedTime.split(":")
            const localDateTime = new Date(
                `${selectedDate}T${String(hours).padStart(2, "0")}:${String(minutes).padStart(2, "0")}:00`
            )

            const utcTime = fromZonedTime(localDateTime, selectedTimezone)

            if (isBefore(utcTime, new Date())) {
                setError(t("scheduleTimeFuture"))
                return ""
            }

            setError("")

            const formatted = format(localDateTime, "PPP p zzz", {
                timeZone: selectedTimezone,
            })

            return `${formatted} (${formatDistanceToNow(utcTime, { addSuffix: true })})`
        } catch {
            return ""
        }
    }, [scheduleType, selectedDate, selectedTime, selectedTimezone])

    const handleScheduleChange = () => {
        if (scheduleType === "immediate") {
            onScheduleChange({ type: "immediate" })
            return
        }

        if (!selectedDate || !selectedTime) {
            setError(t("selectDate") + " " + t("selectTime"))
            return
        }

        const [hours, minutes] = selectedTime.split(":")
        const localDateTime = new Date(
            `${selectedDate}T${String(hours).padStart(2, "0")}:${String(minutes).padStart(2, "0")}:00`
        )

        const utcTime = fromZonedTime(localDateTime, selectedTimezone)

        if (isBefore(utcTime, new Date())) {
            setError(t("scheduleTimeFuture"))
            return
        }

        setError("")
        onScheduleChange({
            type: "scheduled",
            scheduledTime: utcTime,
            timezone: selectedTimezone,
        })
    }

    return (
        <div className="space-y-4 rounded-lg border p-4">
            <div className="space-y-2">
                <h3 className="font-semibold">{t("schedule")}</h3>
                <p className="text-sm text-gray-600">
                    {t("scheduleDescription")}
                </p>
            </div>

            <RadioGroup
                value={scheduleType}
                onValueChange={(v: any) => setScheduleType(v)}
            >
                <div className="flex items-center gap-2">
                    <RadioGroupItem value="immediate" id="immediate" />
                    <Label htmlFor="immediate" className="cursor-pointer">
                        {t("publishNow")}
                    </Label>
                </div>

                <div className="flex items-center gap-2">
                    <RadioGroupItem value="scheduled" id="scheduled" />
                    <Label htmlFor="scheduled" className="cursor-pointer">
                        {t("scheduleForLater")}
                    </Label>
                </div>
            </RadioGroup>

            {scheduleType !== "immediate" && (
                <div className="space-y-3 border-t pt-3">
                    <div className="grid grid-cols-2 gap-3">
                        <div className="space-y-2">
                            <Label
                                htmlFor="date"
                                className="flex items-center gap-2"
                            >
                                <Calendar className="h-4 w-4" />
                                {t("scheduleDate")}
                            </Label>
                            <Input
                                id="date"
                                type="date"
                                value={selectedDate}
                                onChange={e => setSelectedDate(e.target.value)}
                                min={minDate}
                                max={maxDate}
                                aria-label={t("selectDate")}
                            />
                        </div>

                        <div className="space-y-2">
                            <Label
                                htmlFor="time"
                                className="flex items-center gap-2"
                            >
                                <Clock className="h-4 w-4" />
                                {t("scheduleTime")}
                            </Label>
                            <Input
                                id="time"
                                type="time"
                                value={selectedTime}
                                onChange={e => setSelectedTime(e.target.value)}
                                aria-label={t("selectTime")}
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="timezone">{t("timezone")}</Label>
                        <Select
                            value={selectedTimezone}
                            onValueChange={setSelectedTimezone}
                        >
                            <SelectTrigger id="timezone">
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                {timezones.map(tz => (
                                    <SelectItem key={tz} value={tz}>
                                        {tz}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                        <p className="text-xs text-gray-500">
                            {t("timezoneDescription")}
                        </p>
                    </div>

                    {previewTime && (
                        <div className="rounded bg-blue-50 p-3">
                            <p className="text-sm font-medium text-blue-900">
                                {t("schedulePost")}: {previewTime}
                            </p>
                        </div>
                    )}

                    {error && (
                        <div className="flex items-center gap-2 rounded bg-red-50 p-3 text-red-800">
                            <AlertCircle className="h-4 w-4" />
                            <p className="text-sm">{error}</p>
                        </div>
                    )}
                </div>
            )}

            <Button
                onClick={handleScheduleChange}
                className="w-full"
                aria-label={t("confirmSchedule")}
            >
                {scheduleType === "immediate"
                    ? t("readyToPublish")
                    : t("schedulePost")}
            </Button>
        </div>
    )
}

"use client"

import { validateEmail } from "@/lib/validation"
import { useEffect, useState } from "react"

interface EmailInputProps {
    value: string
    onChange: (email: string) => void
    onValidationChange?: (isValid: boolean) => void
    disabled?: boolean
}

export function EmailInput({
    value,
    onChange,
    onValidationChange,
    disabled = false,
}: EmailInputProps) {
    const [isChecking, setIsChecking] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const [isAvailable, setIsAvailable] = useState<boolean | null>(null)

    // Debounced email uniqueness check
    useEffect(() => {
        if (!value) {
            setError(null)
            setIsAvailable(null)
            onValidationChange?.(false)
            return
        }

        const validation = validateEmail(value)
        if (!validation.isValid) {
            setError(validation.error || "Invalid email format")
            setIsAvailable(null)
            onValidationChange?.(false)
            return
        }

        setError(null)

        const timer = setTimeout(async () => {
            setIsChecking(true)
            try {
                const response = await fetch(
                    `/api/auth/check-email?email=${encodeURIComponent(value)}`
                )
                const data = await response.json()

                if (data.success && data.data.available) {
                    setIsAvailable(true)
                    onValidationChange?.(true)
                } else {
                    setError("Email already registered")
                    setIsAvailable(false)
                    onValidationChange?.(false)
                }
            } catch (err) {
                setError("Failed to check email availability")
                setIsAvailable(false)
                onValidationChange?.(false)
            } finally {
                setIsChecking(false)
            }
        }, 500)

        return () => clearTimeout(timer)
    }, [value, onValidationChange])

    return (
        <div className="w-full">
            <label
                htmlFor="email"
                className="block text-sm sm:text-base font-medium text-gray-100 dark:text-gray-100 mb-2"
            >
                Email Address
            </label>
            <div className="relative">
                <input
                    id="email"
                    type="email"
                    value={value}
                    onChange={e => onChange(e.target.value)}
                    disabled={disabled}
                    placeholder="you@example.com"
                    className={`w-full px-4 py-3 sm:py-2 text-base sm:text-sm border rounded-lg focus:outline-none focus:ring-2 transition-all min-h-[44px] sm:min-h-auto ${
                        error
                            ? "border-red-500 focus:ring-red-200 dark:border-red-400 dark:focus:ring-red-900"
                            : isAvailable
                              ? "border-green-500 focus:ring-green-200 dark:border-green-400 dark:focus:ring-green-900"
                              : "border-gray-300 dark:border-gray-600 focus:ring-blue-200 dark:focus:ring-blue-900"
                    } ${disabled ? "bg-gray-100 dark:bg-gray-700 cursor-not-allowed" : "bg-white dark:bg-gray-800 text-gray-900 dark:text-gray-100"}`}
                    aria-label="Email address"
                    aria-describedby={
                        error
                            ? "email-error"
                            : isAvailable
                              ? "email-success"
                              : undefined
                    }
                    required
                />
                {isChecking && (
                    <div className="absolute right-3 top-1/2 -translate-y-1/2">
                        <div className="animate-spin h-5 w-5 border-2 border-blue-500 dark:border-blue-400 border-t-transparent rounded-full" />
                    </div>
                )}
                {isAvailable && !isChecking && (
                    <div className="absolute right-3 top-1/2 -translate-y-1/2 text-green-500 dark:text-green-400">
                        ✓
                    </div>
                )}
            </div>
            {error && (
                <p
                    id="email-error"
                    className="mt-2 text-sm text-red-600 dark:text-red-400"
                >
                    {error}
                </p>
            )}
            {isAvailable && (
                <p
                    id="email-success"
                    className="mt-2 text-sm text-green-600 dark:text-green-400"
                >
                    Email is available
                </p>
            )}
        </div>
    )
}

"use client"

import { calculatePasswordStrength } from "@/lib/auth/password-strength"
import { validatePassword } from "@/lib/validation"
import { useEffect, useState } from "react"

interface PasswordSetupProps {
    value: string
    confirmValue: string
    onChange: (password: string) => void
    onConfirmChange: (confirm: string) => void
    onValidationChange?: (isValid: boolean) => void
    disabled?: boolean
}

export function PasswordSetup({
    value,
    confirmValue,
    onChange,
    onConfirmChange,
    onValidationChange,
    disabled = false,
}: PasswordSetupProps) {
    const [showPassword, setShowPassword] = useState(false)
    const [showConfirm, setShowConfirm] = useState(false)
    const [error, setError] = useState<string | null>(null)

    const validation = validatePassword(value)
    const strength = calculatePasswordStrength(value)
    const passwordsMatch = value && confirmValue && value === confirmValue

    // Update validation state whenever password or confirm password changes
    useEffect(() => {
        // Password is valid only if:
        // 1. Password meets all requirements
        // 2. Confirm password is provided
        // 3. Passwords match
        const isValid = validation.isValid && confirmValue && passwordsMatch

        // Call validation callback immediately
        onValidationChange?.(Boolean(isValid))

        // Update error message based on current state
        if (!value) {
            // No password entered yet - no error
            setError(null)
        } else if (!validation.isValid) {
            // Password doesn't meet requirements
            setError(validation.error || "Password does not meet requirements")
        } else if (!confirmValue) {
            // Password is valid but confirm password is empty - no error yet
            setError(null)
        } else if (!passwordsMatch) {
            // Passwords don't match
            setError("Passwords do not match")
        } else {
            // Everything is valid
            setError(null)
        }
    }, [value, confirmValue, validation, passwordsMatch, onValidationChange])

    return (
        <div className="w-full space-y-4">
            {/* Password Input */}
            <div>
                <div className="mb-3 space-y-1">
                    <label
                        htmlFor="password"
                        className="block text-sm sm:text-base font-medium text-gray-100 dark:text-gray-100"
                    >
                        Password
                    </label>
                    <p className="text-xs sm:text-sm text-gray-500 dark:text-gray-400 font-medium">
                        Required: 8+ characters, uppercase, lowercase, number,
                        special character (!@#$%^&*)
                    </p>
                </div>
                <div className="relative">
                    <input
                        id="password"
                        type={showPassword ? "text" : "password"}
                        value={value}
                        onChange={e => onChange(e.target.value)}
                        disabled={disabled}
                        placeholder="Enter a strong password"
                        className={`w-full px-4 py-3 sm:py-2 text-base sm:text-sm border rounded-lg focus:outline-none focus:ring-2 transition-all min-h-[44px] sm:min-h-auto ${
                            value && !validation.isValid
                                ? "border-red-500 focus:ring-red-200 dark:border-red-400 dark:focus:ring-red-900"
                                : value && validation.isValid
                                  ? "border-green-500 focus:ring-green-200 dark:border-green-400 dark:focus:ring-green-900"
                                  : "border-gray-300 dark:border-gray-600 focus:ring-blue-200 dark:focus:ring-blue-900"
                        } bg-white dark:bg-gray-800 text-gray-900 dark:text-gray-100`}
                        aria-label="Password"
                        aria-describedby="password-requirements"
                        aria-invalid={Boolean(value && !validation.isValid)}
                    />
                    <button
                        type="button"
                        onClick={() => setShowPassword(!showPassword)}
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200 text-sm font-medium min-h-[44px] min-w-[44px] flex items-center justify-center"
                        aria-label={
                            showPassword ? "Hide password" : "Show password"
                        }
                    >
                        {showPassword ? "Hide" : "Show"}
                    </button>
                </div>
                {/* Real-time password validation feedback */}
                {value && !validation.isValid && (
                    <p
                        className="text-sm text-red-600 dark:text-red-400 mt-2 flex items-center gap-1"
                        role="alert"
                    >
                        <span className="text-lg">✕</span>
                        {validation.error}
                    </p>
                )}
                {value && validation.isValid && (
                    <p className="text-sm text-green-600 dark:text-green-400 mt-2 flex items-center gap-1">
                        <span className="text-lg">✓</span>
                        Password meets all requirements
                    </p>
                )}
            </div>

            {/* Password Strength Indicator */}
            {value && (
                <div className="space-y-2">
                    <div className="flex items-center gap-2">
                        <div className="flex-1 bg-gray-200 dark:bg-gray-700 rounded-full h-2">
                            <div
                                className={`h-2 rounded-full transition-all ${
                                    strength.strength === "weak"
                                        ? "bg-red-500 w-1/4"
                                        : strength.strength === "fair"
                                          ? "bg-orange-500 w-1/2"
                                          : strength.strength === "good"
                                            ? "bg-yellow-500 w-3/4"
                                            : "bg-green-500 w-full"
                                }`}
                            />
                        </div>
                        <span className="text-sm font-medium capitalize text-gray-900 dark:text-gray-100">
                            {strength.strength}
                        </span>
                    </div>
                    <p className="text-sm text-gray-600 dark:text-gray-400">
                        {strength.feedback}
                    </p>
                </div>
            )}

            {/* Password Requirements */}
            <div
                className={`p-4 rounded-lg space-y-2 transition-all ${
                    value && validation.isValid
                        ? "bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800"
                        : value && !validation.isValid
                          ? "bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800"
                          : "bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600"
                }`}
            >
                <p
                    className="text-sm font-medium text-gray-900 dark:text-gray-100"
                    id="password-requirements"
                >
                    Password Requirements:
                </p>
                <ul className="space-y-1 text-sm" role="list">
                    <li
                        className={`transition-colors ${
                            validation.requirements.minLength
                                ? "text-green-600 dark:text-green-400 font-medium"
                                : "text-gray-600 dark:text-gray-400"
                        }`}
                        role="listitem"
                    >
                        {validation.requirements.minLength ? "✓" : "○"} At least
                        8 characters
                    </li>
                    <li
                        className={`transition-colors ${
                            validation.requirements.hasUppercase
                                ? "text-green-600 dark:text-green-400 font-medium"
                                : "text-gray-600 dark:text-gray-400"
                        }`}
                        role="listitem"
                    >
                        {validation.requirements.hasUppercase ? "✓" : "○"} One
                        uppercase letter (A-Z)
                    </li>
                    <li
                        className={`transition-colors ${
                            validation.requirements.hasLowercase
                                ? "text-green-600 dark:text-green-400 font-medium"
                                : "text-gray-600 dark:text-gray-400"
                        }`}
                        role="listitem"
                    >
                        {validation.requirements.hasLowercase ? "✓" : "○"} One
                        lowercase letter (a-z)
                    </li>
                    <li
                        className={`transition-colors ${
                            validation.requirements.hasNumber
                                ? "text-green-600 dark:text-green-400 font-medium"
                                : "text-gray-600 dark:text-gray-400"
                        }`}
                        role="listitem"
                    >
                        {validation.requirements.hasNumber ? "✓" : "○"} One
                        number (0-9)
                    </li>
                    <li
                        className={`transition-colors ${
                            validation.requirements.hasSpecial
                                ? "text-green-600 dark:text-green-400 font-medium"
                                : "text-gray-600 dark:text-gray-400"
                        }`}
                        role="listitem"
                    >
                        {validation.requirements.hasSpecial ? "✓" : "○"} One
                        special character (!@#$%^&*)
                    </li>
                </ul>
            </div>

            {/* Confirm Password Input */}
            <div>
                <label
                    htmlFor="confirm"
                    className="block text-sm sm:text-base font-medium text-gray-100 dark:text-gray-100 mb-2"
                >
                    Confirm Password
                </label>
                <div className="relative">
                    <input
                        id="confirm"
                        type={showConfirm ? "text" : "password"}
                        value={confirmValue}
                        onChange={e => onConfirmChange(e.target.value)}
                        disabled={disabled}
                        placeholder="Confirm your password"
                        className={`w-full px-4 py-3 sm:py-2 text-base sm:text-sm border rounded-lg focus:outline-none focus:ring-2 transition-all min-h-[44px] sm:min-h-auto ${
                            confirmValue && !passwordsMatch
                                ? "border-red-500 focus:ring-red-200 dark:border-red-400 dark:focus:ring-red-900"
                                : confirmValue &&
                                    passwordsMatch &&
                                    validation.isValid
                                  ? "border-green-500 focus:ring-green-200 dark:border-green-400 dark:focus:ring-green-900"
                                  : "border-gray-300 dark:border-gray-600 focus:ring-blue-200 dark:focus:ring-blue-900"
                        } bg-white dark:bg-gray-800 text-gray-900 dark:text-gray-100`}
                        aria-label="Confirm password"
                        aria-invalid={Boolean(confirmValue && !passwordsMatch)}
                    />
                    <button
                        type="button"
                        onClick={() => setShowConfirm(!showConfirm)}
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200 text-sm font-medium min-h-[44px] min-w-[44px] flex items-center justify-center"
                        aria-label={
                            showConfirm ? "Hide password" : "Show password"
                        }
                    >
                        {showConfirm ? "Hide" : "Show"}
                    </button>
                </div>
                {/* Real-time confirm password feedback */}
                {confirmValue && !passwordsMatch && (
                    <p
                        className="text-sm text-red-600 dark:text-red-400 mt-2 flex items-center gap-1"
                        role="alert"
                    >
                        <span className="text-lg">✕</span>
                        Passwords do not match
                    </p>
                )}
                {confirmValue && passwordsMatch && validation.isValid && (
                    <p className="text-sm text-green-600 dark:text-green-400 mt-2 flex items-center gap-1">
                        <span className="text-lg">✓</span>
                        Passwords match
                    </p>
                )}
            </div>
        </div>
    )
}

"use client"

import { Button } from "@/components/ui/button"
import {
    Card,
    CardContent,
    CardDescription,
    CardHeader,
    CardTitle,
} from "@/components/ui/card"
import { DynamicIcon } from "@/components/ui/dynamic-icon"
import { logger } from "@/lib/logger"
import { useTranslations } from "next-intl"
import React, { useState } from "react"
import { SocialChannel } from "./SettingsContainer"

/**
 * ChannelsSectionProps
 */
export interface ChannelsSectionProps {
    channels: SocialChannel[]
    onDisconnect: (channelId: string) => void
    onConnect: () => void
}

/**
 * ChannelsSection Component
 * Manage connected social channels
 * List connected social channels
 * Disconnect button for each channel
 * Add Channel button
 * Connection status display
 *
 * Features:
 * - Display connected channels
 * - Show connection status
 * - Disconnect channels
 * - Add new channels
 * - Confirmation dialogs
 */
export const ChannelsSection: React.FC<ChannelsSectionProps> = ({
    channels,
    onDisconnect,
    onConnect,
}) => {
    const t = useTranslations("dashboard")
    const [disconnectingId, setDisconnectingId] = useState<string | null>(null)
    const [confirmDisconnect, setConfirmDisconnect] = useState<string | null>(
        null
    )
    const [connectingPlatform, setConnectingPlatform] = useState<string | null>(
        null
    )

    /**
     * Handle disconnect click
     */
    const handleDisconnectClick = (channelId: string) => {
        setConfirmDisconnect(channelId)
    }

    /**
     * Confirm disconnect
     */
    const handleConfirmDisconnect = async (channelId: string) => {
        try {
            setDisconnectingId(channelId)
            onDisconnect(channelId)
            setConfirmDisconnect(null)
        } finally {
            setDisconnectingId(null)
        }
    }

    /**
     * Handle OAuth connect for any platform
     */
    const handlePlatformConnect = async (platform: string) => {
        if (connectingPlatform) return
        setConnectingPlatform(platform)
        try {
            const response = await fetch(`/api/oauth/authorize/${platform}`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
            })
            if (!response.ok) {
                const data = await response.json()
                throw new Error(
                    data.message || `Failed to start ${platform} linking`
                )
            }
            const data = await response.json()
            if (data.authorizationUrl) {
                window.location.href = data.authorizationUrl
            } else {
                throw new Error("No authorization URL returned")
            }
        } catch (err) {
            logger.error(`Failed to connect ${platform}`, { error: err })
            setConnectingPlatform(null)
        }
    }

    /**
     * Handle platform disconnect via OAuth revoke API
     */
    const handlePlatformDisconnect = async (
        channelId: string,
        platform: string
    ) => {
        try {
            setDisconnectingId(channelId)
            const response = await fetch(`/api/oauth/disconnect/${platform}`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({}),
            })
            if (!response.ok) {
                const data = await response.json()
                throw new Error(
                    data.message || `Failed to disconnect ${platform}`
                )
            }
            onDisconnect(channelId)
            setConfirmDisconnect(null)
        } catch (err) {
            logger.error(`Failed to disconnect ${platform}`, { error: err })
        } finally {
            setDisconnectingId(null)
        }
    }

    /**
     * Get platform icon name
     */
    const getPlatformIcon = (platform: string): string => {
        const iconMap: Record<string, string> = {
            facebook: "facebook",
            instagram: "instagram",
            twitter: "twitter",
            tiktok: "tiktok",
            linkedin: "linkedin",
            youtube: "Youtube",
            kick: "kick",
        }
        return iconMap[platform] || "link"
    }

    /**
     * Get platform display name
     */
    const getPlatformName = (platform: string): string => {
        const nameMap: Record<string, string> = {
            facebook: "Facebook",
            instagram: "Instagram",
            twitter: "Twitter/X",
            tiktok: "TikTok",
            linkedin: "LinkedIn",
            youtube: "YouTube",
        }
        return nameMap[platform] || platform
    }

    const connectedChannels = channels.filter(c => c.isConnected)
    const disconnectedChannels = channels.filter(c => !c.isConnected)
    const youtubeChannel = channels.find(c => c.platform === "youtube")
    const nonYoutubeConnected = connectedChannels.filter(
        c => c.platform !== "youtube"
    )
    const nonYoutubeDisconnected = disconnectedChannels.filter(
        c => c.platform !== "youtube"
    )

    return (
        <Card>
            <CardHeader>
                <CardTitle>YouTube</CardTitle>
                <CardDescription>{t("youtube.connectYouTube")}</CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
                {/* YouTube Connect Card */}
                <div className="rounded-lg border border-gray-200 p-4">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <DynamicIcon name="Youtube" size={32} />
                            <div>
                                <p className="font-medium text-gray-900">
                                    YouTube
                                </p>
                                {youtubeChannel?.isConnected ? (
                                    <>
                                        <p className="text-sm text-gray-600">
                                            {youtubeChannel.accountName}
                                        </p>
                                        {youtubeChannel.connectedAt && (
                                            <p className="text-xs text-gray-500">
                                                {t("youtube.connectedSince")}{" "}
                                                {new Date(
                                                    youtubeChannel.connectedAt
                                                ).toLocaleDateString()}
                                            </p>
                                        )}
                                    </>
                                ) : (
                                    <p className="text-sm text-gray-500">
                                        {t("youtube.noChannel")}
                                    </p>
                                )}
                            </div>
                        </div>
                        {youtubeChannel?.isConnected ? (
                            <div className="flex items-center gap-2">
                                <span className="inline-flex items-center rounded-full bg-green-100 px-3 py-1 text-xs font-medium text-green-800">
                                    {t("youtube.connected")}
                                </span>
                                {confirmDisconnect === youtubeChannel.id ? (
                                    <div className="flex gap-2">
                                        <Button
                                            size="sm"
                                            variant="outline"
                                            onClick={() =>
                                                setConfirmDisconnect(null)
                                            }
                                        >
                                            {t("youtube.cancel")}
                                        </Button>
                                        <Button
                                            size="sm"
                                            variant="outline"
                                            className="text-red-600 hover:bg-red-50"
                                            onClick={() =>
                                                handlePlatformDisconnect(
                                                    youtubeChannel.id,
                                                    "youtube"
                                                )
                                            }
                                            disabled={
                                                disconnectingId ===
                                                youtubeChannel.id
                                            }
                                        >
                                            {disconnectingId ===
                                            youtubeChannel.id
                                                ? t("youtube.disconnecting")
                                                : t(
                                                      "youtube.confirmDisconnect"
                                                  )}
                                        </Button>
                                    </div>
                                ) : (
                                    <Button
                                        size="sm"
                                        variant="outline"
                                        className="text-red-600 hover:bg-red-50"
                                        onClick={() =>
                                            handleDisconnectClick(
                                                youtubeChannel.id
                                            )
                                        }
                                    >
                                        {t("youtube.disconnect")}
                                    </Button>
                                )}
                            </div>
                        ) : (
                            <Button
                                size="sm"
                                onClick={() => handlePlatformConnect("youtube")}
                                disabled={connectingPlatform === "youtube"}
                                className="bg-red-600 text-white hover:bg-red-700"
                            >
                                {connectingPlatform === "youtube"
                                    ? t("youtube.connecting")
                                    : t("youtube.connect")}
                            </Button>
                        )}
                    </div>
                </div>

                {/* Other Connected Channels */}
                {nonYoutubeConnected.length > 0 && (
                    <div className="space-y-4">
                        <h3 className="text-sm font-semibold text-gray-900">
                            {t("youtube.connected")} (
                            {nonYoutubeConnected.length})
                        </h3>
                        <div className="space-y-3">
                            {nonYoutubeConnected.map(channel => (
                                <div
                                    key={channel.id}
                                    className="flex items-center justify-between rounded-lg border border-gray-200 p-4"
                                >
                                    <div className="flex items-center gap-3">
                                        <DynamicIcon
                                            name={
                                                getPlatformIcon(
                                                    channel.platform
                                                ) as import("@/lib/icons").IconName
                                            }
                                            size={24}
                                        />
                                        <div>
                                            <p className="font-medium text-gray-900">
                                                {getPlatformName(
                                                    channel.platform
                                                )}
                                            </p>
                                            <p className="text-sm text-gray-600">
                                                {channel.accountName}
                                            </p>
                                            {channel.connectedAt && (
                                                <p className="text-xs text-gray-500">
                                                    {t(
                                                        "youtube.connectedSince"
                                                    )}{" "}
                                                    {new Date(
                                                        channel.connectedAt
                                                    ).toLocaleDateString()}
                                                </p>
                                            )}
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <span className="inline-flex items-center rounded-full bg-green-100 px-3 py-1 text-xs font-medium text-green-800">
                                            {t("youtube.connected")}
                                        </span>
                                        {confirmDisconnect === channel.id ? (
                                            <div className="flex gap-2">
                                                <Button
                                                    size="sm"
                                                    variant="outline"
                                                    onClick={() =>
                                                        setConfirmDisconnect(
                                                            null
                                                        )
                                                    }
                                                >
                                                    {t("youtube.cancel")}
                                                </Button>
                                                <Button
                                                    size="sm"
                                                    variant="outline"
                                                    className="text-red-600 hover:bg-red-50"
                                                    onClick={() =>
                                                        handlePlatformDisconnect(
                                                            channel.id,
                                                            channel.platform
                                                        )
                                                    }
                                                    disabled={
                                                        disconnectingId ===
                                                        channel.id
                                                    }
                                                >
                                                    {disconnectingId ===
                                                    channel.id
                                                        ? t(
                                                              "youtube.disconnecting"
                                                          )
                                                        : t(
                                                              "youtube.confirmDisconnect"
                                                          )}
                                                </Button>
                                            </div>
                                        ) : (
                                            <Button
                                                size="sm"
                                                variant="outline"
                                                className="text-red-600 hover:bg-red-50"
                                                onClick={() =>
                                                    handleDisconnectClick(
                                                        channel.id
                                                    )
                                                }
                                            >
                                                {t("youtube.disconnect")}
                                            </Button>
                                        )}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Other Available Channels */}
                {nonYoutubeDisconnected.length > 0 && (
                    <div className="space-y-4">
                        <h3 className="text-sm font-semibold text-gray-900">
                            {t("youtube.notConnected")} (
                            {nonYoutubeDisconnected.length})
                        </h3>
                        <div className="space-y-3">
                            {nonYoutubeDisconnected.map(channel => (
                                <div
                                    key={channel.id}
                                    className="flex items-center justify-between rounded-lg border border-gray-200 p-4"
                                >
                                    <div className="flex items-center gap-3">
                                        <DynamicIcon
                                            name={
                                                getPlatformIcon(
                                                    channel.platform
                                                ) as import("@/lib/icons").IconName
                                            }
                                            size={24}
                                        />
                                        <div>
                                            <p className="font-medium text-gray-900">
                                                {getPlatformName(
                                                    channel.platform
                                                )}
                                            </p>
                                            <p className="text-sm text-gray-600">
                                                {t("youtube.notConnected")}
                                            </p>
                                        </div>
                                    </div>
                                    <Button
                                        size="sm"
                                        onClick={() =>
                                            handlePlatformConnect(
                                                channel.platform
                                            )
                                        }
                                        disabled={
                                            connectingPlatform ===
                                            channel.platform
                                        }
                                    >
                                        {connectingPlatform === channel.platform
                                            ? t("youtube.connecting")
                                            : t("youtube.connect")}
                                    </Button>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </CardContent>
        </Card>
    )
}

export default ChannelsSection

