        useLocalEnvs()
    const [expanded, setExpanded] = useState<string | null>(null)

    const hasAnyLocal =
        definedServices.some(s => s.mode !== "cloud_only") ||
        definedServices.some(s => s.envs.length > 0)

    return (
        <Card>
