/**
 * Audit Logger for Secure Login Implementation
 * Logs all authentication events including login attempts, CSRF failures, rate limiting, and Remember Me operations
 * Implements 90+ day retention policy for compliance
 */

import { db } from "@/lib/db"
import { logger } from "@/lib/logger"

const { query, queryOne, queryMany } = db

export type AuditEventType =
    | "LOGIN_ATTEMPT"
    | "LOGIN_SUCCESS"
    | "LOGIN_FAILED"
    | "CSRF_FAILURE"
    | "RATE_LIMIT_EXCEEDED"
    | "REMEMBER_ME_CREATED"
    | "REMEMBER_ME_VALIDATED"
    | "REMEMBER_ME_FAILED"

export interface AuditLogEntry {
    id: string
    eventType: AuditEventType
    userId?: string
    email?: string
    ipAddress?: string
    userAgent?: string
    details?: Record<string, unknown>
    createdAt: Date
}

export interface ExportedAuditLog {
    id: string
    eventType: string
    userId?: string
    email?: string
    ipAddress?: string
    userAgent?: string
    details?: string
    createdAt: string
}

/**
 * Log a login attempt (both successful and failed)
 * Validates: Requirements 6.1
 */
export async function logLoginAttempt(
    email: string,
    ipAddress: string,
    userAgent: string,
    success: boolean,
    reason?: string,
    userId?: string
): Promise<void> {
    try {
        const eventType = success ? "LOGIN_SUCCESS" : "LOGIN_FAILED"
        const details = {
            action: success ? "User logged in successfully" : "Login failed",
            success,
            ...(reason && { reason }),
            timestamp: new Date().toISOString(),
        }

        await query(
            `INSERT INTO audit_logs (event_type, user_id, email, ip_address, user_agent, details, timestamp)
             VALUES ($1, $2, $3, $4, $5, $6, CURRENT_TIMESTAMP)`,
            [
                eventType,
                userId || null,
                email,
                ipAddress,
                userAgent,
                JSON.stringify(details),
            ]
        )

        logger.debug(`Login attempt logged: ${eventType}`, {
            context: "AuditLogger",
            data: { email, success },
        })
    } catch (err) {
        logger.error("Failed to log login attempt", {
            context: "AuditLogger",
            error: err as Error,
            data: { email },
        })
        // Don't throw - audit logging should not break the main flow
    }
}

