}

/**
 * Authentication Service
 * Main controller orchestrating all password security components
 */
export class AuthenticationService {
    private supabase: SupabaseClient<any>
    private rateLimiter: RateLimiter
    private config: ReturnType<typeof getSecurityConfig>
    private repository: AuthRepository
    private auditService: AuthAuditService

    constructor() {
        // Initialize Supabase client
        const url = process.env.NEXT_PUBLIC_SUPABASE_URL
        const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY

        if (!url || !serviceKey) {
            throw new Error(
                "Missing Supabase configuration. " +
                    "Ensure NEXT_PUBLIC_SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY are set."
            )
        }

        this.supabase = createClient<any>(url, serviceKey, {
            auth: {
                autoRefreshToken: false,
                persistSession: false,
            },
        })

        // Initialize configuration
        this.config = getSecurityConfig()

        // Initialize rate limiter with configuration
        this.rateLimiter = getRateLimiter(this.config.rateLimiting)

        // Initialize repository and audit service
        this.repository = new AuthRepository(this.supabase)
        this.auditService = new AuthAuditService(this.supabase)
    }

    /**
     * Register a new user with email and password
     */
    async register(
        request: RegistrationRequest
    ): Promise<AuthenticationResult> {
        const operationStartTime = Date.now()
        try {
            // ================================================================
            // STEP 1: VALIDATE CAPTCHA
            // ================================================================

            if (!request.captchaToken) {
                logger.warn("Registration attempt without CAPTCHA token", {
                    email: request.email,
                })
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "CAPTCHA verification required",
                        errorCode: "CAPTCHA_REQUIRED",
                        statusCode: 400,
                    },
                    operationStartTime
                )
            }

            const captchaResult = await verifyCAPTCHAWithFallback(
                request.captchaToken
            )

            if (!captchaResult.success) {
                logger.warn("CAPTCHA verification failed during registration", {
                    email: request.email,
                    reason: captchaResult.failureReason,
                    degradedMode: captchaResult.degradedMode,
                })
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "Registration failed",
                        errorCode: "REGISTRATION_FAILED",
                        statusCode: 400,
                        degradedMode: captchaResult.degradedMode,
                    },
                    operationStartTime
                )
            }

            // ================================================================
            // STEP 2: VALIDATE INPUT
            // ================================================================

            if (!request.email || typeof request.email !== "string") {
                logger.warn("Invalid email in registration request", {
                    email: request.email,
                })
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "Invalid email format",
                        errorCode: "INVALID_EMAIL",
                        statusCode: 400,
                    },
                    operationStartTime
                )
            }

            try {
                validatePasswordInput(request.password)
            } catch (error) {
                logger.warn("Invalid password in registration request", {
                    email: request.email,
                    error:
                        error instanceof Error ? error.message : String(error),
                })
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "Invalid password format",
                        errorCode: "INVALID_PASSWORD",
                        statusCode: 400,
                    },
                    operationStartTime
                )
            }

            // ================================================================
            // STEP 3: CHECK IF EMAIL EXISTS
            // ================================================================

            let emailExists = false
            try {
                emailExists = await this.repository.userExistsByEmail(
                    request.email
                )
            } catch (error) {
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "Registration failed",
                        errorCode: "DATABASE_ERROR",
                        statusCode: 500,
                    },
                    operationStartTime
                )
            }

            if (emailExists) {
                logger.warn("Registration attempt with existing email", {
                    email: request.email,
                })
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "Registration failed",
                        errorCode: "REGISTRATION_FAILED",
                        statusCode: 409,
                    },
                    operationStartTime
                )
            }

            // ================================================================
            // STEP 4: HASH PASSWORD WITH ARGON2ID
            // ================================================================

            let hashResult: any
            try {
                hashResult = await hashPasswordArgon2id(request.password)
                if (hashResult.performanceWarning) {
                    logger.warn("Password hashing performance warning", {
                        email: request.email,
                        timeTakenMs: hashResult.timeTakenMs,
                    })
                }
            } catch (error) {
                logger.error("Password hashing error during registration", {
                    email: request.email,
                    error:
                        error instanceof Error ? error.message : String(error),
                })
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "Registration failed",
                        errorCode: "HASHING_ERROR",
                        statusCode: 500,
                    },
                    operationStartTime
                )
            }

            // ================================================================
            // STEP 5: CREATE USER RECORD
            // ================================================================

            let newUser: any
            try {
                newUser = await this.repository.createUser({
                    email: request.email,
                    passwordHash: hashResult.hash,
                    passwordAlgorithm: hashResult.algorithm,
                })
            } catch (error) {
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "Registration failed",
                        errorCode: "DATABASE_ERROR",
                        statusCode: 500,
                    },
                    operationStartTime
                )
            }

            // ================================================================
            // STEP 6: LOG REGISTRATION EVENT
            // ================================================================

            await this.auditService.logRegistration({
                email: request.email,
                userId: newUser.id,
                algorithm: hashResult.algorithm,
                hashTimeTakenMs: hashResult.timeTakenMs,
            })

            // ================================================================
            // STEP 7: RETURN SUCCESS & NORMALIZE
            // ================================================================

            logger.info("User registered successfully", {
                userId: newUser.id,
                email: request.email,
            })

            return this.normalizeAndReturn(
                {
                    success: true,
                    userId: newUser.id,
                    email: newUser.email,
                    statusCode: 201,
                },
                operationStartTime
            )
        } catch (error) {
            logger.error("Unexpected error during registration", {
                error: error instanceof Error ? error.message : String(error),
            })
            return this.normalizeAndReturn(
                {
                    success: false,
                    error: "Registration failed",
                    errorCode: "INTERNAL_ERROR",
                    statusCode: 500,
                },
                operationStartTime
            )
        }
    }

    /**
     * Authenticate user with email and password
     */
    async login(request: LoginRequest): Promise<AuthenticationResult> {
        const operationStartTime = Date.now()
        try {
            // ================================================================
            // STEP 1: VALIDATE CAPTCHA
            // ================================================================

            let degradedMode = false

            if (!request.captchaToken) {
                logger.warn("Login attempt without CAPTCHA token", {
                    email: request.email,
                })
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "CAPTCHA verification required",
                        errorCode: "CAPTCHA_REQUIRED",
                        statusCode: 400,
                    },
                    operationStartTime
                )
            }

            const captchaResult = await verifyCAPTCHAWithFallback(
                request.captchaToken
            )

            if (!captchaResult.success) {
                logger.warn("CAPTCHA verification failed during login", {
                    email: request.email,
                    reason: captchaResult.failureReason,
                    degradedMode: captchaResult.degradedMode,
                })

                if (captchaResult.degradedMode) {
                    degradedMode = true
                } else {
                    return this.normalizeAndReturn(
                        {
                            success: false,
                            error: "Authentication failed",
                            errorCode: "AUTH_FAILED",
                            statusCode: 401,
                        },
                        operationStartTime
                    )
                }
            }

            // ================================================================
            // STEP 2: CHECK RATE LIMITS
            // ================================================================

            const rateLimitCheck =
                await this.rateLimiter.checkAndUpdateRateLimit(request.email)

            if (!rateLimitCheck.allowed) {
                logger.warn("Login attempt on rate-limited account", {
                    email: request.email,
                    isLocked: rateLimitCheck.isLocked,
                    lockedUntil: rateLimitCheck.lockedUntil?.toISOString(),
                })

                await this.auditService.logRateLimitExceeded({
                    email: request.email,
                    degradedMode,
                })

                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "Too many login attempts. Please try again later.",
                        errorCode: "TOO_MANY_ATTEMPTS",
                        statusCode: 429,
                        isLocked: true,
                        unlockTimeSeconds: rateLimitCheck.lockedUntil
                            ? Math.ceil(
                                  (rateLimitCheck.lockedUntil.getTime() -
                                      Date.now()) /
                                      1000
                              )
                            : undefined,
                    },
                    operationStartTime
                )
            }

            // ================================================================
            // STEP 3: VALIDATE INPUT
            // ================================================================

            if (!request.email || typeof request.email !== "string") {
                logger.warn("Invalid email in login request", {
                    email: request.email,
                })
                await this.rateLimiter.recordFailure(request.email)
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "Authentication failed",
                        errorCode: "AUTH_FAILED",
                        statusCode: 401,
                    },
                    operationStartTime
                )
            }

            try {
                validatePasswordInput(request.password)
            } catch (error) {
                logger.warn("Invalid password in login request", {
                    email: request.email,
                    error:
                        error instanceof Error ? error.message : String(error),
                })
                await this.rateLimiter.recordFailure(request.email)
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "Authentication failed",
                        errorCode: "AUTH_FAILED",
                        statusCode: 401,
                    },
                    operationStartTime
                )
            }

            // ================================================================
            // STEP 4: LOOK UP USER
            // ================================================================

            let user: any
            try {
                user = await this.repository.findUserByEmail(request.email)
                if (!user) {
                    logger.warn("User not found during login", {
                        email: request.email,
                    })
                    await this.rateLimiter.recordFailure(request.email)
                    return this.normalizeAndReturn(
                        {
                            success: false,
                            error: "Authentication failed",
                            errorCode: "AUTH_FAILED",
                            statusCode: 401,
                        },
                        operationStartTime
                    )
                }
            } catch (error) {
                await this.rateLimiter.recordFailure(request.email)
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "Authentication failed",
                        errorCode: "AUTH_FAILED",
                        statusCode: 401,
                    },
                    operationStartTime
                )
            }

            // ================================================================
            // STEP 5: VALIDATE PASSWORD
            // ================================================================

            let validationResult: any
            try {
                validationResult = await validatePassword(
                    request.password,
                    user.password_hash
                )
            } catch (error) {
                logger.error("Password validation error", {
                    email: request.email,
                    error:
                        error instanceof Error ? error.message : String(error),
                })
                await this.rateLimiter.recordFailure(request.email)
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "Authentication failed",
                        errorCode: "AUTH_FAILED",
                        statusCode: 401,
                    },
                    operationStartTime
                )
            }

            if (!validationResult.valid) {
                logger.warn("Invalid password during login", {
                    email: request.email,
                    algorithmType: validationResult.algorithmType,
                })
                await this.rateLimiter.recordFailure(request.email)
                return this.normalizeAndReturn(
                    {
                        success: false,
                        error: "Authentication failed",
                        errorCode: "AUTH_FAILED",
                        statusCode: 401,
                    },
                    operationStartTime
                )
            }

            // ================================================================
            // STEP 6: RESET RATE LIMIT COUNTER
            // ================================================================

            try {
                await this.rateLimiter.recordSuccess(request.email)
            } catch (error) {
                logger.error("Failed to reset rate limit counter", {
                    email: request.email,
                    error:
                        error instanceof Error ? error.message : String(error),
                })
            }

            // ================================================================
            // STEP 7: LOG AUTHENTICATION EVENT
            // ================================================================

            await this.auditService.logAuthSuccess({
                email: request.email,
                userId: user.id,
                algorithm: validationResult.algorithmType,
                degradedMode,
            })

            // ================================================================
            // STEP 8: RETURN SUCCESS & NORMALIZE
            // ================================================================

            logger.info("User authenticated successfully", {
                userId: user.id,
                email: request.email,
                algorithmType: validationResult.algorithmType,
            })

            return this.normalizeAndReturn(
                {
                    success: true,
                    userId: user.id,
                    email: user.email,
                    statusCode: 200,
                    degradedMode,
                },
                operationStartTime
            )
        } catch (error) {
            logger.error("Unexpected error during login", {
                error: error instanceof Error ? error.message : String(error),
            })
            return this.normalizeAndReturn(
                {
                    success: false,
                    error: "Authentication failed",
                    errorCode: "INTERNAL_ERROR",
                    statusCode: 500,
                },
                operationStartTime
            )
        }
    }

    private async normalizeAndReturn(
        result: AuthenticationResult,
        operationStartTime: number,
        targetResponseTimeMs: number = 500
    ): Promise<AuthenticationResult> {
        try {
            const operationTimeMs = Date.now() - operationStartTime
            await normalizeResponseTime(operationTimeMs, targetResponseTimeMs)
        } catch (error) {
            logger.debug("Response time normalization error", {
                error: error instanceof Error ? error.message : String(error),
            })
        }
        return result
    }

    getRateLimiter(): RateLimiter {
        return this.rateLimiter
    }

    getSecurityConfig() {
        return this.config
    }
}

let authServiceInstance: AuthenticationService | null = null

export function getAuthenticationService(): AuthenticationService {
    if (!authServiceInstance) {
        authServiceInstance = new AuthenticationService()
    }
    return authServiceInstance
}

/**
 * Module: Rate Limiter Service with Supabase Backing
 * Purpose: Implement brute-force protection using persistent Supabase storage
 *
 * This module handles:
 * - Checking if an account is locked (locked_until > now)
 * - Recording failures and incrementing failed_attempts
 * - Recording successes and resetting the counter
 * - Using Supabase for persistent state (not in-memory)
 * - Automatic unlock after lockout period expires
 *
 * Requirements covered:
 * - Requirement 7: Brute Force Protection with Rate Limiting (7.1-7.7)
 * - Requirement 15: Performance and Resource Management (15.4)
 *
 * Design notes:
 * - Uses Supabase for persistence (serverless-compatible)
 * - Tracks by email (user identifier)
 * - Automatic unlock after 15 minutes
 * - Resets counter on successful authentication
 * - Logs all rate limit events for audit trail
 */

import { createLogger } from "@/lib/logger"
import { createClient, type SupabaseClient } from "@supabase/supabase-js"
import type { RateLimitingConfig } from "./types"

const logger = createLogger("RateLimiter")

/**
 * Rate limit record from database
 */
interface RateLimitRecord {
    id: string
    email: string
    failed_attempts: number
    last_attempt: string
    locked_until: string | null
    created_at: string
    updated_at: string
}

/**
 * Result of rate limit check
 */
export interface RateLimitCheckResult {
    allowed: boolean
    remainingAttempts: number
    lockedUntil?: Date
    isLocked: boolean
}

/**
 * RateLimiter Service
 *
 * Manages authentication attempt rate limiting using Supabase for persistent storage.
 * Implements account lockout after configurable number of failures within a time window.
 *
 * Usage:
 *   const limiter = new RateLimiter(config)
 *   const result = await limiter.checkAndUpdateRateLimit(email)
 *   if (!result.allowed) {
 *     return { status: 429, error: 'Too many attempts' }
 *   }
 *   // Attempt authentication...
 *   if (success) {
 *     await limiter.recordSuccess(email)
 *   } else {
 *     await limiter.recordFailure(email)
 *   }
 */
export class RateLimiter {
    private supabase: SupabaseClient<any>
    private config: RateLimitingConfig

    constructor(config: RateLimitingConfig) {
        this.config = config

        // Create Supabase client with service role key for privileged operations
        const url = process.env.NEXT_PUBLIC_SUPABASE_URL
        const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY

        if (!url || !serviceKey) {
            throw new Error(
                "Missing Supabase configuration. " +
                    "Ensure NEXT_PUBLIC_SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY are set."
            )
        }

        this.supabase = createClient<any>(url, serviceKey, {
            auth: {
                autoRefreshToken: false,
                persistSession: false,
            },
        })
    }

    /**
     * Check if an account is locked and update rate limit state
     *
     * This function:
     * 1. Fetches the current rate limit record for the email
     * 2. Checks if the account is locked (locked_until > now)
     * 3. If locked, returns locked status
     * 4. If not locked but window expired, resets the counter
     * 5. Returns whether the request is allowed
     *
     * @param email User email address
     * @returns Rate limit check result with allowed status and remaining attempts
     */
    async checkAndUpdateRateLimit(
        email: string
    ): Promise<RateLimitCheckResult> {
        try {
            // Fetch current record
            const { data: records, error: fetchError } = await this.supabase
                .from("rate_limit_records")
                .select("*")
                .eq("email", email)
                .single()

            if (fetchError && fetchError.code !== "PGRST116") {
                // PGRST116 = no rows found (expected for new users)
                logger.error("Failed to fetch rate limit record", {
                    email,
                    error: fetchError.message,
                })
                throw fetchError
            }

            const now = new Date()
            let record = records as RateLimitRecord | null

            // No record yet - create one
            if (!record) {
                const { error: insertError } = await this.supabase
                    .from("rate_limit_records")
                    .insert({
                        email,
                        failed_attempts: 0,
                        last_attempt: now.toISOString(),
                        locked_until: null,
                    })

                if (insertError) {
                    logger.error("Failed to create rate limit record", {
                        email,
                        error: insertError.message,
                    })
                    throw insertError
                }

                logger.debug("Rate limit record created", { email })

                return {
                    allowed: true,
                    remainingAttempts: this.config.failureThreshold,
                    isLocked: false,
                }
            }

            // Check if locked
            if (record.locked_until) {
                const lockedUntil = new Date(record.locked_until)
                if (now < lockedUntil) {
                    logger.warn("Account locked due to rate limit", {
                        email,
                        lockedUntil: lockedUntil.toISOString(),
                        failedAttempts: record.failed_attempts,
                    })

                    return {
                        allowed: false,
                        remainingAttempts: 0,
                        lockedUntil,
                        isLocked: true,
                    }
                }

                // Lockout expired, reset
                await this.resetRecord(email)
                return {
                    allowed: true,
                    remainingAttempts: this.config.failureThreshold,
                    isLocked: false,
                }
            }

            // Check if window expired
            const lastAttempt = new Date(record.last_attempt)
            const minutesElapsed =
                (now.getTime() - lastAttempt.getTime()) / (1000 * 60)

            if (minutesElapsed > this.config.windowMinutes) {
                // Window expired, reset counter
                await this.resetRecord(email)
                return {
                    allowed: true,
                    remainingAttempts: this.config.failureThreshold,
                    isLocked: false,
                }
            }

            // Check if at threshold
            if (record.failed_attempts >= this.config.failureThreshold) {
                // Lock the account
                const lockedUntil = new Date(
                    now.getTime() + this.config.lockoutMinutes * 60 * 1000
                )

                const { error: updateError } = await this.supabase
                    .from("rate_limit_records")
                    .update({
                        locked_until: lockedUntil.toISOString(),
                        last_attempt: now.toISOString(),
                    })
                    .eq("email", email)

                if (updateError) {
                    logger.error("Failed to lock account", {
                        email,
                        error: updateError.message,
                    })
                    throw updateError
                }

                logger.warn("Account locked due to rate limit threshold", {
                    email,
                    failedAttempts: record.failed_attempts,
                    lockedUntil: lockedUntil.toISOString(),
                })

                return {
                    allowed: false,
                    remainingAttempts: 0,
                    lockedUntil,
                    isLocked: true,
                }
            }

            // Account is not locked and within window
            const remainingAttempts =
                this.config.failureThreshold - record.failed_attempts

            return {
                allowed: true,
                remainingAttempts,
                isLocked: false,
            }
        } catch (error) {
            logger.error("Error checking rate limit", {
                email,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Record a failed authentication attempt
     *
     * This function:
     * 1. Increments the failed_attempts counter
     * 2. Updates last_attempt timestamp
     * 3. Logs the failure for audit trail
     *
     * @param email User email address
     */
    async recordFailure(email: string): Promise<void> {
        try {
            // Fetch current count
            const { data: records, error: fetchError } = await this.supabase
                .from("rate_limit_records")
                .select("failed_attempts")
                .eq("email", email)
                .single()

            if (fetchError && fetchError.code !== "PGRST116") {
                logger.error("Failed to fetch rate limit record for failure", {
                    email,
                    error: fetchError.message,
                })
                throw fetchError
            }

            const currentCount = records?.failed_attempts || 0
            const newCount = currentCount + 1

            // Update record
            const { error: updateError } = await this.supabase
                .from("rate_limit_records")
                .update({
                    failed_attempts: newCount,
                    last_attempt: new Date().toISOString(),
                })
                .eq("email", email)

            if (updateError) {
                logger.error("Failed to record failure", {
                    email,
                    error: updateError.message,
                })
                throw updateError
            }

            logger.debug("Authentication failure recorded", {
                email,
                attemptCount: newCount,
                threshold: this.config.failureThreshold,
            })

            // Log to audit logs
            await this.logAuthFailure(email, newCount)
        } catch (error) {
            logger.error("Error recording failure", {
                email,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Record a successful authentication attempt
     *
     * This function:
     * 1. Resets the failed_attempts counter to 0
     * 2. Clears the locked_until timestamp
     * 3. Updates last_attempt timestamp
     * 4. Logs the success for audit trail
     *
     * @param email User email address
     */
    async recordSuccess(email: string): Promise<void> {
        try {
            // Reset counter on successful login
            const { error: updateError } = await this.supabase
                .from("rate_limit_records")
                .update({
                    failed_attempts: 0,
                    locked_until: null,
                    last_attempt: new Date().toISOString(),
                })
                .eq("email", email)

            if (updateError) {
                logger.error("Failed to record success", {
                    email,
                    error: updateError.message,
                })
                throw updateError
            }

            logger.debug("Authentication success recorded", { email })

            // Log success
            await this.logAuthSuccess(email)
        } catch (error) {
            logger.error("Error recording success", {
                email,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Reset rate limit record for an email
     *
     * Used when:
     * - Lockout period expires
     * - Time window expires
     * - Admin reset
     *
     * @param email User email address
     */
    private async resetRecord(email: string): Promise<void> {
        try {
            const { error } = await this.supabase
                .from("rate_limit_records")
                .update({
                    failed_attempts: 0,
                    locked_until: null,
                    last_attempt: new Date().toISOString(),
                })
                .eq("email", email)

            if (error) {
                logger.error("Failed to reset rate limit record", {
                    email,
                    error: error.message,
                })
                throw error
            }

            logger.debug("Rate limit record reset", { email })
        } catch (error) {
            logger.error("Error resetting rate limit record", {
                email,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Log authentication failure to audit logs
     *
     * @param email User email address
     * @param attemptCount Current attempt count
     */
    private async logAuthFailure(
        email: string,
        attemptCount: number
    ): Promise<void> {
        try {
            const { error } = await this.supabase.from("audit_logs").insert({
                event_type: "auth_failure",
                email,
                attempt_count: attemptCount,
                timestamp: new Date().toISOString(),
            })

            if (error) {
                logger.error("Failed to log auth failure", {
                    email,
                    error: error.message,
                })
                // Don't throw - logging failure shouldn't break authentication
            }
        } catch (error) {
            logger.error("Error logging auth failure", {
                email,
                error: error instanceof Error ? error.message : String(error),
            })
            // Don't throw - logging failure shouldn't break authentication
        }
    }

    /**
     * Log authentication success to audit logs
     *
     * @param email User email address
     */
    private async logAuthSuccess(email: string): Promise<void> {
        try {
            const { error } = await this.supabase.from("audit_logs").insert({
                event_type: "auth_success",
                email,
                timestamp: new Date().toISOString(),
            })

            if (error) {
                logger.error("Failed to log auth success", {
                    email,
                    error: error.message,
                })
                // Don't throw - logging failure shouldn't break authentication
            }
        } catch (error) {
            logger.error("Error logging auth success", {
                email,
                error: error instanceof Error ? error.message : String(error),
            })
            // Don't throw - logging failure shouldn't break authentication
        }
    }

    /**
     * Get current attempt count for an email
     *
     * @param email User email address
     * @returns Current failed attempt count
     */
    async getAttemptCount(email: string): Promise<number> {
        try {
            const { data: records, error } = await this.supabase
                .from("rate_limit_records")
                .select("failed_attempts")
                .eq("email", email)
                .single()

            if (error && error.code !== "PGRST116") {
                logger.error("Failed to get attempt count", {
                    email,
                    error: error.message,
                })
                throw error
            }

            return records?.failed_attempts || 0
        } catch (error) {
            logger.error("Error getting attempt count", {
                email,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Get remaining attempts before lockout
     *
     * @param email User email address
     * @returns Remaining attempts (0 if locked)
     */
    async getRemainingAttempts(email: string): Promise<number> {
        const count = await this.getAttemptCount(email)
        return Math.max(0, this.config.failureThreshold - count)
    }

    /**
     * Get time until rate limit resets (in seconds)
     *
     * @param email User email address
     * @returns Seconds until reset (0 if not limited)
     */
    async getTimeUntilReset(email: string): Promise<number> {
        try {
            const { data: records, error } = await this.supabase
                .from("rate_limit_records")
                .select("last_attempt, locked_until")
                .eq("email", email)
                .single()

            if (error && error.code !== "PGRST116") {
                logger.error("Failed to get time until reset", {
                    email,
                    error: error.message,
                })
                throw error
            }

            if (!records) {
                return 0
            }

            const now = new Date()

            // If locked, return time until unlock
            if (records.locked_until) {
                const lockedUntil = new Date(records.locked_until)
                if (now < lockedUntil) {
                    const timeRemaining = lockedUntil.getTime() - now.getTime()
                    return Math.ceil(timeRemaining / 1000)
                }
            }

            // Otherwise, return time until window expires
            const lastAttempt = new Date(records.last_attempt)
            const windowExpires = new Date(
                lastAttempt.getTime() + this.config.windowMinutes * 60 * 1000
            )

            if (now < windowExpires) {
                const timeRemaining = windowExpires.getTime() - now.getTime()
                return Math.ceil(timeRemaining / 1000)
            }

            return 0
        } catch (error) {
            logger.error("Error getting time until reset", {
                email,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Get time remaining until account unlock (in seconds)
     *
     * This helper function calculates how many seconds remain until a locked account
     * is automatically unlocked. Returns 0 if the account is not locked.
     *
     * Usage:
     *   const secondsRemaining = await limiter.getUnlockTimeRemaining(email)
     *   if (secondsRemaining > 0) {
     *     console.log(`Account locked for ${secondsRemaining} more seconds`)
     *   }
     *
     * @param email User email address
     * @returns Seconds until unlock (0 if not locked)
     */
    async getUnlockTimeRemaining(email: string): Promise<number> {
        try {
            const { data: records, error } = await this.supabase
                .from("rate_limit_records")
                .select("locked_until")
                .eq("email", email)
                .single()

            if (error && error.code !== "PGRST116") {
                logger.error("Failed to get unlock time remaining", {
                    email,
                    error: error.message,
                })
                throw error
            }

            if (!records || !records.locked_until) {
                return 0
            }

            const now = new Date()
            const lockedUntil = new Date(records.locked_until)

            if (now >= lockedUntil) {
                // Account should be unlocked
                return 0
            }

            const timeRemaining = lockedUntil.getTime() - now.getTime()
            return Math.ceil(timeRemaining / 1000)
        } catch (error) {
            logger.error("Error getting unlock time remaining", {
                email,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Manually unlock an account and reset failure counter
     *
     * This helper function immediately unlocks a locked account and resets the
     * failure counter to 0. This is useful for admin operations or when an account
     * needs to be unlocked before the automatic 15-minute timeout.
     *
     * Usage:
     *   await limiter.unlockAccount(email)
     *   // Account is now unlocked and can attempt login again
     *
     * @param email User email address
     */
    async unlockAccount(email: string): Promise<void> {
        try {
            const { error } = await this.supabase
                .from("rate_limit_records")
                .update({
                    failed_attempts: 0,
                    locked_until: null,
                    last_attempt: new Date().toISOString(),
                })
                .eq("email", email)

            if (error) {
                logger.error("Failed to unlock account", {
                    email,
                    error: error.message,
                })
                throw error
            }

            logger.info("Account manually unlocked", { email })
        } catch (error) {
            logger.error("Error unlocking account", {
                email,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Clear all rate limit records (for testing/admin purposes)
     *
     * WARNING: This deletes all rate limit data. Use with caution.
     */
    async clearAllRecords(): Promise<void> {
        try {
            const { error } = await this.supabase
                .from("rate_limit_records")
                .delete()
                .neq("id", "00000000-0000-0000-0000-000000000000") // Delete all

            if (error) {
                logger.error("Failed to clear all rate limit records", {
                    error: error.message,
                })
                throw error
            }

            logger.warn("All rate limit records cleared")
        } catch (error) {
            logger.error("Error clearing all rate limit records", {
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }
}

/**
 * Create a singleton instance of RateLimiter
 *
 * Usage:
 *   const limiter = getRateLimiter()
 *   const result = await limiter.checkAndUpdateRateLimit(email)
 */
let rateLimiterInstance: RateLimiter | null = null

export function getRateLimiter(config?: RateLimitingConfig): RateLimiter {
    if (!rateLimiterInstance) {
        if (!config) {
            throw new Error(
                "RateLimiter not initialized. Call getRateLimiter(config) first."
            )
        }
        rateLimiterInstance = new RateLimiter(config)
    }
    return rateLimiterInstance
}

/**
 * Performance Optimization Utilities for Login System
 * Provides performance monitoring, optimization strategies, and metrics
 *
 * Validates: Requirements 15.1, 15.2, 15.3, 15.4, 15.5, 15.6, 15.7, 15.8
 */

import { createLogger } from "@/lib/logger"

const logger = createLogger("Performance")

/**
 * Performance metrics for monitoring
 */
export interface PerformanceMetrics {
    endpoint: string
    method: string
    duration: number
    timestamp: Date
    statusCode: number
    cached: boolean
    dbQueryTime?: number
    passwordHashTime?: number
    rateLimitTime?: number
    sessionTime?: number
}

/**
 * Performance thresholds (in milliseconds)
 */
export const PERFORMANCE_THRESHOLDS = {
    LOGIN_ENDPOINT: 500, // 500ms for complete login
    CSRF_VALIDATION: 50, // 50ms for CSRF validation
    RATE_LIMITING: 50, // 50ms for rate limiting check
    PASSWORD_HASHING: 250, // 250ms for Argon2id verify/hash
    DATABASE_QUERY: 100, // 100ms for database queries
    SESSION_STORAGE: 50, // 50ms for session storage
}

/**
 * In-memory metrics store for performance monitoring
 */
const metricsStore: PerformanceMetrics[] = []
const MAX_METRICS_STORED = 1000

/**
 * Record performance metric
 */
export function recordMetric(metric: PerformanceMetrics): void {
    metricsStore.push(metric)

    // Keep only recent metrics to avoid memory bloat
    if (metricsStore.length > MAX_METRICS_STORED) {
        metricsStore.shift()
    }

    // Log if threshold exceeded
    if (metric.duration > PERFORMANCE_THRESHOLDS.LOGIN_ENDPOINT) {
        logger.warn("Performance threshold exceeded", {
            endpoint: metric.endpoint,
            duration: metric.duration,
            threshold: PERFORMANCE_THRESHOLDS.LOGIN_ENDPOINT,
        })
    }
}

/**
 * Get performance metrics for analysis
 */
export function getMetrics(
    endpoint?: string,
    limit: number = 100
): PerformanceMetrics[] {
    let metrics = metricsStore

    if (endpoint) {
        metrics = metrics.filter(m => m.endpoint === endpoint)
    }

    return metrics.slice(-limit)
}

/**
 * Calculate average response time
 */
export function getAverageResponseTime(endpoint?: string): number {
    const metrics = getMetrics(endpoint)

    if (metrics.length === 0) {
        return 0
    }

    const total = metrics.reduce((sum, m) => sum + m.duration, 0)
    return total / metrics.length
}

/**
 * Calculate percentile response time (e.g., p95, p99)
 */
export function getPercentileResponseTime(
    percentile: number,
    endpoint?: string
): number {
    const metrics = getMetrics(endpoint)

    if (metrics.length === 0) {
        return 0
    }

    const sorted = metrics.map(m => m.duration).sort((a, b) => a - b)

    const index = Math.ceil((percentile / 100) * sorted.length) - 1
    return sorted[Math.max(0, index)]
}

/**
 * Get performance statistics
 */
export function getPerformanceStats(endpoint?: string): {
    count: number
    min: number
    max: number
    avg: number
    p50: number
    p95: number
    p99: number
} {
    const metrics = getMetrics(endpoint)

    if (metrics.length === 0) {
        return {
            count: 0,
            min: 0,
            max: 0,
            avg: 0,
            p50: 0,
            p95: 0,
            p99: 0,
        }
    }

    const durations = metrics.map(m => m.duration).sort((a, b) => a - b)

    return {
        count: metrics.length,
        min: durations[0],
        max: durations[durations.length - 1],
        avg: getAverageResponseTime(endpoint),
        p50: getPercentileResponseTime(50, endpoint),
        p95: getPercentileResponseTime(95, endpoint),
        p99: getPercentileResponseTime(99, endpoint),
    }
}

/**
 * Check if performance is within acceptable thresholds
 */
export function isPerformanceAcceptable(
    duration: number,
    threshold: number = PERFORMANCE_THRESHOLDS.LOGIN_ENDPOINT
): boolean {
    return duration <= threshold
}

/**
 * Get performance report
 */
export function getPerformanceReport(): {
    endpoints: Record<string, ReturnType<typeof getPerformanceStats>>
    overallStats: ReturnType<typeof getPerformanceStats>
    thresholdsExceeded: Array<{
        endpoint: string
        count: number
        percentage: number
    }>
} {
    const metrics = getMetrics()
    const endpoints = new Set(metrics.map(m => m.endpoint))

    const endpointStats: Record<
        string,
        ReturnType<typeof getPerformanceStats>
    > = {}
    const thresholdsExceeded: Array<{
        endpoint: string
        count: number
        percentage: number
    }> = []

    for (const endpoint of endpoints) {
        endpointStats[endpoint] = getPerformanceStats(endpoint)

        const endpointMetrics = metrics.filter(m => m.endpoint === endpoint)
        const exceededCount = endpointMetrics.filter(
            m => m.duration > PERFORMANCE_THRESHOLDS.LOGIN_ENDPOINT
        ).length

        if (exceededCount > 0) {
            thresholdsExceeded.push({
                endpoint,
                count: exceededCount,
                percentage: (exceededCount / endpointMetrics.length) * 100,
            })
        }
    }

    return {
        endpoints: endpointStats,
        overallStats: getPerformanceStats(),
        thresholdsExceeded,
    }
}

/**
 * Clear performance metrics (for testing)
 */
export function clearMetrics(): void {
    metricsStore.length = 0
}

/**
 * Measure function execution time
 */
export async function measureAsync<T>(
    fn: () => Promise<T>,
    label?: string
): Promise<{ result: T; duration: number }> {
    const start = performance.now()
    const result = await fn()
    const duration = performance.now() - start

    if (label) {
        logger.debug(`${label} took ${duration.toFixed(2)}ms`)
    }

    return { result, duration }
}

/**
 * Measure synchronous function execution time
 */
export function measureSync<T>(
    fn: () => T,
    label?: string
): { result: T; duration: number } {
    const start = performance.now()
    const result = fn()
    const duration = performance.now() - start

    if (label) {
        logger.debug(`${label} took ${duration.toFixed(2)}ms`)
    }

    return { result, duration }
}

/**
 * Cache decorator for performance optimization
 */
export function withCache<T>(
    fn: () => Promise<T>,
    ttl: number = 60000 // 1 minute default
): () => Promise<T> {
    let cachedResult: T | null = null
    let cacheExpiry: number = 0

    return async () => {
        const now = Date.now()

        if (cachedResult !== null && now < cacheExpiry) {
            return cachedResult
        }

        cachedResult = await fn()
        cacheExpiry = now + ttl

        return cachedResult
    }
}

/**
 * Debounce function for performance optimization
 */
export function debounce<T extends (...args: any[]) => any>(
    fn: T,
    delay: number
): (...args: Parameters<T>) => void {
    let timeoutId: NodeJS.Timeout | null = null

    return (...args: Parameters<T>) => {
        if (timeoutId) {
            clearTimeout(timeoutId)
        }

        timeoutId = setTimeout(() => {
            fn(...args)
            timeoutId = null
        }, delay)
    }
}

/**
 * Throttle function for performance optimization
 */
export function throttle<T extends (...args: any[]) => any>(
    fn: T,
    delay: number
): (...args: Parameters<T>) => void {
    let lastCall = 0

    return (...args: Parameters<T>) => {
        const now = Date.now()

        if (now - lastCall >= delay) {
            fn(...args)
            lastCall = now
        }
    }
}

/**
 * Batch operations for performance optimization
 */
export class BatchProcessor<T, R> {
    private queue: T[] = []
    private processing = false
    private flushTimer: NodeJS.Timeout | null = null

    constructor(
        private processor: (items: T[]) => Promise<R[]>,
        private batchSize: number = 10,
        private flushInterval: number = 100
    ) {}

    async add(item: T): Promise<void> {
        this.queue.push(item)

        if (this.queue.length >= this.batchSize) {
            await this.flush()
        } else if (!this.flushTimer) {
            this.flushTimer = setTimeout(() => this.flush(), this.flushInterval)
        }
    }

    async flush(): Promise<R[]> {
        if (this.flushTimer) {
            clearTimeout(this.flushTimer)
            this.flushTimer = null
        }

        if (this.queue.length === 0) {
            return []
        }

        if (this.processing) {
            return []
        }

        this.processing = true

        try {
            const items = this.queue.splice(0, this.batchSize)
            return await this.processor(items)
        } finally {
            this.processing = false

            if (this.queue.length > 0) {
                await this.flush()
            }
        }
    }

    getQueueSize(): number {
        return this.queue.length
    }
}

/**
 * Connection pool for database performance optimization
 */
export class ConnectionPool {
    private connections: any[] = []
    private available: any[] = []
    private waiting: Array<(conn: any) => void> = []

    constructor(
        private factory: () => Promise<any>,
        private poolSize: number = 10
    ) {}

    async initialize(): Promise<void> {
        for (let i = 0; i < this.poolSize; i++) {
            const conn = await this.factory()
            this.connections.push(conn)
            this.available.push(conn)
        }
    }

    async acquire(): Promise<any> {
        if (this.available.length > 0) {
            return this.available.pop()
        }

        return new Promise(resolve => {
            this.waiting.push(resolve)
        })
    }

    release(conn: any): void {
        if (this.waiting.length > 0) {
            const resolve = this.waiting.shift()
            if (resolve) {
                resolve(conn)
            }
        } else {
            this.available.push(conn)
        }
    }

    async close(): Promise<void> {
        for (const conn of this.connections) {
            if (conn && typeof conn.close === "function") {
                await conn.close()
            }
        }

        this.connections = []
        this.available = []
        this.waiting = []
    }

    getStats(): {
        total: number
        available: number
        inUse: number
        waiting: number
    } {
        return {
            total: this.connections.length,
            available: this.available.length,
            inUse: this.connections.length - this.available.length,
            waiting: this.waiting.length,
        }
    }
}

/**
 * Query optimizer for database performance
 */
export class QueryOptimizer {
    private queryCache = new Map<string, { result: any; timestamp: number }>()
    private cacheTTL: number = 60000 // 1 minute

    /**
     * Execute query with caching
     */
    async executeWithCache<T>(
        key: string,
        query: () => Promise<T>
    ): Promise<T> {
        const cached = this.queryCache.get(key)

        if (cached && Date.now() - cached.timestamp < this.cacheTTL) {
            logger.debug("Query cache hit", { key })
            return cached.result
        }

        const result = await query()
        this.queryCache.set(key, { result, timestamp: Date.now() })

        return result
    }

    /**
     * Invalidate cache entry
     */
    invalidateCache(key: string): void {
        this.queryCache.delete(key)
    }

    /**
     * Clear all cache
     */
    clearCache(): void {
        this.queryCache.clear()
    }

    /**
     * Get cache stats
     */
    getCacheStats(): {
        size: number
        entries: Array<{ key: string; age: number }>
    } {
        const entries = Array.from(this.queryCache.entries()).map(
            ([key, value]) => ({
                key,
                age: Date.now() - value.timestamp,
            })
        )

        return {
            size: this.queryCache.size,
            entries,
        }
    }
}

/**
 * Global query optimizer instance
 */
export const queryOptimizer = new QueryOptimizer()

/**
 * Performance monitoring middleware
 */
export function createPerformanceMiddleware() {
    return (req: any, res: any, next: any) => {
        const start = performance.now()

        // Wrap res.end to capture response
        const originalEnd = res.end
        res.end = function (...args: any[]) {
            const duration = performance.now() - start

            recordMetric({
                endpoint: req.path,
                method: req.method,
                duration,
                timestamp: new Date(),
                statusCode: res.statusCode,
                cached: false,
            })

            originalEnd.apply(res, args)
        }

        next()
    }
}

/**
 * Rate Limiting for Login Attempts
 * Implements protection against brute force attacks
 * Max 5 failed attempts per hour per IP address
 *
 * Supports both Upstash Redis and in-memory backends
 */

import { getRedisClient, isRedisConnected } from "@/lib/cache/redis-client"
import { createLogger } from "@/lib/logger"

const logger = createLogger("RateLimiter")

const MAX_ATTEMPTS = 5
const WINDOW_DURATION_HOURS = 1
const WINDOW_DURATION_MS = WINDOW_DURATION_HOURS * 60 * 60 * 1000

// Enhanced rate limiting for degraded mode (CAPTCHA unavailable)
const DEGRADED_MODE_MAX_ATTEMPTS = 3
const DEGRADED_MODE_WINDOW_MINUTES = 10
const DEGRADED_MODE_WINDOW_MS = DEGRADED_MODE_WINDOW_MINUTES * 60 * 1000

/**
 * In-memory store for rate limiting (local development fallback)
 * Structure: { [key: string]: { count: number; resetTime: number } }
 */
const inMemoryStore = new Map<string, { count: number; resetTime: number }>()

/**
 * Generate cache key for rate limiting
 */
function generateKey(ipAddress: string): string {
    return `rate-limit:login:${ipAddress}`
}

/**
 * Clean up expired entries from in-memory store
 */
function cleanupInMemoryStore(): void {
    const now = Date.now()
    for (const [key, value] of inMemoryStore.entries()) {
        if (value.resetTime < now) {
            inMemoryStore.delete(key)
        }
    }
}

/**
 * Get attempt count from in-memory store
 */
function getInMemoryAttemptCount(key: string): number {
    cleanupInMemoryStore()
    const entry = inMemoryStore.get(key)
    if (!entry) {
        return 0
    }
    if (entry.resetTime < Date.now()) {
        inMemoryStore.delete(key)
        return 0
    }
    return entry.count
}

/**
 * Increment attempt count in in-memory store
 */
function incrementInMemoryAttempt(key: string): number {
    cleanupInMemoryStore()
    const entry = inMemoryStore.get(key)
    const now = Date.now()

    if (!entry || entry.resetTime < now) {
        // Create new entry
        const newEntry = { count: 1, resetTime: now + WINDOW_DURATION_MS }
        inMemoryStore.set(key, newEntry)
        return 1
    }

    // Increment existing entry
    entry.count++
    return entry.count
}

/**
 * Reset attempt count in in-memory store
 */
function resetInMemoryAttempts(key: string): void {
    inMemoryStore.delete(key)
}

/**
 * Get attempt count from Redis
 */
async function getRedisAttemptCount(key: string): Promise<number> {
    try {
        const client = await getRedisClient()
        if (!client) {
            return 0
        }

        const count = await client.get(key)
        return count ? parseInt(String(count), 10) : 0
    } catch (error) {
        logger.error("Failed to get attempt count from Redis", {
            key,
            error: error instanceof Error ? error.message : String(error),
        })
        return 0
    }
}

/**
 * Increment attempt count in Redis
 */
async function incrementRedisAttempt(key: string): Promise<number> {
    try {
        const client = await getRedisClient()
        if (!client) {
            return 0
        }

        // Increment and set expiration
        const count = await client.incr(key)

        // Set expiration on first increment
        if (count === 1) {
            await client.expire(key, WINDOW_DURATION_HOURS * 60 * 60)
        }

        return count
    } catch (error) {
        logger.error("Failed to increment attempt count in Redis", {
            key,
            error: error instanceof Error ? error.message : String(error),
        })
        return 0
    }
}

/**
 * Reset attempt count in Redis
 */
async function resetRedisAttempts(key: string): Promise<void> {
    try {
        const client = await getRedisClient()
        if (!client) {
            return
        }

        await client.del(key)
    } catch (error) {
        logger.error("Failed to reset attempt count in Redis", {
            key,
            error: error instanceof Error ? error.message : String(error),
        })
    }
}

/**
 * Check if IP address has exceeded rate limit
 * Returns true if rate limit is exceeded, false otherwise
 */
export async function checkRateLimit(ipAddress: string): Promise<boolean> {
    const key = generateKey(ipAddress)

    try {
        let attemptCount: number

        if (isRedisConnected()) {
            attemptCount = await getRedisAttemptCount(key)
        } else {
            attemptCount = getInMemoryAttemptCount(key)
        }

        const isLimited = attemptCount >= MAX_ATTEMPTS

        if (isLimited) {
            logger.warn("Rate limit exceeded", {
                ipAddress,
                attemptCount,
            })
        }

        return isLimited
    } catch (error) {
        logger.error("Error checking rate limit", {
            ipAddress,
            error: error instanceof Error ? error.message : String(error),
        })
        // Fail open: allow request if rate limiter fails
        return false
    }
}

/**
 * Increment attempt counter for failed login
 * Returns the new attempt count
 */
export async function incrementAttempt(ipAddress: string): Promise<number> {
    const key = generateKey(ipAddress)

    try {
        let newCount: number

        if (isRedisConnected()) {
            newCount = await incrementRedisAttempt(key)
        } else {
            newCount = incrementInMemoryAttempt(key)
        }

        logger.debug("Login attempt incremented", {
            ipAddress,
            attemptCount: newCount,
        })

        return newCount
    } catch (error) {
        logger.error("Error incrementing attempt count", {
            ipAddress,
            error: error instanceof Error ? error.message : String(error),
        })
        return 0
    }
}

/**
 * Reset attempt counter for successful login
 */
export async function resetAttempt(ipAddress: string): Promise<void> {
    const key = generateKey(ipAddress)

    try {
        if (isRedisConnected()) {
            await resetRedisAttempts(key)
        } else {
            resetInMemoryAttempts(key)
        }

        logger.debug("Login attempts reset", { ipAddress })
    } catch (error) {
        logger.error("Error resetting attempt count", {
            ipAddress,
            error: error instanceof Error ? error.message : String(error),
        })
    }
}

/**
 * Get current attempt count for an IP address
 */
export async function getAttemptCount(ipAddress: string): Promise<number> {
    const key = generateKey(ipAddress)

    try {
        let count: number

        if (isRedisConnected()) {
            count = await getRedisAttemptCount(key)
        } else {
            count = getInMemoryAttemptCount(key)
        }

        return count
    } catch (error) {
        logger.error("Error getting attempt count", {
            ipAddress,
            error: error instanceof Error ? error.message : String(error),
        })
        return 0
    }
}

/**
 * Get remaining attempts before rate limit
 */
export async function getRemainingAttempts(ipAddress: string): Promise<number> {
    const count = await getAttemptCount(ipAddress)
    return Math.max(0, MAX_ATTEMPTS - count)
}

/**
 * Get time until rate limit resets (in seconds)
 */
export async function getTimeUntilReset(ipAddress: string): Promise<number> {
    const key = generateKey(ipAddress)

    try {
        if (isRedisConnected()) {
            const client = await getRedisClient()
            if (!client) {
                return 0
            }

            const ttl = await client.ttl(key)
            return Math.max(0, ttl)
        } else {
            cleanupInMemoryStore()
            const entry = inMemoryStore.get(key)
            if (!entry) {
                return 0
            }

            const timeRemaining = entry.resetTime - Date.now()
            return Math.max(0, Math.ceil(timeRemaining / 1000))
        }
    } catch (error) {
        logger.error("Error getting time until reset", {
            ipAddress,
            error: error instanceof Error ? error.message : String(error),
        })
        return 0
    }
}

/**
 * Clear all rate limit entries (for testing/admin purposes)
 */
export async function clearAllRateLimits(): Promise<void> {
    try {
        if (isRedisConnected()) {
            const client = await getRedisClient()
            if (!client) {
                return
            }

            const keys = await client.keys("rate-limit:login:*")
            if (keys.length > 0) {
                await client.del(...keys)
            }
        } else {
            inMemoryStore.clear()
        }

        logger.info("All rate limits cleared")
    } catch (error) {
        logger.error("Error clearing rate limits", {
            error: error instanceof Error ? error.message : String(error),
        })
    }
}

/**
 * Get rate limiter statistics (for monitoring)
 */
export async function getRateLimiterStats(): Promise<{
    backend: "redis" | "in-memory"
    entriesCount: number
}> {
    try {
        if (isRedisConnected()) {
            const client = await getRedisClient()
            if (!client) {
                return { backend: "in-memory", entriesCount: 0 }
            }

            const keys = await client.keys("rate-limit:login:*")
            return {
                backend: "redis",
                entriesCount: keys.length,
            }
        } else {
            cleanupInMemoryStore()
            return {
                backend: "in-memory",
                entriesCount: inMemoryStore.size,
            }
        }
    } catch (error) {
        logger.error("Error getting rate limiter stats", {
            error: error instanceof Error ? error.message : String(error),
        })
        return { backend: "in-memory", entriesCount: 0 }
    }
}

/**
 * Check rate limit with degraded mode support
 *
 * In degraded mode (CAPTCHA unavailable):
 * - Stricter failure threshold (3 instead of 5)
 * - Shorter lockout window (10 minutes instead of 15)
 * - More aggressive logging
 *
 * @param ipAddress Client IP address
 * @param degradedMode Whether CAPTCHA service is unavailable
 * @returns Object with rate limit status and details
 */
export async function checkRateLimitWithDegradation(
    ipAddress: string,
    degradedMode: boolean = false
): Promise<{
    allowed: boolean
    remainingAttempts: number
    degradedMode: boolean
    reason?: string
}> {
    const key = generateKey(ipAddress)
    const maxAttempts = degradedMode ? DEGRADED_MODE_MAX_ATTEMPTS : MAX_ATTEMPTS
    const windowMs = degradedMode ? DEGRADED_MODE_WINDOW_MS : WINDOW_DURATION_MS

    try {
        let attemptCount: number

        if (isRedisConnected()) {
            attemptCount = await getRedisAttemptCount(key)
        } else {
            attemptCount = getInMemoryAttemptCount(key)
        }

        const isLimited = attemptCount >= maxAttempts

        if (isLimited) {
            const logLevel = degradedMode ? "error" : "warn"
            logger[logLevel as "warn" | "error"](
                "Rate limit exceeded" +
                    (degradedMode ? " (degraded mode)" : ""),
                {
                    ipAddress,
                    attemptCount,
                    maxAttempts,
                    degradedMode,
                    windowMinutes: degradedMode
                        ? DEGRADED_MODE_WINDOW_MINUTES
                        : WINDOW_DURATION_HOURS * 60,
                }
            )

            // Log degraded mode rate limiting for audit trail
            if (degradedMode) {
                logger.info("Degraded mode rate limiting applied", {
                    event_type: "rate_limit_degraded_mode",
                    ipAddress,
                    attemptCount,
                    maxAttempts: DEGRADED_MODE_MAX_ATTEMPTS,
                    lockout_window_minutes: DEGRADED_MODE_WINDOW_MINUTES,
                    timestamp: new Date().toISOString(),
                })
            }
        }

        return {
            allowed: !isLimited,
            remainingAttempts: Math.max(0, maxAttempts - attemptCount),
            degradedMode,
            reason: isLimited
                ? degradedMode
                    ? `Too many attempts (degraded mode: ${maxAttempts} attempts in ${DEGRADED_MODE_WINDOW_MINUTES} minutes)`
                    : `Too many attempts (${maxAttempts} attempts in ${WINDOW_DURATION_HOURS} hour)`
                : undefined,
        }
    } catch (error) {
        logger.error("Error checking rate limit with degradation", {
            ipAddress,
            degradedMode,
            error: error instanceof Error ? error.message : String(error),
        })
        // Fail open: allow request if rate limiter fails
        return {
            allowed: true,
            remainingAttempts: maxAttempts,
            degradedMode,
        }
    }
}

/**
 * Increment attempt counter with degraded mode support
 *
 * In degraded mode, uses shorter window (10 minutes instead of 15)
 * and logs more aggressively for audit trail.
 *
 * @param ipAddress Client IP address
 * @param degradedMode Whether CAPTCHA service is unavailable
 * @returns New attempt count
 */
export async function incrementAttemptWithDegradation(
    ipAddress: string,
    degradedMode: boolean = false
): Promise<number> {
    const key = generateKey(ipAddress)
    const windowMs = degradedMode ? DEGRADED_MODE_WINDOW_MS : WINDOW_DURATION_MS

    try {
        let newCount: number

        if (isRedisConnected()) {
            const client = await getRedisClient()
            if (!client) {
                return 0
            }

            // Increment and set expiration
            newCount = await client.incr(key)

            // Set expiration on first increment
            if (newCount === 1) {
                const expirationSeconds = degradedMode
                    ? DEGRADED_MODE_WINDOW_MINUTES * 60
                    : WINDOW_DURATION_HOURS * 60 * 60
                await client.expire(key, expirationSeconds)
            }
        } else {
            cleanupInMemoryStore()
            const entry = inMemoryStore.get(key)
            const now = Date.now()

            if (!entry || entry.resetTime < now) {
                // Create new entry
                const newEntry = {
                    count: 1,
                    resetTime: now + windowMs,
                }
                inMemoryStore.set(key, newEntry)
                newCount = 1
            } else {
                // Increment existing entry
                entry.count++
                newCount = entry.count
            }
        }

        // Log with degraded mode indicator
        if (degradedMode) {
            logger.warn("Login attempt incremented (degraded mode)", {
                ipAddress,
                attemptCount: newCount,
                maxAttempts: DEGRADED_MODE_MAX_ATTEMPTS,
                windowMinutes: DEGRADED_MODE_WINDOW_MINUTES,
            })
        } else {
            logger.debug("Login attempt incremented", {
                ipAddress,
                attemptCount: newCount,
            })
        }

        return newCount
    } catch (error) {
        logger.error("Error incrementing attempt count with degradation", {
            ipAddress,
            degradedMode,
            error: error instanceof Error ? error.message : String(error),
        })
        return 0
    }
}

/**
 * Registration Session Management Module
 * Handles registration session creation, validation, and removal for the multi-step registration flow
 *
 * Validates: Requirements 16.1, 16.2, 16.6
 */

import { generateRandomHex } from "@/lib/crypto-utils"
import { db } from "@/lib/db"
import { logger } from "@/lib/logger"

const { queryOne, query } = db

/**
 * Registration session configuration constants
 */
const REGISTRATION_SESSION_EXPIRATION_MINUTES = 30
const SESSION_ID_LENGTH = 32 // 32 bytes = 256 bits

/**
 * Registration Session interface
 * Represents a registration session with form data and expiration
 */
export interface RegistrationSession {
    id: string
    session_id: string
    email: string
    name: string
    phone: string
    current_step: 1 | 2 | 3 | 4
    created_at: Date
    expires_at: Date
    last_activity_at: Date
}

/**
 * Create a new registration session
 *
 * This function:
 * 1. Generates a unique session_id using crypto.randomBytes(32)
 * 2. Creates a registration session record in the database
 * 3. Sets expiration to 30 minutes from now
 * 4. Returns the RegistrationSession object
 *
 * @param email - The user's email address
 * @returns RegistrationSession object with id, session_id, email, created_at, expires_at
 * @throws Error if session creation fails
 *
 * Validates: Requirements 16.1, 16.2
 */
export async function createRegistrationSession(
    email: string
): Promise<RegistrationSession> {
    try {
        // Validate email
        if (!email || typeof email !== "string") {
            throw new Error("Invalid email provided")
        }

        // Generate unique session_id using crypto.getRandomValues
        // Convert to hex string for storage in database
        const sessionId = generateRandomHex(SESSION_ID_LENGTH)

        // Calculate expiration date (30 minutes from now)
        const now = new Date()
        const expiresAt = new Date(
            now.getTime() + REGISTRATION_SESSION_EXPIRATION_MINUTES * 60 * 1000
        )

        // Create registration session record in database
        const session = await queryOne<RegistrationSession>(
            `INSERT INTO registration_sessions (session_id, email, current_step, created_at, expires_at, last_activity_at)
             VALUES ($1, $2, $3, NOW(), $4, NOW())
             RETURNING id, session_id, email, name, phone, current_step, created_at, expires_at, last_activity_at`,
            [sessionId, email, 1, expiresAt]
        )

        if (!session) {
            throw new Error("Failed to create registration session record")
        }

        logger.debug("Registration session created successfully", {
            context: "Auth",
            data: {
                email,
                sessionId: sessionId.substring(0, 8) + "...", // Log only first 8 chars for security
                expiresAt: expiresAt.toISOString(),
            },
        })

        return session
    } catch (error) {
        logger.error("Failed to create registration session", {
            context: "Auth",
            error: error as Error,
            data: { email },
        })
        throw error
    }
}

/**
 * Validate a registration session by session_id
 *
 * This function:
 * 1. Queries the registration_sessions table by session_id
 * 2. Checks if session exists
 * 3. Checks if session is not expired (expires_at > now)
 * 4. Updates last_activity_at to current time
 * 5. Returns RegistrationSession object if valid, null if invalid or expired
 *
 * @param sessionId - The session ID to validate
 * @returns RegistrationSession object if valid and not expired, null otherwise
 * @throws Error if database operation fails
 *
 * Validates: Requirements 16.1, 16.2, 16.6
 */
export async function validateRegistrationSession(
    sessionId: string
): Promise<RegistrationSession | null> {
    try {
        // Validate session ID
        if (!sessionId || typeof sessionId !== "string") {
            logger.warn("Invalid session ID provided for validation", {
                context: "Auth",
            })
            return null
        }

        // Query session by session_id
        const session = await queryOne<RegistrationSession>(
            `SELECT id, session_id, email, name, phone, current_step, created_at, expires_at, last_activity_at
             FROM registration_sessions
             WHERE session_id = $1`,
            [sessionId]
        )

        // Session not found
        if (!session) {
            logger.debug("Registration session not found", {
                context: "Auth",
                data: { sessionId: sessionId.substring(0, 8) + "..." },
            })
            return null
        }

        // Check if session is expired
        const now = new Date()
        const expiresAt = new Date(session.expires_at)

        if (expiresAt < now) {
            logger.debug("Registration session expired", {
                context: "Auth",
                data: {
                    email: session.email,
                    expiresAt: expiresAt.toISOString(),
                },
            })
            return null
        }

        // Update last_activity_at to current time
        await query(
            `UPDATE registration_sessions
             SET last_activity_at = NOW()
             WHERE session_id = $1`,
            [sessionId]
        )

        // Session is valid
        logger.debug("Registration session validated successfully", {
            context: "Auth",
            data: {
                email: session.email,
                currentStep: session.current_step,
                expiresAt: expiresAt.toISOString(),
            },
        })

        return session
    } catch (error) {
        logger.error("Failed to validate registration session", {
            context: "Auth",
            error: error as Error,
            data: { sessionId: sessionId?.substring(0, 8) + "..." },
        })
        throw error
    }
}

/**
 * Retrieve a registration session by session_id
 *
 * This function:
 * 1. Queries the registration_sessions table by session_id
 * 2. Returns the session if found, null otherwise
 * 3. Does NOT check expiration (use validateRegistrationSession for that)
 *
 * @param sessionId - The session ID to retrieve
 * @returns RegistrationSession object if found, null otherwise
 * @throws Error if database operation fails
 *
 * Validates: Requirements 16.1, 16.6
 */
export async function getRegistrationSession(
    sessionId: string
): Promise<RegistrationSession | null> {
    try {
        // Validate session ID
        if (!sessionId || typeof sessionId !== "string") {
            logger.warn("Invalid session ID provided for retrieval", {
                context: "Auth",
            })
            return null
        }

        // Query session by session_id
        const session = await queryOne<RegistrationSession>(
            `SELECT id, session_id, email, name, phone, current_step, created_at, expires_at, last_activity_at
             FROM registration_sessions
             WHERE session_id = $1`,
            [sessionId]
        )

        if (!session) {
            logger.debug("Registration session not found for retrieval", {
                context: "Auth",
                data: { sessionId: sessionId.substring(0, 8) + "..." },
            })
            return null
        }

        logger.debug("Registration session retrieved successfully", {
            context: "Auth",
            data: {
                email: session.email,
                currentStep: session.current_step,
            },
        })

        return session
    } catch (error) {
        logger.error("Failed to retrieve registration session", {
            context: "Auth",
            error: error as Error,
            data: { sessionId: sessionId?.substring(0, 8) + "..." },
        })
        throw error
    }
}

/**
 * Update registration session with form data
 *
 * This function:
 * 1. Updates the registration session with new form data
 * 2. Updates the current_step
 * 3. Updates last_activity_at to current time
 * 4. Returns the updated RegistrationSession object
 *
 * @param sessionId - The session ID to update
 * @param data - Partial registration session data to update
 * @returns Updated RegistrationSession object
 * @throws Error if session not found or update fails
 *
 * Validates: Requirements 16.1, 16.6
 */
export async function updateRegistrationSession(
    sessionId: string,
    data: Partial<
        Omit<
            RegistrationSession,
            | "id"
            | "session_id"
            | "created_at"
            | "expires_at"
            | "last_activity_at"
        >
    >
): Promise<RegistrationSession> {
    try {
        // Validate session ID
        if (!sessionId || typeof sessionId !== "string") {
            throw new Error("Invalid session ID provided")
        }

        // Build update query dynamically based on provided data
        const updateFields: string[] = []
        const updateValues: any[] = [sessionId]
        let paramIndex = 2

        if (data.email !== undefined) {
            updateFields.push(`email = $${paramIndex}`)
            updateValues.push(data.email)
            paramIndex++
        }

        if (data.name !== undefined) {
            updateFields.push(`name = $${paramIndex}`)
            updateValues.push(data.name)
            paramIndex++
        }

        if (data.phone !== undefined) {
            updateFields.push(`phone = $${paramIndex}`)
            updateValues.push(data.phone)
            paramIndex++
        }

        if (data.current_step !== undefined) {
            updateFields.push(`current_step = $${paramIndex}`)
            updateValues.push(data.current_step)
            paramIndex++
        }

        // Always update last_activity_at
        updateFields.push("last_activity_at = NOW()")

        if (updateFields.length === 1) {
            // Only last_activity_at is being updated
            throw new Error("No data provided to update")
        }

        // Update session record in database
        const updatedSession = await queryOne<RegistrationSession>(
            `UPDATE registration_sessions
             SET ${updateFields.join(", ")}
             WHERE session_id = $1
             RETURNING id, session_id, email, name, phone, current_step, created_at, expires_at, last_activity_at`,
            updateValues
        )

        if (!updatedSession) {
            throw new Error("Registration session not found for update")
        }

        logger.debug("Registration session updated successfully", {
            context: "Auth",
            data: {
                email: updatedSession.email,
                currentStep: updatedSession.current_step,
                sessionId: sessionId.substring(0, 8) + "...",
            },
        })

        return updatedSession
    } catch (error) {
        logger.error("Failed to update registration session", {
            context: "Auth",
            error: error as Error,
            data: { sessionId: sessionId?.substring(0, 8) + "..." },
        })
        throw error
    }
}

/**
 * Remove a registration session by session_id
 *
 * This function:
 * 1. Deletes the registration session from the database by session_id
 * 2. Returns success status
 *
 * @param sessionId - The session ID to remove
 * @returns true if session was deleted, false if session not found
 * @throws Error if database operation fails
 *
 * Validates: Requirements 16.1, 16.6
 */
export async function removeRegistrationSession(
    sessionId: string
): Promise<boolean> {
    try {
        // Validate session ID
        if (!sessionId || typeof sessionId !== "string") {
            throw new Error("Invalid session ID provided")
        }

        // Delete session from database
        const result = await query(
            "DELETE FROM registration_sessions WHERE session_id = $1",
            [sessionId]
        )

        // Check if any rows were deleted
        const deleted = (result.rowCount || 0) > 0

        if (deleted) {
            logger.debug("Registration session removed successfully", {
                context: "Auth",
                data: { sessionId: sessionId.substring(0, 8) + "..." },
            })
        } else {
            logger.debug("Registration session not found for removal", {
                context: "Auth",
                data: { sessionId: sessionId.substring(0, 8) + "..." },
            })
        }

        return deleted
    } catch (error) {
        logger.error("Failed to remove registration session", {
            context: "Auth",
            error: error as Error,
            data: { sessionId: sessionId?.substring(0, 8) + "..." },
        })
        throw error
    }
}

/**
 * Clean up expired registration sessions
 *
 * This function:
 * 1. Deletes all registration sessions that have expired
 * 2. Returns the number of sessions deleted
 *
 * @returns Number of expired sessions deleted
 * @throws Error if database operation fails
 *
 * Validates: Requirements 16.2
 */
export async function cleanupExpiredRegistrationSessions(): Promise<number> {
    try {
        const result = await query(
            "DELETE FROM registration_sessions WHERE expires_at < NOW()"
        )

        const deletedCount = result.rowCount || 0

        logger.debug("Expired registration sessions cleaned up", {
            context: "Auth",
            data: { deletedCount },
        })

        return deletedCount
    } catch (error) {
        logger.error("Failed to cleanup expired registration sessions", {
            context: "Auth",
            error: error as Error,
        })
        throw error
    }
}

export interface UnifiedAuthResult {
    success: boolean
    userExists: boolean
    userId?: string
    email?: string
    error?: string
}

export async function checkUserExists(
    email: string
): Promise<UnifiedAuthResult> {
    try {
        const response = await fetch(
            `${process.env.NEXT_PUBLIC_SUPABASE_URL}/rest/v1/users?email=eq.${encodeURIComponent(email)}&select=id`,
            {
                headers: {
                    Authorization: `Bearer ${process.env.NEXT_PUBLIC_SUPABASE_PUBLISHABLE_KEY}`,
                    "Content-Type": "application/json",
                },
            }
        )

        if (!response.ok) {
            return {
                success: true,
                userExists: false,
                email,
            }
        }

        const data = await response.json()
        const userExists = Array.isArray(data) && data.length > 0

        return {
            success: true,
            userExists,
            email,
        }
    } catch {
        return {
            success: false,
            userExists: false,
            error: "Failed to check user existence",
        }
    }
}

export async function signInWithEmail(
    email: string,
    password: string
): Promise<UnifiedAuthResult> {
    try {
        const response = await fetch("/api/auth/login", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ email, password }),
        })

        const data = await response.json()

        if (!response.ok || !data.success) {
            return {
                success: false,
                userExists: false,
                error: data.error || "Authentication failed",
            }
        }

        return {
            success: true,
            userExists: true,
            userId: data.data?.userId,
            email: data.data?.email,
        }
    } catch (err) {
        return {
            success: false,
            userExists: false,
            error: err instanceof Error ? err.message : "Authentication failed",
        }
    }
}

export async function signUpWithEmail(
    email: string,
    password: string,
    metadata?: Record<string, unknown>
): Promise<UnifiedAuthResult> {
    try {
        const response = await fetch("/api/auth/register", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                email,
                password,
                name: (metadata?.name as string) || email.split("@")[0],
                phone: metadata?.phone || "",
                captchaToken: metadata?.captchaToken as string | undefined,
            }),
        })

        const data = await response.json()

        if (!response.ok || !data.success) {
            return {
                success: false,
                userExists: false,
                error: data.error || "Registration failed",
            }
        }

        return {
            success: true,
            userExists: false,
            userId: data.data?.userId,
            email: data.data?.email,
        }
    } catch (err) {
        return {
            success: false,
            userExists: false,
            error: err instanceof Error ? err.message : "Registration failed",
        }
    }
}

export async function signInWithOAuth(
    provider: "google" | "github"
): Promise<void> {
    const clientId = process.env.NEXT_PUBLIC_GOOGLE_CLIENT_ID
    const redirectUri = process.env.NEXT_PUBLIC_GOOGLE_REDIRECT_URI

    if (!clientId || !redirectUri) {
        throw new Error("OAuth not configured")
    }

    const state = Math.random().toString(36).substring(7)
    if (typeof window !== "undefined") {
        sessionStorage.setItem("oauth_state", state)
    }

    const params = new URLSearchParams({
        client_id: clientId,
        redirect_uri: redirectUri,
        response_type: "code",
        scope: "openid email profile",
        state,
    })

    if (typeof window !== "undefined") {
        window.location.href = `https://accounts.google.com/o/oauth2/v2/auth?${params.toString()}`
    }
}

export async function signInWithSSO(email: string): Promise<void> {
    throw new Error(
        "SSO is not supported with the current authentication system."
    )
}

// Database Layer - Enhanced with Logging and Helpers
// Focus: Debugability, Performance, Reliability

import { logger } from "@/lib/logger"
import { Pool, PoolClient, QueryResult, QueryResultRow } from "pg"

// Singleton pool
let pool: Pool | null = null

const SLOW_QUERY_THRESHOLD_MS = 100
const MAX_RETRIES = 3
const RETRY_DELAY_MS = 1000

/**
 * Get or create the database pool
 */
function getPool(): Pool {
    if (!pool) {
        const connectionString = process.env.DATABASE_URL
        if (!connectionString) {
            throw new Error("DATABASE_URL is not defined")
        }

        pool = new Pool({
            connectionString,
            max: 10,
            idleTimeoutMillis: 30000,
            connectionTimeoutMillis: 5000,
        })

        pool.on("connect", () => {
            logger.debug("New DB connection established", { context: "DB" })
        })

        pool.on("error", err => {
            logger.error("Unexpected DB pool error", {
                context: "DB",
                error: err,
            })
        })

        logger.startup("PostgreSQL Pool")
    }

    return pool
}

/**
 * Execute a query with timing and logging
 */
export async function query<T extends QueryResultRow = QueryResultRow>(
    text: string,
    params?: Array<string | number | boolean | null | Date>
): Promise<QueryResult<T>> {
    const start = Date.now()

    try {
        const result = await getPool().query<T>(text, params)
        const duration = Date.now() - start

        // Log slow queries
        if (duration > SLOW_QUERY_THRESHOLD_MS) {
            logger.warn(`Slow query: ${duration}ms`, {
                context: "DB",
                data: { query: text.slice(0, 100), duration },
            })
        } else {
            logger.debug(`Query: ${duration}ms`, { context: "DB" })
        }

        return result
    } catch (err) {
        logger.error("Query failed", {
            context: "DB",
            error: err as Error,
            data: { query: text.slice(0, 100) },
        })
        throw err
    }
}

/**
 * Get a single row or null
 */
export async function queryOne<T extends QueryResultRow = QueryResultRow>(
    text: string,
    params?: Array<string | number | boolean | null | Date>
): Promise<T | null> {
    const result = await query<T>(text, params)
    return result.rows[0] || null
}

/**
 * Get multiple rows
 */
export async function queryMany<T extends QueryResultRow = QueryResultRow>(
    text: string,
    params?: Array<string | number | boolean | null | Date>
): Promise<T[]> {
    const result = await query<T>(text, params)
    return result.rows
}

/**
 * Execute within a transaction
 */
export async function transaction<T>(
    fn: (client: PoolClient) => Promise<T>
): Promise<T> {
    const client = await getPool().connect()

    try {
        await client.query("BEGIN")
        const result = await fn(client)
        await client.query("COMMIT")
        return result
    } catch (err) {
        await client.query("ROLLBACK")
        logger.error("Transaction rolled back", {
            context: "DB",
            error: err as Error,
        })
        throw err
    } finally {
        client.release()
    }
}

/**
 * Health check with retry logic
 */
export async function healthCheck(): Promise<boolean> {
    for (let i = 0; i < MAX_RETRIES; i++) {
        try {
            await query("SELECT 1")
            return true
        } catch (err) {
            logger.warn(
                `DB health check failed, attempt ${i + 1}/${MAX_RETRIES}`,
                { context: "DB" }
            )
            if (i < MAX_RETRIES - 1) {
                await new Promise(r => setTimeout(r, RETRY_DELAY_MS))
            }
        }
    }

    logger.fatal("DB health check failed after retries", { context: "DB" })
    return false
}

/**
 * Graceful shutdown
 */
export async function shutdown(): Promise<void> {
    if (pool) {
        logger.shutdown("PostgreSQL Pool")
        await pool.end()
        pool = null
    }
}

const db = {
    query,
    queryOne,
    queryMany,
    transaction,
    healthCheck,
    shutdown,
}

export { db }
export default db

// Discord Alerter with Rate Limiting
// Focus: Critical alerts only, non-blocking, rate-limited

import { createLogger } from "@/lib/logger"
import { InMemoryRateLimiter, type RateLimiter } from "./rate-limiter"

const logger = createLogger("DiscordAlerter")

export type AlertLevel = "error" | "fatal" | "startup" | "shutdown"

export interface Alert {
    level: AlertLevel
    title: string
    message: string
    context?: Record<string, any>
    stack?: string
}

export interface DiscordAlerter {
    sendAlert(alert: Alert): Promise<void>
}

export class DiscordAlerterImpl implements DiscordAlerter {
    private webhookUrl: string
    private rateLimiter: RateLimiter

    constructor(webhookUrl: string, rateLimiter?: RateLimiter) {
        this.webhookUrl = webhookUrl
        this.rateLimiter = rateLimiter || new InMemoryRateLimiter(60000) // 1 minute default
    }

    async sendAlert(alert: Alert): Promise<void> {
        // Rate limit key: level + title for granular control
        const rateLimitKey = `${alert.level}:${alert.title}`

        if (!this.rateLimiter.shouldAllow(rateLimitKey)) {
            logger.debug("Alert suppressed by rate limiter", {
                alert: rateLimitKey,
            })
            return
        }

        const embed = this.createEmbed(alert)

        try {
            const response = await fetch(this.webhookUrl, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ embeds: [embed] }),
            })

            if (!response.ok) {
                logger.error(
                    "Failed to send Discord alert",
                    new Error(`HTTP ${response.status}`),
                    {
                        alert: rateLimitKey,
                        status: response.status,
                    }
                )
            }
        } catch (error) {
            // Non-blocking: log error but don't throw
            logger.error("Discord webhook request failed", error as Error, {
                alert: rateLimitKey,
            })
        }
    }

    private createEmbed(alert: Alert): any {
        const colors: Record<AlertLevel, number> = {
            error: 0xffa500, // Orange
            fatal: 0xff0000, // Red
            startup: 0x00ff00, // Green
            shutdown: 0x0000ff, // Blue
        }

        const embed: any = {
            title: alert.title,
            description: alert.message,
            color: colors[alert.level],
            fields: [],
            timestamp: new Date().toISOString(),
        }

        // Add context if present
        if (alert.context && Object.keys(alert.context).length > 0) {
            embed.fields.push({
                name: "Context",
                value:
                    "```json\n" +
                    JSON.stringify(alert.context, null, 2).substring(0, 500) +
                    "\n```",
            })
        }

        // Add stack trace if present (truncated to fit Discord limits)
        if (alert.stack) {
            embed.fields.push({
                name: "Stack Trace",
                value: "```\n" + alert.stack.substring(0, 1000) + "\n```",
            })
        }

        return embed
    }
}

// Factory function for easy instantiation
export function createDiscordAlerter(webhookUrl?: string): DiscordAlerter {
    const url = webhookUrl || process.env.DISCORD_WEBHOOK_URL

    if (!url) {
        throw new Error("Discord webhook URL is required")
    }

    return new DiscordAlerterImpl(url)
}

export default createDiscordAlerter

