import type {
    EnvMode,
    LocalEnvEntry,
    LocalEnvsData,
    ServiceEnvs,
} from "./types"
import { KNOWN_SERVICES, STORAGE_KEY } from "./types"

function getStored(): LocalEnvsData {
    if (typeof window === "undefined") {
        return { version: 1, services: [] }
    }
    try {
        const raw = localStorage.getItem(STORAGE_KEY)
        if (!raw) return { version: 1, services: [] }
        return JSON.parse(raw) as LocalEnvsData
    } catch {
        return { version: 1, services: [] }
    }
}

function persist(data: LocalEnvsData): void {
    if (typeof window === "undefined") return
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data))
}

export function getServiceEnvs(serviceId: string): ServiceEnvs | undefined {
    const data = getStored()
    return data.services.find(s => s.serviceId === serviceId)
}

export function getAllServiceEnvs(): ServiceEnvs[] {
    return getStored().services
}

export function setServiceMode(serviceId: string, mode: EnvMode): void {
    const data = getStored()
    const existing = data.services.find(s => s.serviceId === serviceId)
    if (existing) {
        existing.mode = mode
    } else {
        const def = KNOWN_SERVICES.find(s => s.id === serviceId)
        data.services.push({
            serviceId,
            serviceName: def?.name ?? serviceId,
            icon: def?.icon ?? "box",
            mode,
            envs: [],
        })
    }
    persist(data)
}

export function setEnvVar(
    serviceId: string,
    key: string,
    value: string,
    label: string
): void {
    const data = getStored()
    let service = data.services.find(s => s.serviceId === serviceId)
    if (!service) {
        const def = KNOWN_SERVICES.find(s => s.id === serviceId)
        service = {
            serviceId,
            serviceName: def?.name ?? serviceId,
            icon: def?.icon ?? "box",
            mode: "cloud_preferred",
            envs: [],
        }
        data.services.push(service)
    }
    const existing = service.envs.find(e => e.key === key)
    if (existing) {
        existing.value = value
    } else {
        service.envs.push({ key, value, label })
    }
    persist(data)
}

export function removeEnvVar(serviceId: string, key: string): void {
    const data = getStored()
    const service = data.services.find(s => s.serviceId === serviceId)
    if (!service) return
    service.envs = service.envs.filter(e => e.key !== key)
    if (service.envs.length === 0 && service.mode === "cloud_only") {
        data.services = data.services.filter(s => s.serviceId !== serviceId)
    }
    persist(data)
}

export function removeService(serviceId: string): void {
    const data = getStored()
    data.services = data.services.filter(s => s.serviceId !== serviceId)
    persist(data)
}

export function getEnvVarValue(
    serviceId: string,
    key: string
): string | undefined {
    const service = getServiceEnvs(serviceId)
    if (!service) return undefined
    return service.envs.find(e => e.key === key)?.value
}

export function getServiceMode(serviceId: string): EnvMode {
    const service = getServiceEnvs(serviceId)
    return service?.mode ?? "cloud_only"
}

export function clearAll(): void {
    if (typeof window === "undefined") return
    localStorage.removeItem(STORAGE_KEY)
}

// Request Context Middleware
// Focus: Request tracing
// Note: x-user-id is NOT trusted from client headers — must come from session/auth middleware

import { NextRequest, NextResponse } from "next/server"

function generateRequestId(): string {
    const bytes = new Uint8Array(16)
    crypto.getRandomValues(bytes)

    bytes[6] = (bytes[6] & 0x0f) | 0x40
    bytes[8] = (bytes[8] & 0x3f) | 0x80

    const hex = Array.from(bytes)
        .map(b => b.toString(16).padStart(2, "0"))
        .join("")

    return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20)}`
}

export interface RequestContext {
    requestId: string
    startTime: number
    path: string
    method: string
}

export function contextMiddleware(request: NextRequest): NextResponse {
    const requestId = request.headers.get("x-request-id") || generateRequestId()

    const context: RequestContext = {
        requestId,
        startTime: Date.now(),
        path: request.nextUrl.pathname,
        method: request.method,
    }

    const response = NextResponse.next()
    response.headers.set("X-Request-ID", requestId)

    return response
}

export function getRequestContext(headers: Headers): Partial<RequestContext> {
    return {
        requestId: headers.get("x-request-id") || undefined,
    }
}

export default contextMiddleware

/**
 * Security Headers Middleware
 * Implements comprehensive security headers to protect against common web vulnerabilities
 */

import type { NextRequest } from "next/server"
import { NextResponse } from "next/server"

/**
 * Security headers configuration
 */
const SECURITY_HEADERS = {
    // Content Security Policy - prevents XSS attacks
    "Content-Security-Policy":
        "default-src 'self'; script-src 'self' 'unsafe-inline'; style-src 'self' 'unsafe-inline'; img-src 'self' data: https:; font-src 'self' data:; connect-src 'self' https:; frame-ancestors 'none'; base-uri 'self'; form-action 'self'",

    // X-Frame-Options - prevents clickjacking
    "X-Frame-Options": "DENY",

    // X-Content-Type-Options - prevents MIME type sniffing
    "X-Content-Type-Options": "nosniff",

    // Strict-Transport-Security - enforces HTTPS
    "Strict-Transport-Security": "max-age=31536000; includeSubDomains; preload",

    // Referrer-Policy - controls referrer information
    "Referrer-Policy": "strict-origin-when-cross-origin",

    // Permissions-Policy - controls browser features
    "Permissions-Policy":
        "geolocation=(), microphone=(), camera=(), payment=(), usb=(), magnetometer=(), gyroscope=(), accelerometer=()",

    // X-Permitted-Cross-Domain-Policies - prevents cross-domain policy abuse
    "X-Permitted-Cross-Domain-Policies": "none",

    // X-XSS-Protection - legacy XSS protection (for older browsers)
    "X-XSS-Protection": "1; mode=block",
}

/**
 * Apply security headers to a response
 */
export function applySecurityHeaders(response: NextResponse): NextResponse {
    Object.entries(SECURITY_HEADERS).forEach(([key, value]) => {
        response.headers.set(key, value)
    })

    return response
}

/**
 * Middleware to add security headers to all responses
 */
export function securityHeadersMiddleware(request: NextRequest): NextResponse {
    // Create a response
    let response = NextResponse.next()

    // Apply security headers
    response = applySecurityHeaders(response)

    return response
}

/**
 * Get security headers as an object (useful for API routes)
 */
export function getSecurityHeaders(): Record<string, string> {
    return SECURITY_HEADERS
}

/**
 * Middleware for API routes to add security headers
 */
export function withSecurityHeaders(
    handler: (req: NextRequest) => Promise<Response> | Response
) {
    return async (req: NextRequest) => {
        const response = await handler(req)

        // Convert to NextResponse if needed
        let nextResponse: NextResponse
        if (response instanceof NextResponse) {
            nextResponse = response
        } else {
            nextResponse = new NextResponse(response.body, {
                status: response.status,
                statusText: response.statusText,
                headers: response.headers,
            })
        }

        // Apply security headers
        return applySecurityHeaders(nextResponse)
    }
}

/**
 * Get CSP header for inline scripts (if needed)
 * This should be used sparingly and only when absolutely necessary
 */
export function getCspNonce(): string {
    // Generate a random nonce for inline scripts
    return Buffer.from(Math.random().toString()).toString("base64")
}

/**
 * Validate that a request has the correct origin
 * Useful for CSRF protection
 */
export function validateOrigin(
    request: NextRequest,
    allowedOrigins: string[]
): boolean {
    const origin = request.headers.get("origin")

    if (!origin) {
        return true // Allow requests without origin header (e.g., same-site requests)
    }

    return allowedOrigins.includes(origin)
}

/**
 * Get the client IP address from request
 * Handles X-Forwarded-For header for proxied requests
 */
export function getClientIp(request: NextRequest): string {
    const forwarded = request.headers.get("x-forwarded-for")
    if (forwarded) {
        return forwarded.split(",")[0].trim()
    }

    return request.headers.get("x-real-ip") || "unknown"
}

/**
 * Network Manager Service
 * Manages social media network linking, unlinking, and status checking
 * Requirements: 5.1, 5.2, 5.3, 5.4, 5.5
 */

import { createClient } from "@supabase/supabase-js"
import { CACHE_KEYS, CacheManager } from "../cache"
import { createLogger } from "../logger"
import { getTokenStore } from "../token-store"

const logger = createLogger("NetworkManager")

/**
 * Supported social media platforms
 */
export type SocialPlatform =
    | "youtube"
    | "facebook"
    | "instagram"
    | "twitter"
    | "linkedin"

/**
 * Network status
 */
export type NetworkStatus = "connected" | "disconnected" | "expired" | "error"

/**
 * Social network record
 */
export interface SocialNetwork {
    id: string
    userId: string
    platform: SocialPlatform
    platformUserId: string
    platformUsername: string
    status: NetworkStatus
    linkedAt: number
    expiresAt?: number
    metadata?: Record<string, any>
    createdAt: number
    updatedAt: number
}

/**
 * Network Manager
 * Handles network linking, unlinking, and status management
 */
export class NetworkManager {
    private supabase = createClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL || "",
        process.env.SUPABASE_SERVICE_ROLE_KEY || ""
    )
    private tokenStore = getTokenStore()

    /**
     * Link a social network to a user account
     */
    async linkNetwork(
        userId: string,
        platform: SocialPlatform,
        platformUserId: string,
        platformUsername: string,
        metadata?: Record<string, any>
    ): Promise<SocialNetwork> {
        try {
            // Check if network is already linked
            const { data: existing } = await this.supabase
                .from("social_networks")
                .select("id")
                .eq("user_id", userId)
                .eq("platform", platform)
                .single()

            const now = Date.now()

            let result

            if (existing) {
                // Update existing network
                result = await this.supabase
                    .from("social_networks")
                    .update({
                        platform_user_id: platformUserId,
                        platform_username: platformUsername,
                        status: "connected",
                        metadata: metadata || null,
                        updated_at: new Date(now),
                    })
                    .eq("user_id", userId)
                    .eq("platform", platform)
                    .select()
                    .single()
            } else {
                // Insert new network
                result = await this.supabase
                    .from("social_networks")
                    .insert({
                        user_id: userId,
                        platform,
                        platform_user_id: platformUserId,
                        platform_username: platformUsername,
                        status: "connected",
                        linked_at: new Date(now),
                        metadata: metadata || null,
                        created_at: new Date(now),
                        updated_at: new Date(now),
                    })
                    .select()
                    .single()
            }

            if (result.error) {
                throw new Error(`Database error: ${result.error.message}`)
            }

            // Invalidate cache
            await CacheManager.delete(CACHE_KEYS.USER_NETWORKS(userId))

            logger.info("Network linked successfully", {
                userId,
                platform,
                platformUserId,
            })

            return this.mapDatabaseToNetwork(result.data)
        } catch (error) {
            logger.error("Failed to link network", {
                userId,
                platform,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Unlink a social network from a user account
     */
    async unlinkNetwork(
        userId: string,
        platform: SocialPlatform
    ): Promise<boolean> {
        try {
            // Get the network to revoke token
            const { data: network } = await this.supabase
                .from("social_networks")
                .select("*")
                .eq("user_id", userId)
                .eq("platform", platform)
                .single()

            if (!network) {
                logger.warn("Network not found for unlinking", {
                    userId,
                    platform,
                })
                return false
            }

            // Revoke token if it exists
            try {
                await this.tokenStore.deleteToken(userId, platform)
            } catch (error) {
                logger.warn("Failed to delete token during unlinking", {
                    userId,
                    platform,
                    error:
                        error instanceof Error ? error.message : String(error),
                })
            }

            // Delete the network
            const { error } = await this.supabase
                .from("social_networks")
                .delete()
                .eq("user_id", userId)
                .eq("platform", platform)

            if (error) {
                throw new Error(`Database error: ${error.message}`)
            }

            // Invalidate cache
            await CacheManager.delete(CACHE_KEYS.USER_NETWORKS(userId))

            logger.info("Network unlinked successfully", {
                userId,
                platform,
            })

            return true
        } catch (error) {
            logger.error("Failed to unlink network", {
                userId,
                platform,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Get all networks for a user
     */
    async getUserNetworks(userId: string): Promise<SocialNetwork[]> {
        try {
            // Try to get from cache first
            const cacheKey = CACHE_KEYS.USER_NETWORKS(userId)
            const cached = await CacheManager.get<SocialNetwork[]>(cacheKey)

            if (cached) {
                logger.debug("User networks retrieved from cache", { userId })
                return cached
            }

            // Get from database
            const { data, error } = await this.supabase
                .from("social_networks")
                .select("*")
                .eq("user_id", userId)

            if (error) {
                throw new Error(`Database error: ${error.message}`)
            }

            const networks = (data || []).map(network =>
                this.mapDatabaseToNetwork(network)
            )

            // Cache for 5 minutes
            await CacheManager.set(cacheKey, networks, 5 * 60)

            logger.info("User networks retrieved", {
                userId,
                count: networks.length,
            })

            return networks
        } catch (error) {
            logger.error("Failed to retrieve user networks", {
                userId,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Get a specific network for a user
     */
    async getNetwork(
        userId: string,
        platform: SocialPlatform
    ): Promise<SocialNetwork | null> {
        try {
            const { data, error } = await this.supabase
                .from("social_networks")
                .select("*")
                .eq("user_id", userId)
                .eq("platform", platform)
                .single()

            if (error) {
                if (error.code === "PGRST116") {
                    // No rows found
                    return null
                }
                throw new Error(`Database error: ${error.message}`)
            }

            logger.info("Network retrieved", { userId, platform })

            return this.mapDatabaseToNetwork(data)
        } catch (error) {
            logger.error("Failed to retrieve network", {
                userId,
                platform,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Check network status
     */
    async checkNetworkStatus(
        userId: string,
        platform: SocialPlatform
    ): Promise<NetworkStatus> {
        try {
            const network = await this.getNetwork(userId, platform)

            if (!network) {
                return "disconnected"
            }

            // Check if token is valid
            const isTokenValid = await this.tokenStore.isTokenValid(
                userId,
                platform
            )

            if (!isTokenValid) {
                // Update network status
                await this.supabase
                    .from("social_networks")
                    .update({
                        status: "expired",
                        updated_at: new Date(),
                    })
                    .eq("user_id", userId)
                    .eq("platform", platform)

                // Invalidate cache
                await CacheManager.delete(CACHE_KEYS.USER_NETWORKS(userId))

                return "expired"
            }

            return "connected"
        } catch (error) {
            logger.error("Failed to check network status", {
                userId,
                platform,
                error: error instanceof Error ? error.message : String(error),
            })
            return "error"
        }
    }

    /**
     * Get status for all user networks
     */
    async getUserNetworkStatuses(
        userId: string
    ): Promise<Record<SocialPlatform, NetworkStatus>> {
        try {
            const networks = await this.getUserNetworks(userId)
            const statuses: Record<SocialPlatform, NetworkStatus> = {
                youtube: "disconnected",
                facebook: "disconnected",
                instagram: "disconnected",
                twitter: "disconnected",
                linkedin: "disconnected",
            }

            for (const network of networks) {
                const status = await this.checkNetworkStatus(
                    userId,
                    network.platform
                )
                statuses[network.platform] = status
            }

            logger.info("User network statuses retrieved", {
                userId,
                statuses,
            })

            return statuses
        } catch (error) {
            logger.error("Failed to retrieve user network statuses", {
                userId,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Check if user has any linked networks
     */
    async hasLinkedNetworks(userId: string): Promise<boolean> {
        try {
            const networks = await this.getUserNetworks(userId)
            return networks.length > 0
        } catch (error) {
            logger.error("Failed to check linked networks", {
                userId,
                error: error instanceof Error ? error.message : String(error),
            })
            return false
        }
    }

    /**
     * Map database record to SocialNetwork
     */
    private mapDatabaseToNetwork(dbNetwork: any): SocialNetwork {
        return {
            id: dbNetwork.id,
            userId: dbNetwork.user_id,
            platform: dbNetwork.platform,
            platformUserId: dbNetwork.platform_user_id,
            platformUsername: dbNetwork.platform_username,
            status: dbNetwork.status,
            linkedAt: new Date(dbNetwork.linked_at).getTime(),
            expiresAt: dbNetwork.expires_at
                ? new Date(dbNetwork.expires_at).getTime()
                : undefined,
            metadata: dbNetwork.metadata,
            createdAt: new Date(dbNetwork.created_at).getTime(),
            updatedAt: new Date(dbNetwork.updated_at).getTime(),
        }
    }
}

/**
 * Create a singleton Network Manager instance
 */
let networkManagerInstance: NetworkManager | null = null

/**
 * Get or create the Network Manager
 */
export function getNetworkManager(): NetworkManager {
    if (!networkManagerInstance) {
        networkManagerInstance = new NetworkManager()
    }
    return networkManagerInstance
}

/**
 * Reset the Network Manager (useful for testing)
 */
export function resetNetworkManager(): void {
    networkManagerInstance = null
}

import { getValidFacebookToken } from "@/lib/facebook/get-valid-token"
import { getFacebookConfig } from "@/lib/facebook/config"
import { getFacebookOAuthService } from "@/lib/facebook/oauth-service"
import { postToPageFeed } from "@/lib/facebook/posts"
import { getTokenStore } from "@/lib/token-store"

export interface FacebookPostConfig {
    userId: string
    pageId: string
    message: string
    link?: string
    picture?: string
    caption?: string
    description?: string
}

export interface FacebookPostResult {
    success: boolean
    postId?: string
    url?: string
    error?: string
}

export async function postToFacebook(
    config: FacebookPostConfig
): Promise<FacebookPostResult> {
    try {
        if (!config.pageId || !config.message) {
            return {
                success: false,
                error: "Page ID and message are required",
            }
        }

        const fbConfig = getFacebookConfig()
        const oauthService = getFacebookOAuthService(fbConfig)
        await oauthService.initialize()

        const userToken = await getValidFacebookToken(config.userId, {
            oauthService,
        })

        if (!userToken) {
            return {
                success: false,
                error: "Facebook account is not linked",
            }
        }

        const pageAccessToken = await oauthService.getPageAccessToken(
            config.pageId,
            userToken
        )

        if (!pageAccessToken) {
            return {
                success: false,
                error: "Failed to obtain page access token",
            }
        }

        const result = await postToPageFeed(pageAccessToken, config.pageId, {
            message: config.message,
            link: config.link,
            picture: config.picture,
            caption: config.caption,
            description: config.description,
        })

        return {
            success: true,
            postId: result.id,
            url: `https://www.facebook.com/${config.pageId}/posts/${result.id}`,
        }
    } catch (error) {
        return {
            success: false,
            error: error instanceof Error ? error.message : "Unknown error",
        }
    }
}

export default { postToFacebook }

import { getValidTikTokToken } from "@/lib/tiktok/get-valid-token"
import { getTikTokConfig } from "@/lib/tiktok/config"
import { getTikTokOAuthService } from "@/lib/tiktok/oauth-service"
import { getTokenStore } from "@/lib/token-store"

export interface TikTokPostConfig {
    userId: string
    title: string
    source: "FILE_UPLOAD" | "PULL_FROM_URL"
    videoUrl?: string
    videoBuffer?: ArrayBuffer
    privacyLevel?: string
    disableDuet?: boolean
    disableStitch?: boolean
    disableComment?: boolean
}

export interface TikTokPostResult {
    success: boolean
    publishId?: string
    postUrl?: string
    uploadUrl?: string
    error?: string
}

export async function postToTikTok(
    config: TikTokPostConfig
): Promise<TikTokPostResult> {
    try {
        if (!config.title || !config.source) {
            return {
                success: false,
                error: "Title and source are required",
            }
        }

        if (config.source === "PULL_FROM_URL" && !config.videoUrl) {
            return {
                success: false,
                error: "Video URL is required when source is PULL_FROM_URL",
            }
        }

        const ttConfig = getTikTokConfig()
        const oauthService = getTikTokOAuthService(ttConfig)
        await oauthService.initialize()

        const userToken = await getValidTikTokToken(config.userId, {
            oauthService,
        })

        if (!userToken) {
            return {
                success: false,
                error: "TikTok account is not linked",
            }
        }

        const initResult = await oauthService.initVideoPublish(userToken, {
            source: config.source,
            videoUrl: config.videoUrl,
            title: config.title,
            privacyLevel: config.privacyLevel || "SELF_ONLY",
            disableDuet: config.disableDuet,
            disableStitch: config.disableStitch,
            disableComment: config.disableComment,
        })

        if (config.source === "FILE_UPLOAD" && config.videoBuffer) {
            if (!initResult.uploadUrl) {
                return {
                    success: false,
                    error: "No upload URL returned from TikTok init",
                    publishId: initResult.publishId,
                }
            }

            const uploaded = await oauthService.uploadVideoFile(
                initResult.uploadUrl,
                config.videoBuffer
            )

            if (!uploaded) {
                return {
                    success: false,
                    error: "Video file upload failed",
                    publishId: initResult.publishId,
                    uploadUrl: initResult.uploadUrl,
                }
            }
        }

        return {
            success: true,
            publishId: initResult.publishId,
            uploadUrl: initResult.uploadUrl,
        }
    } catch (error) {
        return {
            success: false,
            error: error instanceof Error ? error.message : "Unknown error",
        }
    }
}

export default { postToTikTok }

/**
 * Conflict Detector Service
 * Detects scheduling conflicts and platform incompatibilities
 * Requirements: 14.1, 14.2, 14.3, 14.4, 14.5, 14.6, 14.7, 14.8
 */

import { createLogger } from "../logger"
import type { SocialPlatform } from "../networks"
import { getNetworkManager } from "../networks"
import { getContentAdapter } from "./content-adapter"

const logger = createLogger("ConflictDetector")

/**
 * Conflict type
 */
export type ConflictType =
    | "scheduling_conflict"
    | "content_limit"
    | "authentication_expired"
    | "platform_incompatibility"
    | "unsupported_feature"

/**
 * Conflict
 */
export interface Conflict {
    type: ConflictType
    platform?: SocialPlatform
    message: string
    severity: "warning" | "error"
    resolution?: string
}

/**
 * Conflict detection result
 */
export interface ConflictDetectionResult {
    hasConflicts: boolean
    conflicts: Conflict[]
    canPublish: boolean
}

/**
 * Conflict Detector
 * Detects scheduling conflicts and platform incompatibilities
 */
export class ConflictDetector {
    private networkManager = getNetworkManager()
    private contentAdapter = getContentAdapter()

    /**
     * Detect conflicts for a post
     */
    async detectConflicts(
        userId: string,
        content: string,
        platforms: SocialPlatform[],
        scheduledTime?: number
    ): Promise<ConflictDetectionResult> {
        const conflicts: Conflict[] = []

        // Check authentication status
        const authConflicts = await this.checkAuthenticationStatus(
            userId,
            platforms
        )
        conflicts.push(...authConflicts)

        // Check content limits
        const contentConflicts = this.checkContentLimits(content, platforms)
        conflicts.push(...contentConflicts)

        // Check scheduling conflicts
        if (scheduledTime) {
            const schedulingConflicts = await this.checkSchedulingConflicts(
                userId,
                scheduledTime,
                platforms
            )
            conflicts.push(...schedulingConflicts)
        }

        // Check platform incompatibilities
        const incompatibilityConflicts = this.checkPlatformIncompatibilities(
            content,
            platforms
        )
        conflicts.push(...incompatibilityConflicts)

        const hasConflicts = conflicts.length > 0
        const hasErrors = conflicts.some(c => c.severity === "error")

        logger.info("Conflict detection completed", {
            userId,
            platforms,
            conflictCount: conflicts.length,
            hasErrors,
        })

        return {
            hasConflicts,
            conflicts,
            canPublish: !hasErrors,
        }
    }

    /**
     * Check authentication status for platforms
     */
    private async checkAuthenticationStatus(
        userId: string,
        platforms: SocialPlatform[]
    ): Promise<Conflict[]> {
        const conflicts: Conflict[] = []

        for (const platform of platforms) {
            try {
                const status = await this.networkManager.checkNetworkStatus(
                    userId,
                    platform
                )

                if (status === "disconnected") {
                    conflicts.push({
                        type: "authentication_expired",
                        platform,
                        message: `${platform} is not connected. Please link your account first.`,
                        severity: "error",
                        resolution: `Go to settings and connect your ${platform} account`,
                    })
                } else if (status === "expired") {
                    conflicts.push({
                        type: "authentication_expired",
                        platform,
                        message: `Your ${platform} authentication has expired. Please re-authenticate.`,
                        severity: "error",
                        resolution: `Re-authenticate your ${platform} account in settings`,
                    })
                }
            } catch (error) {
                logger.error("Failed to check authentication status", {
                    userId,
                    platform,
                    error:
                        error instanceof Error ? error.message : String(error),
                })

                conflicts.push({
                    type: "authentication_expired",
                    platform,
                    message: `Failed to verify ${platform} authentication status`,
                    severity: "warning",
                })
            }
        }

        return conflicts
    }

    /**
     * Check content limits for platforms
     */
    private checkContentLimits(
        content: string,
        platforms: SocialPlatform[]
    ): Conflict[] {
        const conflicts: Conflict[] = []

        for (const platform of platforms) {
            const validation = this.contentAdapter.validateForPlatform(
                content,
                platform
            )

            for (const error of validation.errors) {
                conflicts.push({
                    type: "content_limit",
                    platform,
                    message: error,
                    severity: "error",
                    resolution: `Reduce content length or remove ${platform} from selected platforms`,
                })
            }

            for (const warning of validation.warnings) {
                conflicts.push({
                    type: "content_limit",
                    platform,
                    message: warning,
                    severity: "warning",
                })
            }
        }

        return conflicts
    }

    /**
     * Check scheduling conflicts
     */
    private async checkSchedulingConflicts(
        userId: string,
        scheduledTime: number,
        platforms: SocialPlatform[]
    ): Promise<Conflict[]> {
        const conflicts: Conflict[] = []

        // Check if scheduled time is in the past
        if (scheduledTime < Date.now()) {
            conflicts.push({
                type: "scheduling_conflict",
                message:
                    "Scheduled time is in the past. Please select a future time.",
                severity: "error",
                resolution: "Select a future date and time",
            })
        }

        // Check if scheduled time is too far in the future (> 365 days)
        const maxFutureTime = Date.now() + 365 * 24 * 60 * 60 * 1000
        if (scheduledTime > maxFutureTime) {
            conflicts.push({
                type: "scheduling_conflict",
                message: "Scheduled time is more than 365 days in the future.",
                severity: "warning",
                resolution: "Select a date within 365 days",
            })
        }

        return conflicts
    }

    /**
     * Check platform incompatibilities
     */
    private checkPlatformIncompatibilities(
        content: string,
        platforms: SocialPlatform[]
    ): Conflict[] {
        const conflicts: Conflict[] = []

        // Check for links on Instagram
        if (platforms.includes("instagram") && this.containsLinks(content)) {
            conflicts.push({
                type: "platform_incompatibility",
                platform: "instagram",
                message:
                    "Instagram does not support clickable links in captions. Links will be displayed as text.",
                severity: "warning",
                resolution:
                    "Add link to Instagram bio or remove from Instagram selection",
            })
        }

        // Check for mentions on platforms that don't support them
        if (this.containsMentions(content)) {
            for (const platform of platforms) {
                if (platform === "twitter" || platform === "facebook") {
                    // These support mentions, skip
                    continue
                }

                conflicts.push({
                    type: "unsupported_feature",
                    platform,
                    message: `${platform} may not properly format mentions. Consider removing or reformatting.`,
                    severity: "warning",
                })
            }
        }

        return conflicts
    }

    /**
     * Check if content contains links
     */
    private containsLinks(content: string): boolean {
        const urlRegex = /(https?:\/\/[^\s]+)/g
        return urlRegex.test(content)
    }

    /**
     * Check if content contains mentions
     */
    private containsMentions(content: string): boolean {
        const mentionRegex = /@\w+/g
        return mentionRegex.test(content)
    }
}

