 */
export function resetContentAdapter(): void {
    contentAdapterInstance = null
}

/**
 * Background Queue Processor
 *
 * This module provides a simple background processing solution
 * that runs in the Next.js server without requiring external cron jobs.
 *
 * It uses setInterval to check for due publications periodically.
 * This only works in long-running Node.js processes (not serverless).
 */

import { PublicationQueue } from "./publication-queue"
import { postToTwitter } from "@/lib/posting/adapters/twitter"
import { postToLinkedIn } from "@/lib/posting/adapters/linkedin"
import type { ScheduledPost } from "./publication-queue"

let processingInterval: NodeJS.Timeout | null = null
let isProcessing = false

export class BackgroundProcessor {
    private interval: number
    private queue: PublicationQueue

    constructor(intervalMs: number = 60000) {
        this.interval = intervalMs
        this.queue = new PublicationQueue()
    }

    /**
     * Start the background processor
     * Call this once when your server starts
     */
    start() {
        if (processingInterval) {
            console.log("Background processor already running")
            return
        }

        console.log(
            `Starting background processor (interval: ${this.interval}ms)`
        )

        // Process immediately on start
        this.processQueue()

        // Then process on interval
        processingInterval = setInterval(() => {
            this.processQueue()
        }, this.interval)
    }

    /**
     * Stop the background processor
     */
    stop() {
        if (processingInterval) {
            clearInterval(processingInterval)
            processingInterval = null
            console.log("Background processor stopped")
        }
    }

    /**
     * Process the queue
     */
    private async processQueue() {
        // Prevent concurrent processing
        if (isProcessing) {
            console.log("Queue processing already in progress, skipping...")
            return
        }

        isProcessing = true

        try {
            const duePublications = await this.queue.getAllDuePublications()

            if (duePublications.length === 0) {
                return
            }

            console.log(`Processing ${duePublications.length} due publications`)

            for (const publication of duePublications) {
                try {
                    await this.processPublication(publication)
                } catch (error) {
                    console.error(
                        `Failed to process publication ${publication.id}:`,
                        error
                    )
                }
            }

            console.log(
                `Finished processing ${duePublications.length} publications`
            )
        } catch (error) {
            console.error("Error in queue processing:", error)
        } finally {
            isProcessing = false
        }
    }

    /**
     * Process a single publication
     */
    private async processPublication(publication: ScheduledPost) {
        try {
            await this.queue.markAsProcessing(publication.id)

            const results = await this.publishToNetworks(publication)

            const allSucceeded = results.every(
                (r: { success: boolean }) => r.success
            )
            const allFailed = results.every(
                (r: { success: boolean }) => !r.success
            )

            if (allSucceeded) {
                await this.queue.markAsPublished(publication.id)
            } else if (allFailed) {
                await this.queue.markAsFailed(
                    publication.id,
                    "All networks failed"
                )
            } else {
                await this.queue.markAsPartiallyPublished(
                    publication.id,
                    results
                )
            }
        } catch (error) {
            await this.queue.handleFailure(
                publication.id,
                error instanceof Error ? error.message : "Unknown error"
            )
            throw error
        }
    }

    /**
     * Publish to all networks
     */
    private async publishToNetworks(publication: ScheduledPost) {
        const results: Array<{
            network: string
            success: boolean
            externalId?: string
        }> = []
        for (const network of publication.networks) {
            try {
                if (network.platform === "twitter") {
                    const result = await postToTwitter({
                        text: publication.content,
                    })
                    results.push({
                        network: network.platform,
                        success: result.success,
                        externalId: result.tweetId,
                    })
                } else if (network.platform === "linkedin") {
                    const result = await postToLinkedIn({
                        text: publication.content,
                        personId: publication.userId,
                    })
                    results.push({
                        network: network.platform,
                        success: result.success,
                        externalId: result.postId,
                    })
                } else {
                    results.push({
                        network: network.platform,
                        success: true,
                        externalId: `mock_${Date.now()}`,
                    })
                }
            } catch (error) {
                results.push({
                    network: network.platform,
                    success: false,
                })
            }
        }
        return results
    }
}

// Singleton instance
let backgroundProcessor: BackgroundProcessor | null = null

/**
 * Get or create the background processor instance
 */
export function getBackgroundProcessor(
    intervalMs?: number
): BackgroundProcessor {
    if (!backgroundProcessor) {
        backgroundProcessor = new BackgroundProcessor(intervalMs)
    }
    return backgroundProcessor
}

/**
 * Start background processing
 * Call this in your server startup code
 */
export function startBackgroundProcessing(intervalMs: number = 60000) {
    const processor = getBackgroundProcessor(intervalMs)
    processor.start()
    return processor
}

/**
 * Stop background processing
 * Call this on server shutdown
 */
export function stopBackgroundProcessing() {
    if (backgroundProcessor) {
        backgroundProcessor.stop()
        backgroundProcessor = null
    }
}

/**
 * Publication Queue Service
 * Manages scheduled posts and publication queue processing
 * Requirements: 11.1, 11.2, 11.3, 11.4, 11.5, 11.6, 11.7, 11.8, 13.1, 13.2, 13.3, 13.4, 13.5, 13.6, 13.7, 13.8
 */

import { createClient } from "@supabase/supabase-js"
import { CACHE_KEYS, CacheManager } from "../cache"
import { createLogger } from "../logger"
import type { SocialPlatform } from "../networks"

const logger = createLogger("PublicationQueue")

/**
 * Scheduled post record
 */
export interface ScheduledPost {
    id: string
    userId: string
    content: string
    mediaType: "text" | "video"
    mediaId?: string
    scheduledTime: number
    status: "pending" | "processing" | "published" | "failed"
    retryCount: number
    lastRetryAt?: number
    errorMessage?: string
    networks: ScheduledPostNetwork[]
    createdAt: number
    updatedAt: number
}

/**
 * Scheduled post network record
 */
export interface ScheduledPostNetwork {
    id: string
    postId: string
    platform: SocialPlatform
    status: "pending" | "published" | "failed"
    externalId?: string
    externalUrl?: string
    errorMessage?: string
    createdAt: number
    updatedAt: number
}

/**
 * Publication history record
 */
export interface PublicationHistoryEntry {
    id: string
    userId: string
    postId?: string
    platform: SocialPlatform
    status: "success" | "failed" | "pending"
    externalId?: string
    externalUrl?: string
    errorMessage?: string
    publishedAt: number
    createdAt: number
}

/**
 * Publication Queue
 * Manages scheduled posts and publication processing
 */
export class PublicationQueue {
    private supabase = createClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL || "",
        process.env.SUPABASE_SERVICE_ROLE_KEY || ""
    )

    /**
     * Create a scheduled post
     */
    async createScheduledPost(
        userId: string,
        content: string,
        scheduledTime: number,
        platforms: SocialPlatform[],
        mediaType: "text" | "video" = "text",
        _mediaId?: string
    ): Promise<ScheduledPost> {
        try {
            const now = Date.now()

            // Create the scheduled post
            const { data: post, error: postError } = await this.supabase
                .from("scheduled_posts")
                .insert({
                    user_id: userId,
                    content,
                    media_type: mediaType,
                    scheduled_time: new Date(scheduledTime),
                    status: "pending",
                    created_at: new Date(now),
                    updated_at: new Date(now),
                })
                .select()
                .single()

            if (postError) {
                throw new Error(`Database error: ${postError.message}`)
            }

            // Create network entries
            const networkEntries = platforms.map(platform => ({
                post_id: post.id,
                platform,
                status: "pending",
                created_at: new Date(now),
                updated_at: new Date(now),
            }))

            const { error: networkError } = await this.supabase
                .from("scheduled_post_networks")
                .insert(networkEntries)

            if (networkError) {
                throw new Error(`Database error: ${networkError.message}`)
            }

            // Invalidate cache
            await CacheManager.delete(CACHE_KEYS.PUBLICATION_QUEUE(userId))

            logger.info("Scheduled post created", {
                userId,
                postId: post.id,
                platforms,
                scheduledTime,
                mediaType,
            })

            return this.mapDatabaseToScheduledPost(post, platforms)
        } catch (error) {
            logger.error("Failed to create scheduled post", {
                userId,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Get a scheduled post
     */
    async getScheduledPost(
        userId: string,
        postId: string
    ): Promise<ScheduledPost | null> {
        try {
            const { data: post, error: postError } = await this.supabase
                .from("scheduled_posts")
                .select("*")
                .eq("id", postId)
                .eq("user_id", userId)
                .single()

            if (postError) {
                if (postError.code === "PGRST116") {
                    return null
                }
                throw new Error(`Database error: ${postError.message}`)
            }

            // Get networks
            const { data: networks, error: networkError } = await this.supabase
                .from("scheduled_post_networks")
                .select("*")
                .eq("post_id", postId)

            if (networkError) {
                throw new Error(`Database error: ${networkError.message}`)
            }

            logger.info("Scheduled post retrieved", { userId, postId })

            return this.mapDatabaseToScheduledPost(
                post,
                (networks || []).map(n => n.platform)
            )
        } catch (error) {
            logger.error("Failed to retrieve scheduled post", {
                userId,
                postId,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Get all scheduled posts for a user
     */
    async getUserScheduledPosts(userId: string): Promise<ScheduledPost[]> {
        try {
            const { data: posts, error: postError } = await this.supabase
                .from("scheduled_posts")
                .select("*")
                .eq("user_id", userId)
                .order("scheduled_time", { ascending: true })

            if (postError) {
                throw new Error(`Database error: ${postError.message}`)
            }

            const scheduledPosts: ScheduledPost[] = []

            for (const post of posts || []) {
                const { data: networks } = await this.supabase
                    .from("scheduled_post_networks")
                    .select("*")
                    .eq("post_id", post.id)

                scheduledPosts.push(
                    this.mapDatabaseToScheduledPost(
                        post,
                        (networks || []).map(n => n.platform)
                    )
                )
            }

            logger.info("User scheduled posts retrieved", {
                userId,
                count: scheduledPosts.length,
            })

            return scheduledPosts
        } catch (error) {
            logger.error("Failed to retrieve user scheduled posts", {
                userId,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Get posts ready for publication
     */
    async getPostsReadyForPublication(): Promise<ScheduledPost[]> {
        try {
            const now = new Date()

            const { data: posts, error } = await this.supabase
                .from("scheduled_posts")
                .select("*")
                .eq("status", "pending")
                .lte("scheduled_time", now)
                .order("scheduled_time", { ascending: true })
                .limit(100)

            if (error) {
                throw new Error(`Database error: ${error.message}`)
            }

            const scheduledPosts: ScheduledPost[] = []

            for (const post of posts || []) {
                const { data: networks } = await this.supabase
                    .from("scheduled_post_networks")
                    .select("*")
                    .eq("post_id", post.id)

                scheduledPosts.push(
                    this.mapDatabaseToScheduledPost(
                        post,
                        (networks || []).map(n => n.platform)
                    )
                )
            }

            logger.info("Posts ready for publication retrieved", {
                count: scheduledPosts.length,
            })

            return scheduledPosts
        } catch (error) {
            logger.error("Failed to retrieve posts ready for publication", {
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Update post status
     */
    async updatePostStatus(
        postId: string,
        status: "pending" | "processing" | "published" | "failed"
    ): Promise<void> {
        try {
            const { error } = await this.supabase
                .from("scheduled_posts")
                .update({
                    status,
                    updated_at: new Date(),
                })
                .eq("id", postId)

            if (error) {
                throw new Error(`Database error: ${error.message}`)
            }

            logger.info("Post status updated", { postId, status })
        } catch (error) {
            logger.error("Failed to update post status", {
                postId,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Update network publication status
     */
    async updateNetworkStatus(
        postId: string,
        platform: SocialPlatform,
        status: "pending" | "published" | "failed",
        externalId?: string,
        externalUrl?: string,
        errorMessage?: string
    ): Promise<void> {
        try {
            const { error } = await this.supabase
                .from("scheduled_post_networks")
                .update({
                    status,
                    external_id: externalId || null,
                    external_url: externalUrl || null,
                    error_message: errorMessage || null,
                    updated_at: new Date(),
                })
                .eq("post_id", postId)
                .eq("platform", platform)

            if (error) {
                throw new Error(`Database error: ${error.message}`)
            }

            logger.info("Network status updated", {
                postId,
                platform,
                status,
            })
        } catch (error) {
            logger.error("Failed to update network status", {
                postId,
                platform,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Record publication in history
     */
    async recordPublication(
        userId: string,
        postId: string | undefined,
        platform: SocialPlatform,
        status: "success" | "failed" | "pending",
        externalId?: string,
        externalUrl?: string,
        errorMessage?: string
    ): Promise<PublicationHistoryEntry> {
        try {
            const now = Date.now()

            const { data, error } = await this.supabase
                .from("publication_history")
                .insert({
                    user_id: userId,
                    post_id: postId || null,
                    platform,
                    status,
                    external_id: externalId || null,
                    external_url: externalUrl || null,
                    error_message: errorMessage || null,
                    published_at: new Date(now),
                    created_at: new Date(now),
                })
                .select()
                .single()

            if (error) {
                throw new Error(`Database error: ${error.message}`)
            }

            logger.info("Publication recorded in history", {
                userId,
                postId,
                platform,
                status,
            })

            return this.mapDatabaseToPublicationHistory(data)
        } catch (error) {
            logger.error("Failed to record publication", {
                userId,
                postId,
                platform,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    /**
     * Delete a scheduled post
     */
    async deleteScheduledPost(
        userId: string,
        postId: string
    ): Promise<boolean> {
        try {
            // Delete networks first
            await this.supabase
                .from("scheduled_post_networks")
                .delete()
                .eq("post_id", postId)

            // Delete the post
            const { error } = await this.supabase
                .from("scheduled_posts")
                .delete()
                .eq("id", postId)
                .eq("user_id", userId)

            if (error) {
                throw new Error(`Database error: ${error.message}`)
            }

            // Invalidate cache
            await CacheManager.delete(CACHE_KEYS.PUBLICATION_QUEUE(userId))

            logger.info("Scheduled post deleted", { userId, postId })

            return true
        } catch (error) {
            logger.error("Failed to delete scheduled post", {
                userId,
                postId,
                error: error instanceof Error ? error.message : String(error),
            })
            throw error
        }
    }

    async getDuePublications(userId: string): Promise<ScheduledPost[]> {
        const posts = await this.getPostsReadyForPublication()
        return posts.filter(post => post.userId === userId)
    }

    async getAllDuePublications(): Promise<ScheduledPost[]> {
        return this.getPostsReadyForPublication()
    }

    async markAsProcessing(postId: string): Promise<void> {
        await this.updatePostStatus(postId, "processing")
    }

    async markAsPublished(postId: string): Promise<void> {
        await this.updatePostStatus(postId, "published")
    }

    async markAsFailed(postId: string, errorMessage: string): Promise<void> {
        const { error } = await this.supabase
            .from("scheduled_posts")
            .update({
                status: "failed",
                error_message: errorMessage,
                updated_at: new Date(),
            })
            .eq("id", postId)

        if (error) {
            throw new Error(`Database error: ${error.message}`)
        }
    }

    async markAsPartiallyPublished(
        postId: string,
        _results: Array<{ success: boolean }>
    ): Promise<void> {
        await this.updatePostStatus(postId, "published")
    }

    async handleFailure(postId: string, errorMessage: string): Promise<void> {
        await this.markAsFailed(postId, errorMessage)
    }

    /**
     * Map database record to ScheduledPost
     */
    private mapDatabaseToScheduledPost(
        dbPost: any,
        platforms: SocialPlatform[]
    ): ScheduledPost {
        return {
            id: dbPost.id,
            userId: dbPost.user_id,
            content: dbPost.content,
            mediaType: dbPost.media_type || "text",
            mediaId: dbPost.media_id || undefined,
            scheduledTime: new Date(dbPost.scheduled_time).getTime(),
            status: dbPost.status,
            retryCount: dbPost.retry_count,
            lastRetryAt: dbPost.last_retry_at
                ? new Date(dbPost.last_retry_at).getTime()
                : undefined,
            errorMessage: dbPost.error_message || undefined,
            networks: platforms.map(platform => ({
                id: "",
                postId: dbPost.id,
                platform,
                status: "pending" as const,
                createdAt: new Date(dbPost.created_at).getTime(),
                updatedAt: new Date(dbPost.updated_at).getTime(),
            })),
            createdAt: new Date(dbPost.created_at).getTime(),
            updatedAt: new Date(dbPost.updated_at).getTime(),
        }
    }

    /**
     * Map database record to PublicationHistoryEntry
     */
    private mapDatabaseToPublicationHistory(
        dbEntry: any
    ): PublicationHistoryEntry {
        return {
            id: dbEntry.id,
            userId: dbEntry.user_id,
            postId: dbEntry.post_id || undefined,
            platform: dbEntry.platform,
            status: dbEntry.status,
            externalId: dbEntry.external_id || undefined,
            externalUrl: dbEntry.external_url || undefined,
            errorMessage: dbEntry.error_message || undefined,
            publishedAt: new Date(dbEntry.published_at).getTime(),
            createdAt: new Date(dbEntry.created_at).getTime(),
        }
    }
}

/**
 * Create a singleton Publication Queue instance
 */
let publicationQueueInstance: PublicationQueue | null = null

/**
 * Get or create the Publication Queue
 */
export function getPublicationQueue(): PublicationQueue {
    if (!publicationQueueInstance) {
        publicationQueueInstance = new PublicationQueue()
    }
    return publicationQueueInstance
}

/**
 * Reset the Publication Queue (useful for testing)
 */
export function resetPublicationQueue(): void {
    publicationQueueInstance = null
}

// Startup Handler
// Implements Requirements 2.8, 3.1, 8.9 from distributed-infrastructure-logging spec

import { DiscordAlerter } from "../discord/alerter"
import { createLogger } from "../logger"

const logger = createLogger("StartupHandler")

// List of sensitive environment variable keys that should never be logged
const SENSITIVE_ENV_VARS = [
    "PASSWORD",
    "SECRET",
    "TOKEN",
    "KEY",
    "PRIVATE",
    "CREDENTIAL",
    "AUTH",
    "API_KEY",
    "DATABASE_URL", // Contains password
    "REDIS_URL", // May contain password
    "DISCORD_WEBHOOK_URL", // Sensitive webhook URL
]

export interface StartupHandler {
    logStartup(version?: string): Promise<void>
}

export class StartupHandlerImpl implements StartupHandler {
    constructor(private discordAlerter: DiscordAlerter) {}

    async logStartup(version?: string): Promise<void> {
        const environment = process.env.NODE_ENV || "development"
        const appVersion =
            version || process.env.npm_package_version || "unknown"

        // Log startup
        logger.info("Application starting", {
            version: appVersion,
            environment,
            nodeVersion: process.version,
            platform: process.platform,
            pid: process.pid,
        })

        // Log non-sensitive configuration
        const safeConfig = this.getSafeConfiguration()
        logger.info("Configuration loaded", safeConfig)

        // Send startup alert to Discord
        await this.discordAlerter.sendAlert({
            level: "startup",
            title: "Application Started",
            message: "Application has started successfully",
            context: {
                version: appVersion,
                environment,
                nodeVersion: process.version,
                timestamp: new Date().toISOString(),
            },
        })

        logger.info("Startup complete")
    }

    private getSafeConfiguration(): Record<string, any> {
        const config: Record<string, any> = {}

        for (const [key, value] of Object.entries(process.env)) {
            // Skip sensitive variables
            if (this.isSensitive(key)) {
                config[key] = "[REDACTED]"
            } else if (value !== undefined) {
                config[key] = value
            }
        }

        return config
    }

    private isSensitive(key: string): boolean {
        const upperKey = key.toUpperCase()
        return SENSITIVE_ENV_VARS.some(sensitive =>
            upperKey.includes(sensitive)
        )
    }
}

// Factory function
export const createStartupHandler = (
    discordAlerter: DiscordAlerter
): StartupHandler => {
    return new StartupHandlerImpl(discordAlerter)
}

import { BaseService, ServiceError } from "../youtube/base-service"
import { TikTokConfig } from "./config"

export interface OAuthTokenResponse {
    accessToken: string
    refreshToken: string
    expiresIn: number
    tokenType: string
}

export interface AuthorizationUrlResponse {
    authorizationUrl: string
    state: string
}

export interface TikTokUser {
    openId: string
    unionId?: string
    displayName: string
    avatarUrl?: string
    avatarUrl100?: string
    avatarLargeUrl?: string
    bioDescription?: string
    isVerified?: boolean
    username?: string
    followerCount?: number
    followingCount?: number
    likesCount?: number
    videoCount?: number
}

export interface TikTokVideo {
    id: string
    title?: string
    coverImageUrl?: string
    shareUrl?: string
    videoDescription?: string
    duration?: number
    height?: number
    width?: number
    likeCount?: number
    commentCount?: number
    shareCount?: number
    viewCount?: number
    createTime?: string
}

