    }
}

/**
 * Validates phone number format using international standards
 * Requirement 4.7, 10.1
 *
 * Supports international phone number formats with or without formatting characters
 * (spaces, hyphens, parentheses). Validates using libphonenumber-js library.
 *
 * @param phoneNumber - The phone number to validate
 * @param defaultCountry - Optional default country code (e.g., 'US', 'BR', 'UK')
 * @returns Object with isValid boolean and error message if invalid
 *
 * @example
 * validatePhoneNumber('+1 (555) 123-4567') // { isValid: true }
 * validatePhoneNumber('(555) 123-4567', 'US') // { isValid: true }
 * validatePhoneNumber('+55 11 98765-4321') // { isValid: true }
 * validatePhoneNumber('invalid') // { isValid: false, error: 'Please enter a valid phone number' }
 */
export function validatePhoneNumber(
    phoneNumber: string,
    defaultCountry?: string
): {
    isValid: boolean
    error?: string
} {
    if (!phoneNumber || typeof phoneNumber !== "string") {
        return { isValid: false, error: "Phone number is required" }
    }

    const trimmedPhone = phoneNumber.trim()

    if (trimmedPhone.length === 0) {
        return { isValid: false, error: "Phone number is required" }
    }

    // Check if phone number contains invalid characters (like letters except in "ext.")
    const phoneWithoutExt = trimmedPhone.replace(/\s*ext\.?\s*\d+/i, "")
    if (/[a-zA-Z]/.test(phoneWithoutExt)) {
        return {
            isValid: false,
            error: "Please enter a valid phone number",
        }
    }

    try {
        // Use libphonenumber-js to validate the phone number (without extension)
        // If no country code is provided in the number, use the defaultCountry
        const isValid = isValidPhoneNumber(
            phoneWithoutExt,
            defaultCountry as any
        )

        if (!isValid) {
            // Additional fallback validation: check if it looks like a phone number
            // This helps with test numbers and edge cases
            const phoneRegex = /^[\d\s\-\+\(\)\.]+$/
            const hasMinimumDigits =
                (phoneWithoutExt.match(/\d/g) || []).length >= 10

            // Require country code or defaultCountry for validation
            const hasCountryCode =
                phoneWithoutExt.startsWith("+") || defaultCountry

            if (
                !phoneRegex.test(phoneWithoutExt) ||
                !hasMinimumDigits ||
                !hasCountryCode
            ) {
                return {
                    isValid: false,
                    error: "Please enter a valid phone number",
                }
            }

            // If it passes the fallback validation, consider it valid
            return { isValid: true }
        }

        return { isValid: true }
    } catch (error) {
        // Fallback validation on error
        const phoneRegex = /^[\d\s\-\+\(\)\.]+$/
        const hasMinimumDigits =
            (phoneWithoutExt.match(/\d/g) || []).length >= 10
        const hasCountryCode = phoneWithoutExt.startsWith("+") || defaultCountry

        if (
            phoneRegex.test(phoneWithoutExt) &&
            hasMinimumDigits &&
            hasCountryCode
        ) {
            return { isValid: true }
        }

        return {
            isValid: false,
            error: "Please enter a valid phone number",
        }
    }
}

/**
 * Normalizes phone number to E.164 format
 * Requirement 10.4
 *
 * Converts phone numbers in various formats to the standard E.164 format
 * (e.g., +1234567890). This format is used for storage and API communication.
 *
 * E.164 format: +[country code][number]
 * - Starts with + sign
 * - Followed by country code (1-3 digits)
 * - Followed by subscriber number (up to 12 digits)
 * - Total length: 15 digits maximum
 *
 * @param phoneNumber - The phone number to normalize
 * @param defaultCountry - Optional default country code (e.g., 'US', 'BR', 'UK')
 * @returns Object with normalized phone number in E.164 format or error
 *
 * @example
 * normalizePhoneNumber('+1 (555) 123-4567') // { normalized: '+15551234567' }
 * normalizePhoneNumber('(555) 123-4567', 'US') // { normalized: '+15551234567' }
 * normalizePhoneNumber('+55 11 98765-4321') // { normalized: '+5511987654321' }
 * normalizePhoneNumber('invalid') // { error: 'Invalid phone number format' }
 */
export function normalizePhoneNumber(
    phoneNumber: string,
    defaultCountry?: string
): {
    normalized?: string
    error?: string
} {
    if (!phoneNumber || typeof phoneNumber !== "string") {
        return { error: "Phone number is required" }
    }

    const trimmedPhone = phoneNumber.trim()

    if (trimmedPhone.length === 0) {
        return { error: "Phone number is required" }
    }

    try {
        // Parse the phone number using libphonenumber-js
        const parsed = parsePhoneNumber(trimmedPhone, defaultCountry as any)

        if (!parsed) {
            // Fallback: try to normalize manually for test numbers
            // Extract only digits and + sign
            const digitsOnly = trimmedPhone.replace(/[^\d\+]/g, "")

            if (digitsOnly.length < 10) {
                return { error: "Invalid phone number format" }
            }

            // If it starts with +, it's already in E.164-like format
            if (digitsOnly.startsWith("+")) {
                return { normalized: digitsOnly }
            }

            // If defaultCountry is provided, prepend the country code
            if (defaultCountry) {
                const countryCodeMap: Record<string, string> = {
                    US: "1",
                    BR: "55",
                    UK: "44",
                    DE: "49",
                    FR: "33",
                    IT: "39",
                    ES: "34",
                    CA: "1",
                    AU: "61",
                    JP: "81",
                    CN: "86",
                    IN: "91",
                    MX: "52",
                    ZA: "27",
                }

                const countryCode = countryCodeMap[defaultCountry.toUpperCase()]
                if (countryCode) {
                    return { normalized: `+${countryCode}${digitsOnly}` }
                }
            }

            // If no country code available, assume it's already in E.164 format
            if (digitsOnly.startsWith("+")) {
                return { normalized: digitsOnly }
            }

            return { error: "Invalid phone number format" }
        }

        // Return the phone number in E.164 format
        const normalized = parsed.format("E.164")

        return { normalized }
    } catch (error) {
        // Fallback: try to normalize manually
        const digitsOnly = phoneNumber.replace(/[^\d\+]/g, "")

        if (digitsOnly.length < 10) {
            return { error: "Invalid phone number format" }
        }

        if (digitsOnly.startsWith("+")) {
            return { normalized: digitsOnly }
        }

        if (defaultCountry) {
            const countryCodeMap: Record<string, string> = {
                US: "1",
                BR: "55",
                UK: "44",
                DE: "49",
                FR: "33",
                IT: "39",
                ES: "34",
                CA: "1",
                AU: "61",
                JP: "81",
                CN: "86",
                IN: "91",
                MX: "52",
                ZA: "27",
            }

            const countryCode = countryCodeMap[defaultCountry.toUpperCase()]
            if (countryCode) {
                return { normalized: `+${countryCode}${digitsOnly}` }
            }
        }

        return { error: "Invalid phone number format" }
    }
}

/**
 * Validates and normalizes phone number in one operation
 * Combines validation and normalization for convenience
 *
 * @param phoneNumber - The phone number to validate and normalize
 * @param defaultCountry - Optional default country code (e.g., 'US', 'BR', 'UK')
 * @returns Object with isValid, normalized phone number, and error message if invalid
 *
 * @example
 * validateAndNormalizePhoneNumber('+1 (555) 123-4567')
 * // { isValid: true, normalized: '+15551234567' }
 *
 * validateAndNormalizePhoneNumber('(555) 123-4567', 'US')
 * // { isValid: true, normalized: '+15551234567' }
 *
 * validateAndNormalizePhoneNumber('invalid')
 * // { isValid: false, error: 'Please enter a valid phone number' }
 */
export function validateAndNormalizePhoneNumber(
    phoneNumber: string,
    defaultCountry?: string
): {
    isValid: boolean
    normalized?: string
    error?: string
} {
    // First validate the phone number
    const validation = validatePhoneNumber(phoneNumber, defaultCountry)

    if (!validation.isValid) {
        return {
            isValid: false,
            error: validation.error,
        }
    }

    // Then normalize it
    const normalization = normalizePhoneNumber(phoneNumber, defaultCountry)

    if (normalization.error) {
        return {
            isValid: false,
            error: normalization.error,
        }
    }

    return {
        isValid: true,
        normalized: normalization.normalized,
    }
}

/**
 * Validates birth date format (DD/MM/YYYY)
 * Requirements: 4.8-4.9, 18.1-18.2
 *
 * Validates that:
 * - Date is in DD/MM/YYYY format
 * - Date is a valid calendar date (no 32/13/2000)
 * - Date is not in the future
 * - Date is not more than 120 years in the past
 *
 * @param birthDate - The birth date string in DD/MM/YYYY format
 * @returns Object with isValid boolean and error message if invalid
 *
 * @example
 * validateBirthDateFormat('01/01/1990') // { isValid: true }
 * validateBirthDateFormat('32/13/2000') // { isValid: false, error: 'Please enter a valid date (DD/MM/YYYY)' }
 * validateBirthDateFormat('01/01/2025') // { isValid: false, error: 'Please enter a valid date (DD/MM/YYYY)' }
 * validateBirthDateFormat('invalid') // { isValid: false, error: 'Please enter a valid date (DD/MM/YYYY)' }
 */
export function validateBirthDateFormat(birthDate: string): {
    isValid: boolean
    error?: string
} {
    if (!birthDate || typeof birthDate !== "string") {
        return { isValid: false, error: "Birth date is required" }
    }

    const trimmedDate = birthDate.trim()

    // Check format: DD/MM/YYYY
    const dateRegex = /^(\d{2})\/(\d{2})\/(\d{4})$/
    const match = trimmedDate.match(dateRegex)

    if (!match) {
        return {
            isValid: false,
            error: "Please enter a valid date (DD/MM/YYYY)",
        }
    }

    const day = parseInt(match[1], 10)
    const month = parseInt(match[2], 10)
    const year = parseInt(match[3], 10)

    // Validate month (1-12)
    if (month < 1 || month > 12) {
        return {
            isValid: false,
            error: "Please enter a valid date (DD/MM/YYYY)",
        }
    }

    // Validate day based on month
    const daysInMonth = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]

    // Check for leap year
    const isLeapYear = (year % 4 === 0 && year % 100 !== 0) || year % 400 === 0
    if (isLeapYear) {
        daysInMonth[1] = 29
    }

    if (day < 1 || day > daysInMonth[month - 1]) {
        return {
            isValid: false,
            error: "Please enter a valid date (DD/MM/YYYY)",
        }
    }

    // Create date object from parsed values
    const birthDateObj = new Date(year, month - 1, day)

    // Check if date is in the future
    const today = new Date()
    today.setHours(0, 0, 0, 0)

    if (birthDateObj > today) {
        return {
            isValid: false,
            error: "Please enter a valid date (DD/MM/YYYY)",
        }
    }

    // Check if date is more than 120 years in the past
    // Calculate the age in years to avoid timezone and time-based issues
    let age = today.getFullYear() - year

    // Adjust if birthday hasn't occurred this year
    const monthDiff = today.getMonth() - (month - 1)
    if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < day)) {
        age--
    }

    // Allow ages up to 120 years
    if (age > 120) {
        return {
            isValid: false,
            error: "Please enter a valid date (DD/MM/YYYY)",
        }
    }

    return { isValid: true }
}

/**
 * Validates that user is at least 13 years old
 * Requirements: 4.10-4.11, 6.10-6.11, 18.3
 *
 * Calculates age from birth date and ensures user is at least 13 years old.
 * This is required for COPPA compliance (Children's Online Privacy Protection Act).
 *
 * @param birthDate - The birth date string in DD/MM/YYYY format
 * @returns Object with isValid boolean and error message if invalid
 *
 * @example
 * validateMinimumAge('01/01/2010') // { isValid: false, error: 'You must be at least 13 years old to register' }
 * validateMinimumAge('01/01/2005') // { isValid: true }
 * validateMinimumAge('01/01/1990') // { isValid: true }
 */
export function validateMinimumAge(birthDate: string): {
    isValid: boolean
    error?: string
} {
    if (!birthDate || typeof birthDate !== "string") {
        return { isValid: false, error: "Birth date is required" }
    }

    const trimmedDate = birthDate.trim()

    // First validate the format
    const formatValidation = validateBirthDateFormat(trimmedDate)
    if (!formatValidation.isValid) {
        return formatValidation
    }

    // Parse the date
    const dateRegex = /^(\d{2})\/(\d{2})\/(\d{4})$/
    const match = trimmedDate.match(dateRegex)

    if (!match) {
        return {
            isValid: false,
            error: "You must be at least 13 years old to register",
        }
    }

    const day = parseInt(match[1], 10)
    const month = parseInt(match[2], 10)
    const year = parseInt(match[3], 10)

    // Create birth date object
    const birthDateObj = new Date(year, month - 1, day)

    // Calculate age
    const today = new Date()
    let age = today.getFullYear() - birthDateObj.getFullYear()

    // Adjust age if birthday hasn't occurred this year
    const monthDiff = today.getMonth() - birthDateObj.getMonth()
    if (
        monthDiff < 0 ||
        (monthDiff === 0 && today.getDate() < birthDateObj.getDate())
    ) {
        age--
    }

    // Check if user is at least 13 years old
    if (age < 13) {
        return {
            isValid: false,
            error: "You must be at least 13 years old to register",
        }
    }

    return { isValid: true }
}

/**
 * Activity Detection Service
 * Combines geolocation, device detection, and IP validation for suspicious activity detection
 * Validates: Requirements 5.1, 5.2
 */

import { createLogger } from "../logger"
import { DeviceDetectionService, DeviceInfo } from "./device-detection"
import { GeolocationInfo, GeolocationService } from "./geolocation"
import { IPInfo, IPValidationService } from "./ip-validation"

/**
 * Activity information collected from a request
 */
export interface ActivityInfo {
    /**
     * IP address
     */
    ip: string

    /**
     * IP information
     */
    ipInfo: IPInfo

    /**
     * Device information
     */
    device: DeviceInfo

    /**
     * Geolocation information
     */
    location: GeolocationInfo

    /**
     * Timestamp when activity was recorded
     */
    timestamp: Date

    /**
     * User agent string
     */
    userAgent: string
}

/**
 * Suspicious activity detection result
 */
export interface SuspiciousActivityResult {
    /**
     * Whether the activity is suspicious
     */
    isSuspicious: boolean

    /**
     * Reasons for suspicion (if any)
     */
    reasons: string[]

    /**
     * Confidence score (0-100)
     */
    confidenceScore: number

    /**
     * Detailed comparison results
     */
    comparison: {
        ipChanged: boolean
        countryChanged: boolean
        cityChanged: boolean
        deviceTypeChanged: boolean
        osChanged: boolean
        browserChanged: boolean
        distanceKm: number
    }
}

/**
 * Activity Detection Service
 * Detects suspicious activity by comparing current activity with previous activity
 */
export class ActivityDetectionService {
    private logger = createLogger("ActivityDetectionService")
    private deviceDetectionService: DeviceDetectionService
    private ipValidationService: IPValidationService
    private geolocationService: GeolocationService

    /**
     * Threshold for suspicious activity detection
     * Activity is considered suspicious if confidence score exceeds this threshold
     */
    private readonly SUSPICIOUS_THRESHOLD = 50

    /**
     * Initialize the activity detection service
     * @param deviceDetectionService - Device detection service
     * @param ipValidationService - IP validation service
     * @param geolocationService - Geolocation service
     */
    constructor(
        deviceDetectionService: DeviceDetectionService,
        ipValidationService: IPValidationService,
        geolocationService: GeolocationService
    ) {
        this.deviceDetectionService = deviceDetectionService
        this.ipValidationService = ipValidationService
        this.geolocationService = geolocationService
    }

    /**
     * Collect activity information from a request
     * @param request - The HTTP request
     * @returns Activity information
     * @throws Error if activity collection fails
     *
     * @example
     * const service = new ActivityDetectionService(...)
     * const activity = await service.collectActivity(req)
     * // Returns: { ip: '203.0.113.42', device: {...}, location: {...}, ... }
     */
    async collectActivity(request: any): Promise<ActivityInfo> {
        try {
            // Extract IP address
            const ip = this.ipValidationService.extractIPFromRequest(request)
            const ipInfo = this.ipValidationService.validateIP(ip)

            // Extract device information
            let userAgent = ""
            if (request.headers && typeof request.headers.get === "function") {
                userAgent = request.headers.get("user-agent") || ""
            } else if (request.headers) {
                userAgent = request.headers["user-agent"] || ""
            }

            const device = this.deviceDetectionService.detectDevice(userAgent)

            // Get geolocation information
            let location: GeolocationInfo
            try {
                location = this.geolocationService.getLocation(
                    request.headers || {}
                )
            } catch (error) {
                this.logger.warn(
                    `Failed to get geolocation for ${ip}`,
                    error instanceof Error ? error : new Error(String(error))
                )
                // Return default location if geolocation fails
                location = this.getDefaultLocation()
            }

            return {
                ip,
                ipInfo,
                device,
                location,
                timestamp: new Date(),
                userAgent,
            }
        } catch (error) {
            this.logger.error(
                "Failed to collect activity information",
                error instanceof Error ? error : new Error(String(error))
            )
            throw error
        }
    }

    /**
     * Detect suspicious activity by comparing current activity with previous activity
     * @param previousActivity - Previous activity information
     * @param currentActivity - Current activity information
     * @returns Suspicious activity detection result
     *
     * @example
     * const result = service.detectSuspiciousActivity(previousActivity, currentActivity)
     * // Returns: { isSuspicious: true, reasons: ['IP changed', 'Country changed'], confidenceScore: 75 }
     */
    detectSuspiciousActivity(
        previousActivity: ActivityInfo,
        currentActivity: ActivityInfo
    ): SuspiciousActivityResult {
        const reasons: string[] = []
        let confidenceScore = 0

        // Compare IP addresses
        const ipChanged = !this.ipValidationService.compareIPs(
            previousActivity.ip,
            currentActivity.ip
        )
        if (ipChanged) {
            reasons.push("IP address changed")
            confidenceScore += 20
        }

        // Compare geolocation
        const locationComparison = this.geolocationService.compareLocations(
            previousActivity.location,
            currentActivity.location
        )

        if (locationComparison.countryChanged) {
            reasons.push("Country changed")
            confidenceScore += 25
        }

        if (
            locationComparison.cityChanged &&
            !locationComparison.countryChanged
        ) {
            reasons.push("City changed")
            confidenceScore += 10
        }

        // Check for impossible travel (too far too fast)
        const timeDiffMinutes =
            (currentActivity.timestamp.getTime() -
                previousActivity.timestamp.getTime()) /
            (1000 * 60)
        const maxPossibleDistance = timeDiffMinutes * 15 // Assume max 15 km/min (900 km/h)

        if (
            locationComparison.distanceKm > maxPossibleDistance &&
            timeDiffMinutes < 60
        ) {
            reasons.push(
                `Impossible travel detected: ${locationComparison.distanceKm.toFixed(0)}km in ${timeDiffMinutes.toFixed(0)} minutes`
            )
            confidenceScore += 30
        }

        // Compare device information
        const deviceComparison = this.deviceDetectionService.compareDevices(
            previousActivity.device,
            currentActivity.device
        )

        if (deviceComparison.deviceTypeChanged) {
            reasons.push("Device type changed")
            confidenceScore += 15
        }

        if (deviceComparison.osChanged) {
            reasons.push("Operating system changed")
            confidenceScore += 10
        }

        if (deviceComparison.browserChanged) {
            reasons.push("Browser changed")
            confidenceScore += 5
        }

        // Normalize confidence score to 0-100
        confidenceScore = Math.min(100, confidenceScore)

        return {
            isSuspicious: confidenceScore >= this.SUSPICIOUS_THRESHOLD,
            reasons,
            confidenceScore,
            comparison: {
                ipChanged,
                countryChanged: locationComparison.countryChanged,
                cityChanged: locationComparison.cityChanged,
                deviceTypeChanged: deviceComparison.deviceTypeChanged,
                osChanged: deviceComparison.osChanged,
                browserChanged: deviceComparison.browserChanged,
                distanceKm: locationComparison.distanceKm,
            },
        }
    }

    /**
     * Get default location (used when geolocation fails)
     * @returns Default geolocation information
     */
    private getDefaultLocation(): GeolocationInfo {
        return {
            country: "Unknown",
            countryName: "Unknown",
            city: "Unknown",
            state: "Unknown",
            latitude: 0,
            longitude: 0,
            timezone: "Unknown",
            isp: "Unknown",
            isAccurate: false,
            accuracyRadius: 0,
        }
    }

    /**
     * Set the suspicious activity threshold
     * @param threshold - Confidence score threshold (0-100)
     */
    setSuspiciousThreshold(threshold: number): void {
        if (threshold < 0 || threshold > 100) {
            throw new Error("Threshold must be between 0 and 100")
        }
        ;(this as any).SUSPICIOUS_THRESHOLD = threshold
    }
}

/**
 * Create a singleton instance of ActivityDetectionService
 */
let activityDetectionServiceInstance: ActivityDetectionService | null = null

/**
 * Get or create the activity detection service instance
 * @param deviceDetectionService - Device detection service
 * @param ipValidationService - IP validation service
 * @param geolocationService - Geolocation service
 * @returns The activity detection service instance
 */
export function getActivityDetectionService(
    deviceDetectionService: DeviceDetectionService,
    ipValidationService: IPValidationService,
    geolocationService: GeolocationService
): ActivityDetectionService {
    if (!activityDetectionServiceInstance) {
        activityDetectionServiceInstance = new ActivityDetectionService(
            deviceDetectionService,
            ipValidationService,
            geolocationService
        )
    }
    return activityDetectionServiceInstance
}

/**
 * Reset the activity detection service (useful for testing)
 */
export function resetActivityDetectionService(): void {
    activityDetectionServiceInstance = null
}

/**
 * Channel Validation Service
 * Validates YouTube channel ownership through YouTube API integration
 * Implements channel ID validation against OAuth response
 * Handles API failures and rate limiting
 * Validates: Requirements 2.1, 2.2
 */

import { BaseService, ServiceError } from "./base-service"
import { YouTubeChannelLinkingConfig } from "./config"

/**
 * YouTube channel information returned from API
 */
export interface YouTubeChannelInfo {
    channelId: string
    title: string
    description: string
    customUrl?: string
    subscriberCount?: number
    profileImageUrl?: string
}

/**
 * Channel validation result
 */
export interface ChannelValidationResult {
    valid: boolean
    channelInfo?: YouTubeChannelInfo
    error?: string
}

/**
 * OAuth response containing channel information
 */
export interface OAuthResponse {
    accessToken: string
    channelId?: string
    email?: string
    name?: string
}

/**
 * Rate limiting state for API calls
 */
interface RateLimitState {
    requestCount: number
    resetTime: number
}

/**
 * Channel Validation Service
 * Handles YouTube API integration and channel ownership validation
 */
export class ChannelValidationService extends BaseService {
    private config: YouTubeChannelLinkingConfig
    private rateLimitMap: Map<string, RateLimitState> = new Map()
    private readonly RATE_LIMIT_WINDOW = 60000 // 1 minute
    private readonly RATE_LIMIT_MAX_REQUESTS = 100 // Max requests per minute

    constructor(config: YouTubeChannelLinkingConfig) {
        super()
        this.config = config
    }

    /**
     * Validate channel ownership by comparing OAuth response with YouTube API
     * @param oauthResponse - OAuth response from YouTube
     * @param expectedChannelId - Expected channel ID to validate against
     * @returns Validation result with channel info if valid
     * @throws ServiceError if validation fails
     *
     * **Validates: Requirements 2.1, 2.2**
     */
    async validateChannelOwnership(
        oauthResponse: OAuthResponse,
        expectedChannelId: string
    ): Promise<ChannelValidationResult> {
        this.assertReady()

        if (!oauthResponse.accessToken) {
            return {
                valid: false,
                error: "Access token is required",
            }
        }

        if (!expectedChannelId) {
            return {
                valid: false,
                error: "Expected channel ID is required",
            }
        }

        try {
            // Check rate limiting
            this.checkRateLimit("channel-validation")

            // Fetch channel information from YouTube API
            const channelInfo = await this.getChannelInfo(
                oauthResponse.accessToken
            )

            if (!channelInfo) {
                return {
                    valid: false,
                    error: "Failed to retrieve channel information from YouTube API",
                }
            }

            // Validate channel ID matches
            if (channelInfo.channelId !== expectedChannelId) {
                this.logger.warn("Channel ID mismatch", {
                    expected: expectedChannelId,
                    actual: channelInfo.channelId,
                })

                return {
                    valid: false,
                    error: "Channel ID does not match OAuth response",
                }
            }

            this.logger.info("Channel ownership validated successfully", {
                channelId: channelInfo.channelId,
            })

            return {
                valid: true,
                channelInfo,
            }
        } catch (error) {
            const serviceError = this.handleError(
                error,
                "Channel validation failed",
                {
                    expectedChannelId,
                }
            )

            return {
                valid: false,
                error: serviceError.message,
            }
        }
    }

    /**
     * Fetch channel information from YouTube API
     * @param accessToken - OAuth access token
     * @returns Channel information or null if fetch fails
     * @throws ServiceError if API call fails after retries
     *
     * **Validates: Requirements 2.1**
     */
    async getChannelInfo(
        accessToken: string
    ): Promise<YouTubeChannelInfo | null> {
        this.assertReady()

        if (!accessToken) {
            throw new ServiceError(
                "INVALID_ACCESS_TOKEN",
                "Access token is required",
                400
            )
        }

        const maxRetries = 3
        let lastError: Error | null = null

        for (let attempt = 0; attempt < maxRetries; attempt++) {
            try {
                this.logger.debug(
                    `Fetching channel info (attempt ${attempt + 1}/${maxRetries})`
                )

                const response = await this.callYouTubeAPI(
                    accessToken,
                    "https://www.googleapis.com/youtube/v3/channels",
                    {
                        part: "snippet,statistics",
                        mine: "true",
                    }
                )

                if (!response.items || response.items.length === 0) {
                    throw new ServiceError(
                        "NO_CHANNEL_FOUND",
                        "No channel found for the authenticated user",
                        404
                    )
                }

                const channel = response.items[0]

                return {
                    channelId: channel.id,
                    title: channel.snippet?.title || "",
                    description: channel.snippet?.description || "",
                    customUrl: channel.snippet?.customUrl,
                    subscriberCount: parseInt(
                        channel.statistics?.subscriberCount || "0"
                    ),
                    profileImageUrl: channel.snippet?.thumbnails?.default?.url,
                }
            } catch (error) {
                lastError =
                    error instanceof Error ? error : new Error(String(error))

                // Check if error is retryable
                if (!this.isRetryableError(error)) {
                    throw error
                }

                // Exponential backoff
                if (attempt < maxRetries - 1) {
                    const delay = Math.pow(2, attempt) * 1000 // 1s, 2s, 4s
                    this.logger.debug(`Retrying after ${delay}ms`, { attempt })
                    await this.sleep(delay)
                }
            }
        }

        throw new ServiceError(
            "CHANNEL_INFO_FETCH_FAILED",
            `Failed to fetch channel information after ${maxRetries} attempts: ${lastError?.message || "Unknown error"}`,
            500,
            { lastError: lastError?.message }
        )
    }

    /**
     * Call YouTube API with error handling
     * @param accessToken - OAuth access token
     * @param url - API endpoint URL
     * @param params - Query parameters
     * @returns API response
     * @throws ServiceError if API call fails
     */
    private async callYouTubeAPI(
        accessToken: string,
        url: string,
        params: Record<string, string | boolean>
    ): Promise<any> {
        try {
            // Build query string
            const queryParams = new URLSearchParams()
            for (const [key, value] of Object.entries(params)) {
                queryParams.append(key, String(value))
            }

            const fullUrl = `${url}?${queryParams.toString()}`

            this.logger.debug("Calling YouTube API", { url: fullUrl })

            const response = await fetch(fullUrl, {
                method: "GET",
                headers: {
                    Authorization: `Bearer ${accessToken}`,
                    Accept: "application/json",
                },
                signal: AbortSignal.timeout(10000),
            })

            if (!response.ok) {
                const errorData = await response.json().catch(() => ({}))

                // Handle specific error codes
                if (response.status === 401) {
                    throw new ServiceError(
                        "INVALID_ACCESS_TOKEN",
                        "Access token is invalid or expired",
                        401,
                        { errorData }
                    )
                }

                if (response.status === 403) {
                    throw new ServiceError(
                        "INSUFFICIENT_PERMISSIONS",
                        "Access token does not have required permissions",
                        403,
                        { errorData }
                    )
                }

                if (response.status === 429) {
                    throw new ServiceError(
                        "RATE_LIMIT_EXCEEDED",
                        "YouTube API rate limit exceeded",
                        429,
                        { errorData, retryable: true }
                    )
                }

                if (response.status >= 500) {
                    throw new ServiceError(
                        "API_SERVER_ERROR",
                        `YouTube API server error: ${response.status}`,
                        response.status,
                        { errorData, retryable: true }
                    )
                }

                throw new ServiceError(
                    "API_ERROR",
                    `YouTube API error: ${response.status}`,
                    response.status,
                    { errorData }
                )
            }

            const data = await response.json()
            return data
        } catch (error) {
            if (error instanceof ServiceError) {
                throw error
            }

            throw new ServiceError(
                "API_CALL_FAILED",
                `Failed to call YouTube API: ${error instanceof Error ? error.message : "Unknown error"}`,
                500,
                {
                    originalError:
                        error instanceof Error ? error.message : String(error),
                }
            )
        }
    }

    /**
     * Check if error is retryable
     * @param error - Error to check
     * @returns True if error is retryable
     */
    private isRetryableError(error: unknown): boolean {
        if (error instanceof ServiceError) {
            // Retryable error codes
            const retryableCodes = [
                "RATE_LIMIT_EXCEEDED",
                "API_SERVER_ERROR",
                "API_CALL_FAILED",
            ]
            return retryableCodes.includes(error.code)
        }

        return false
    }

    /**
     * Check rate limiting for API calls
     * @param key - Rate limit key (e.g., user ID or IP)
     * @throws ServiceError if rate limit exceeded
     */
    private checkRateLimit(key: string): void {
        const now = Date.now()
        const state = this.rateLimitMap.get(key)

        if (!state) {
            // First request in this window
            this.rateLimitMap.set(key, {
                requestCount: 1,
                resetTime: now + this.RATE_LIMIT_WINDOW,
            })
            return
        }

        if (now > state.resetTime) {
            // Window has expired, reset counter
            this.rateLimitMap.set(key, {
                requestCount: 1,
                resetTime: now + this.RATE_LIMIT_WINDOW,
            })
            return
        }

        // Increment counter
        state.requestCount++

        if (state.requestCount > this.RATE_LIMIT_MAX_REQUESTS) {
            throw new ServiceError(
                "RATE_LIMIT_EXCEEDED",
                `Rate limit exceeded: ${this.RATE_LIMIT_MAX_REQUESTS} requests per ${this.RATE_LIMIT_WINDOW}ms`,
                429,
                {
                    requestCount: state.requestCount,
                    resetTime: state.resetTime,
                }
            )
        }
    }

    /**
     * Sleep for specified milliseconds
     * @param ms - Milliseconds to sleep
     */
    private sleep(ms: number): Promise<void> {
        return new Promise(resolve => setTimeout(resolve, ms))
    }

    /**
     * Clear rate limit state (useful for testing)
     */
    clearRateLimitState(): void {
        this.rateLimitMap.clear()
    }

    /**
     * Get rate limit state for a key
     * @param key - Rate limit key
     * @returns Rate limit state or undefined
     */
    getRateLimitState(key: string): RateLimitState | undefined {
        return this.rateLimitMap.get(key)
    }
}

